                ],
                'status_code' => ($status['status'] ?? '') === 'ready' ? 'logged_in' : 'login_expired',
            ]);
        }

        return $this->success(
            $status,
            !empty($status['exists']) ? '携程 Profile 状态已读取' : '未找到携程 Profile'
        );
    }

