                continue;
            }
            $amount = $this->meituanNumber($row, ['amount', 'Amount', 'totalAmount', 'total_amount', 'saleAmount', 'orderAmount', 'gmv', 'turnover', 'bookingAmount', '成交收入', '成交金额', '销售额'], 0);
            $roomNights = (int)$this->meituanNumber($row, ['quantity', 'Quantity', 'roomNights', 'room_nights', 'checkOutQuantity', 'roomNightCount', 'nightNum', '成交间夜', '间夜', '房晚'], 0);
            $orders = (int)$this->meituanNumber($row, ['bookOrderNum', 'book_order_num', 'orderCount', 'order_count', 'orderNum', 'orders', 'bookings', '成交订单数', '订单数'], 0);

            $summary['amount'] += $amount;
            $summary['room_nights'] += $roomNights;
            $summary['order_count'] += $orders;
            $summary['yesterday_uv'] += (int)$this->meituanNumber($row, ['yesterday_uv', 'yesterdayUv', 'yesterdayUV', 'uv', 'UV', 'visitorCount', 'detailUv', 'totalDetailNum', 'visitors', '昨日UV', '访客数'], 0);
            $summary['competitor_uv'] += (int)$this->meituanNumber($row, ['competitor_uv', 'competitorUv', 'competitorUV', 'competeUv', 'competeUV', 'peerUv', 'peerUV', 'comhtluv', '竞品UV'], 0);
            $summary['competitor_orders'] += (int)$this->meituanNumber($row, ['competitor_orders', 'competitorOrders', 'competitorOrderNum', 'competeOrderNum', 'peerOrderNum', 'ordquantity', '竞品订单', '竞品订单数'], 0);
            $summary['competitor_amount'] += $this->meituanNumber($row, ['competitor_amount', 'competitorAmount', 'competitorRevenue', 'competeAmount', 'peerAmount', 'ordamount', '竞品收入', '竞品成交收入'], 0);
            $summary['favorite_count'] += (int)$this->meituanNumber($row, ['favorite_count', 'favoriteCount', 'collectCount', 'hotelCollect', '收藏数', '收藏量'], 0);
            $summary['self_list_exposure'] += (int)$this->meituanNumber($row, ['self_list_exposure'], 0);
            $summary['self_detail_exposure'] += (int)$this->meituanNumber($row, ['self_detail_exposure'], 0);
            $summary['self_order_filling_num'] += (int)$this->meituanNumber($row, ['self_order_filling_num'], 0);
            $summary['self_order_submit_num'] += (int)$this->meituanNumber($row, ['self_order_submit_num'], 0);
            $summary['competitor_list_exposure'] += (int)$this->meituanNumber($row, ['competitor_list_exposure'], 0);
            $summary['competitor_detail_exposure'] += (int)$this->meituanNumber($row, ['competitor_detail_exposure'], 0);
            $summary['competitor_order_filling_num'] += (int)$this->meituanNumber($row, ['competitor_order_filling_num'], 0);
            $summary['competitor_order_submit_num'] += (int)$this->meituanNumber($row, ['competitor_order_submit_num'], 0);

            foreach (array_keys($rankValues) as $rankKey) {
                $rank = (int)$this->meituanNumber($row, [$rankKey], 0);
                if ($rank > 0) {
                    $rankValues[$rankKey][] = $rank;
                }
            }
            foreach (['compete_hotel_count', 'hot_words_count', 'hot_hotels_count'] as $countKey) {
                $count = (int)$this->meituanNumber($row, [$countKey], 0);
                if ($count > 0) {
                    $summary[$countKey] = max((int)($summary[$countKey] ?? 0), $count);
                }
            }
            foreach (['top_flow_hotel', 'top_hot_room'] as $textKey) {
                $text = trim((string)($row[$textKey] ?? ''));
                if ($text !== '' && (string)($summary[$textKey] ?? '') === '') {
                    $summary[$textKey] = $text;
                }
            }
            foreach ([
                'top_hot_words' => '_overview_hot_words',
                'top_hot_hotels' => '_overview_hot_hotels',
            ] as $summaryKey => $rowListKey) {
                if (empty($summary[$summaryKey])) {
                    $items = $this->normalizeCtripStringListItems($row[$summaryKey] ?? $row[$rowListKey] ?? []);
                    if (!empty($items)) {
                        $summary[$summaryKey] = array_slice($items, 0, 10);
                    }
                }
            }
            foreach ([
                'flow_lost_order_num',
                'flow_lost_room_nights',
                'top_hot_room_nights',
                'last_week_good_add',
                'last_week_bad_add',
                'last_week_checkout_room_nights',
                'last_week_book_quantity',
                'last_week_book_room_nights',
            ] as $intKey) {
                $rawValue = $this->firstMeituanValue($row, [$intKey], null);
                if ($rawValue !== null) {
                    $value = (int)$this->meituanNumber($row, [$intKey], 0);
                    $summary[$intKey] = (int)($summary[$intKey] ?? 0) + $value;
                }
            }
            foreach ([
                'flow_lost_amount',
                'top_flow_hotel_browse_rate',
                'top_flow_hotel_order_rate',
                'top_hot_room_sale_percent',
                'last_week_comment_score',
                'last_week_price_score',
                'last_week_checkout_sales',
                'last_week_checkout_room_price',
                'last_week_book_sales',
            ] as $numberKey) {
                $rawValue = $this->firstMeituanValue($row, [$numberKey], null);
                if ($rawValue !== null && $summary[$numberKey] === null) {
                    $summary[$numberKey] = $this->meituanNumber($row, [$numberKey], 0);
                }
            }
            foreach (['weekly_self', 'weekly_competitor', 'top_competitor'] as $prefix) {
                foreach (['list_exposure', 'detail_exposure', 'order_filling_num', 'order_submit_num'] as $metricKey) {
                    $summaryKey = $prefix . '_' . $metricKey;
                    $rawValue = $this->firstMeituanValue($row, [$summaryKey], null);
                    if ($rawValue !== null) {
                        $value = (int)$this->meituanNumber($row, [$summaryKey], 0);
                        $summary[$summaryKey] = (int)($summary[$summaryKey] ?? 0) + $value;
                    }
                }
                foreach (['flow_rate', 'order_fill_rate', 'deal_rate'] as $rateKey) {
                    $summaryKey = $prefix . '_' . $rateKey;
                    $value = $this->normalizeMeituanPercentValue($this->firstMeituanValue($row, [$summaryKey], null));
                    if ($value !== null && $summary[$summaryKey] === null) {
                        $summary[$summaryKey] = $value;
                    }
                }
            }

            $avgPrice = $this->meituanNumber($row, ['avg_price', 'avgPrice', 'averagePrice', 'adr', 'ADR', '均价', '平均房价'], 0);
            if ($avgPrice > 0) {
                $avgPriceValues[] = $avgPrice;
            }
            $conversionRate = $this->normalizeMeituanPercentValue($this->firstMeituanValue($row, ['closeRate', 'conversion_rate', 'conversionRate', 'convertionRate', 'bookRate', '成交率', '转化率'], null));
            if ($conversionRate !== null) {
                $conversionValues[] = $conversionRate;
            }
            $psi = $this->meituanNumber($row, ['psi', 'PSI', 'psiScore', 'serviceScore', 'service_score', 'PSI值'], 0);
            if ($psi > 0) {
                $psiValues[] = $psi;
            }
            $hotelScore = $this->meituanNumber($row, ['hotel_score', 'hotelScore', 'ctripRatingall', 'ctrip_rating_all', '酒店评分', '酒店点评分'], 0);
            if ($hotelScore > 0) {
                $hotelScoreValues[] = $hotelScore;
            }
            $replyRate = $this->normalizeMeituanPercentValue($this->firstMeituanValue($row, ['reply_rate', 'replyRate', 'replyrate5m', '回复率', '5分钟回复率'], null));
            if ($replyRate !== null) {
                $replyRateValues[] = $replyRate;
            }
            $visitorRank = (int)$this->meituanNumber($row, ['visitor_rank', 'visitorRank', 'uvRank', '访客排名'], 0);
            if ($visitorRank > 0) {
                $visitorRanks[] = $visitorRank;
            }
        }

        if ($summary['room_nights'] > 0) {
            $summary['avg_price'] = round($summary['amount'] / $summary['room_nights'], 2);
        } elseif (!empty($avgPriceValues)) {
            $summary['avg_price'] = round(array_sum($avgPriceValues) / count($avgPriceValues), 2);
        }
        if (!empty($conversionValues)) {
            $summary['conversion_rate'] = round(array_sum($conversionValues) / count($conversionValues), 2);
        }
        if (!empty($psiValues)) {
            $summary['psi'] = round(array_sum($psiValues) / count($psiValues), 2);
        }
        if (!empty($hotelScoreValues)) {
            $summary['hotel_score'] = round(array_sum($hotelScoreValues) / count($hotelScoreValues), 2);
        }
        if (!empty($replyRateValues)) {
            $summary['reply_rate'] = round(array_sum($replyRateValues) / count($replyRateValues), 2);
        }
        if (!empty($visitorRanks)) {
            $summary['visitor_rank'] = min($visitorRanks);
        }
        foreach ($rankValues as $rankKey => $values) {
            if (!empty($values)) {
                $summary[$rankKey] = min($values);
            }
        }
        $summary['self_flow_rate'] = $this->trafficRate((float)$summary['self_detail_exposure'], (float)$summary['self_list_exposure']);
        $summary['self_order_fill_rate'] = $this->trafficRate((float)$summary['self_order_filling_num'], (float)$summary['self_detail_exposure']);
        $summary['self_deal_rate'] = $this->trafficRate((float)$summary['self_order_submit_num'], (float)$summary['self_order_filling_num']);
        $summary['competitor_flow_rate'] = $this->trafficRate((float)$summary['competitor_detail_exposure'], (float)$summary['competitor_list_exposure']);
        $summary['competitor_order_fill_rate'] = $this->trafficRate((float)$summary['competitor_order_filling_num'], (float)$summary['competitor_detail_exposure']);
        $summary['competitor_deal_rate'] = $this->trafficRate((float)$summary['competitor_order_submit_num'], (float)$summary['competitor_order_filling_num']);
        foreach (['weekly_self', 'weekly_competitor', 'top_competitor'] as $prefix) {
            if ($summary[$prefix . '_flow_rate'] === null && (float)($summary[$prefix . '_list_exposure'] ?? 0) > 0) {
                $summary[$prefix . '_flow_rate'] = $this->trafficRate((float)($summary[$prefix . '_detail_exposure'] ?? 0), (float)($summary[$prefix . '_list_exposure'] ?? 0));
            }
            if ($summary[$prefix . '_order_fill_rate'] === null && (float)($summary[$prefix . '_detail_exposure'] ?? 0) > 0) {
                $summary[$prefix . '_order_fill_rate'] = $this->trafficRate((float)($summary[$prefix . '_order_filling_num'] ?? 0), (float)($summary[$prefix . '_detail_exposure'] ?? 0));
            }
            if ($summary[$prefix . '_deal_rate'] === null && (float)($summary[$prefix . '_order_filling_num'] ?? 0) > 0) {
                $summary[$prefix . '_deal_rate'] = $this->trafficRate((float)($summary[$prefix . '_order_submit_num'] ?? 0), (float)($summary[$prefix . '_order_filling_num'] ?? 0));
            }
        }
        $summary['amount'] = round($summary['amount'], 2);
        $summary['competitor_amount'] = round($summary['competitor_amount'], 2);
        if ($summary['flow_lost_amount'] !== null) {
            $summary['flow_lost_amount'] = round((float)$summary['flow_lost_amount'], 2);
        }
        foreach (['last_week_checkout_sales', 'last_week_checkout_room_price', 'last_week_book_sales'] as $moneyKey) {
            if ($summary[$moneyKey] !== null) {
                $summary[$moneyKey] = round((float)$summary[$moneyKey], 2);
            }
        }
        return $summary;
    }

    private function buildCtripAdsDirectPayload(array $payload, string $startDate, string $endDate, string $apiType): array
    {
        $apiType = $this->normalizeCtripAdsApiType($apiType);
        foreach ([
            'startDate' => $startDate,
            'endDate' => $endDate,
            'beginDate' => $startDate,
            'statStartDate' => $startDate,
            'statEndDate' => $endDate,
        ] as $key => $value) {
            if (!array_key_exists($key, $payload) || $payload[$key] === '' || $payload[$key] === null) {
                $payload[$key] = $value;
            }
        }
        $payload['apiType'] = $apiType;
        return $payload;
    }

    private function buildCtripAdsDateRange(string $dateRange, string $startDate, string $endDate, ?int $now = null): array
    {
        $today = $this->ctripAdsClock($now)->format('Y-m-d');
        $reportEndDate = $this->ctripAdsReportEndDate($now);
        switch ($dateRange) {
            case 'today_realtime':
            case 'today':
            case '0':
                return [$today, $today];
            case 'last_7_days':
            case '7':
                return [date('Y-m-d', strtotime($reportEndDate . ' -6 days')), $reportEndDate];
            case 'last_30_days':
            case '30':
                return [date('Y-m-d', strtotime($reportEndDate . ' -29 days')), $reportEndDate];
            case 'custom':
                if ($startDate === '' || $endDate === '') {
                    throw new \InvalidArgumentException('请选择自定义开始日期和结束日期');
                }
                break;
            case 'yesterday':
            case '1':
            default:
                $startDate = $reportEndDate;
                $endDate = $reportEndDate;
                break;
        }

        if (strtotime($startDate) === false || strtotime($endDate) === false || strtotime($startDate) > strtotime($endDate)) {
            throw new \InvalidArgumentException('日期范围无效');
        }
        return [$startDate, $endDate];
    }

    private function ctripAdsReportEndDate(?int $now = null): string
    {
        $clock = $this->ctripAdsClock($now);
        $offsetDays = (int)$clock->format('G') < 7 ? 2 : 1;
        return $clock->modify('-' . $offsetDays . ' days')->format('Y-m-d');
    }

    private function ctripAdsClock(?int $now = null): \DateTimeImmutable
    {
        $timezone = new \DateTimeZone('Asia/Shanghai');
        if ($now === null) {
            return new \DateTimeImmutable('now', $timezone);
        }
        return (new \DateTimeImmutable('@' . $now))->setTimezone($timezone);
    }

    private function isCtripAdsApiUrl(string $url): bool
    {
        $normalized = strtolower(trim($url));
        return str_contains($normalized, 'pyramidad')
            || str_contains($normalized, 'promotion')
            || str_contains($normalized, '/toolcenter/api/cpc/')
            || str_contains($normalized, 'querycampaignreportlist');
    }

    private function extractCtripCapturedAds(array $payload): array
    {
        $rows = [];
        foreach (['ads', 'advertising', 'adData'] as $key) {
            if (array_key_exists($key, $payload)) {
                $rows = array_merge($rows, $this->normalizeCtripCapturedAdList($payload[$key]));
            }
        }

        if (isset($payload['responses']) && is_array($payload['responses'])) {
            foreach ($payload['responses'] as $response) {
                if (!is_array($response)) {
                    continue;
                }
                $url = strtolower((string)($response['url'] ?? ''));
                $section = strtolower((string)($response['section'] ?? $response['type'] ?? ''));
                if ($section !== 'ads' && !$this->isCtripAdsApiUrl($url)) {
                    continue;
                }
                $data = $response['data'] ?? $response['body'] ?? $response['json'] ?? [];
                $rows = array_merge($rows, $this->normalizeCtripCapturedAdList($data));
            }
        }

        $seen = [];
        $deduped = [];
        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }
            $identity = json_encode([
                $this->firstMeituanValue($row, ['campaignId', 'campaign_id', 'planId', 'plan_id', 'adId', 'id'], ''),
                $this->firstMeituanValue($row, ['campaign_name', 'campaignName', 'promotionName', 'planName', 'adName', 'name'], ''),
                $this->firstMeituanValue($row, ['stat_date', 'statDate', 'dataDate', 'date'], ''),
                $this->firstMeituanValue($row, ['exposure_count', 'exposureCount', 'exposure', 'impression'], ''),
                $this->firstMeituanValue($row, ['click_count', 'clickCount', 'clicks', 'click'], ''),
                $this->firstMeituanValue($row, ['cost_amount', 'costAmount', 'cost', 'consume', 'spend'], ''),
                $row['_dom_text'] ?? '',
            ], JSON_UNESCAPED_UNICODE);
            if (isset($seen[$identity])) {
                continue;
            }
            $seen[$identity] = true;
            $deduped[] = $row;
        }

        return $deduped;
    }

    private function normalizeCtripCapturedAdList($value): array
    {
        if (!is_array($value)) {
            return [];
        }
        if ($this->isSequentialArray($value)) {
            return array_values(array_filter($value, static fn($item): bool => is_array($item)));
        }

        $paths = [
            ['data', 'list'],
            ['data', 'rows'],
            ['data', 'items'],
            ['data', 'details'],
            ['data', 'campaignList'],
            ['data', 'promotionList'],
            ['data', 'adList'],
            ['data', 'records'],
            ['result', 'list'],
            ['result', 'rows'],
            ['result', 'items'],
            ['list'],
            ['rows'],
            ['items'],
            ['campaignList'],
            ['promotionList'],
            ['adList'],
            ['records'],
            ['data'],
        ];
        foreach ($paths as $path) {
            $nested = $this->readNestedMeituanValue($value, $path);
            if (is_array($nested)) {
                $rows = $this->normalizeCtripCapturedAdList($nested);
                if (!empty($rows)) {
                    return $rows;
                }
            }
        }

        return $this->looksLikeCtripCapturedAdRow($value) ? [$value] : [];
    }

    private function looksLikeCtripCapturedAdRow(array $value): bool
    {
        foreach (['exposure', 'exposureCount', 'impression', 'impressions', 'click', 'clickCount', 'clicks', 'cost', 'consume', 'spend', 'todayCost', 'cashCost', 'bonusCost', 'orderNum', 'bookingNum', 'bookings', 'campaignName', 'promotionName', 'planName', '曝光', '曝光量', '展现量', '点击', '点击量', '消耗', '费用', '花费', '预订量', '成交数', '推广名称', '计划名称'] as $key) {
            if (array_key_exists($key, $value)) {
                return true;
            }
        }
        return false;
    }

    private function buildCtripCapturedAdRows(array $ads, array $payload, ?int $systemHotelId = null): array
    {
        $context = [
            'system_hotel_id' => $systemHotelId,
            'hotel_id' => (string)$this->firstMeituanValue($payload, ['hotel_id', 'hotelId', 'profile_id', 'profileId'], ''),
            'hotel_name' => (string)$this->firstMeituanValue($payload, ['hotel_name', 'hotelName'], ''),
            'captured_at' => (string)$this->firstMeituanValue($payload, ['captured_at', 'capturedAt'], date('Y-m-d H:i:s')),
            'request_start_date' => (string)$this->firstMeituanValue($payload, ['request_start_date', 'requestStartDate'], ''),
            'request_end_date' => (string)$this->firstMeituanValue($payload, ['request_end_date', 'requestEndDate'], ''),
        ];
        $rows = [];
        foreach ($ads as $item) {
            if (!is_array($item)) {
                continue;
            }
            $row = $this->normalizeCtripCapturedAdRow($item, $context);
            if ($row !== null) {
                $rows[] = $row;
            }
        }
        return $rows;
    }

    private function normalizeCtripCapturedAdRow(array $item, array $context): ?array
    {
        $exposure = (int)$this->meituanNumber($item, ['exposure_count', 'exposureCount', 'exposure', 'impression', 'impressions', 'showNum', 'showCount', 'displayCount', 'pv', '曝光', '曝光量', '展现量', '展示量'], 0);
        $clicks = (int)$this->meituanNumber($item, ['click_count', 'clickCount', 'clickNum', 'clicks', 'click', '点击', '点击量'], 0);
        $orders = (int)$this->meituanNumber($item, ['booking_count', 'bookingCount', 'bookingNum', 'bookings', 'orderNum', 'order_count', 'orderCount', 'dealNum', 'transactionNum', 'conversionNum', '预订量', '预订数', '成交数', '成交量', '成交订单数'], 0);
        $nights = (int)$this->meituanNumber($item, ['nights', 'nightNum', 'roomNights', 'room_nights', 'quantity', '间夜', '成交间夜'], 0);
        $cost = $this->meituanNumber($item, ['cost_amount', 'costAmount', 'cost', 'todayCost', 'cashCost', 'consume', 'consumption', 'spend', 'fee', 'expense', 'amount', 'totalCost', '消耗', '费用', '花费', '广告费', '消耗金额', '消费金额'], 0.0);
        if ($exposure <= 0 && $clicks <= 0 && $orders <= 0 && $cost <= 0 && empty($item['_dom_text'])) {
            return null;
        }

        $dataDate = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['effectTime', 'effect_time', 'stat_date', 'statDate', 'data_date', 'dataDate', 'date', 'reportDate', 'day', '日期', '统计日期'], ''))
            ?: ($this->normalizeOnlineDataDate($context['request_end_date'] ?? '') ?: date('Y-m-d'));
        $identity = (string)$this->firstMeituanValue($item, ['campaignId', 'campaign_id', 'planId', 'plan_id', 'adId', 'id', 'campaign_name', 'campaignName', 'promotionName', 'planName', 'adName', 'name', '推广名称', '计划名称', '广告名称', '广告计划'], '');
        if ($identity === '') {
            $identity = substr(md5(json_encode($item, JSON_UNESCAPED_UNICODE)), 0, 12);
        }

        $raw = $item;
        $raw['_capture_context'] = array_filter([
            'profile_id' => $context['hotel_id'] ?? '',
            'captured_at' => $context['captured_at'] ?? '',
            'request_start_date' => $context['request_start_date'] ?? '',
            'request_end_date' => $context['request_end_date'] ?? '',
        ], static fn($value): bool => $value !== null && $value !== '');

        return [
            'hotel_id' => (string)$this->firstMeituanValue($item, ['hotel_id', 'hotelId'], $context['hotel_id'] ?? ''),
            'hotel_name' => (string)$this->firstMeituanValue($item, ['hotel_name', 'hotelName'], $context['hotel_name'] ?? ''),
            'system_hotel_id' => $context['system_hotel_id'] ?? null,
            'data_date' => $dataDate,
            'amount' => round($cost, 2),
            'quantity' => $nights,
            'book_order_num' => $orders,
            'comment_score' => 0,
            'qunar_comment_score' => 0,
            'data_value' => $exposure,
            'source' => 'ctrip',
            'data_type' => 'advertising',
            'dimension' => 'ads:' . $identity,
            'platform' => 'Ctrip',
            'compare_type' => 'self',
            'list_exposure' => $exposure,
            'detail_exposure' => $clicks,
            'flow_rate' => round($this->trafficRate((float)$clicks, (float)$exposure), 2),
            'order_filling_num' => $clicks,
            'order_submit_num' => $orders,
            'raw_data' => json_encode($raw, JSON_UNESCAPED_UNICODE | JSON_INVALID_UTF8_SUBSTITUTE),
        ];
    }

    private function summarizeCtripAdRows(array $rows): array
    {
        $summary = [
            'exposure' => 0,
            'clicks' => 0,
            'orders' => 0,
            'cost' => 0.0,
            'click_rate' => 0.0,
            'cost_per_click' => 0.0,
            'cost_per_order' => 0.0,
        ];
        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }
            $summary['exposure'] += (int)($row['list_exposure'] ?? 0);
            $summary['clicks'] += (int)($row['detail_exposure'] ?? 0);
            $summary['orders'] += (int)($row['book_order_num'] ?? $row['order_submit_num'] ?? 0);
            $summary['cost'] += (float)($row['amount'] ?? 0);
        }
        $summary['cost'] = round($summary['cost'], 2);
        $summary['click_rate'] = round($this->trafficRate((float)$summary['clicks'], (float)$summary['exposure']), 2);
        $summary['cost_per_click'] = $summary['clicks'] > 0 ? round($summary['cost'] / $summary['clicks'], 2) : 0.0;
        $summary['cost_per_order'] = $summary['orders'] > 0 ? round($summary['cost'] / $summary['orders'], 2) : 0.0;
        return $summary;
    }

    private function saveCtripCapturedAdRows(array $rows): int
    {
        $columns = $this->getOnlineDailyDataColumns();
        $savedCount = 0;
        $now = date('Y-m-d H:i:s');
        foreach ($rows as $row) {
            if (!is_array($row) || empty($row['data_date']) || empty($row['data_type'])) {
                continue;
            }
            if (isset($columns['update_time'])) {
                $row['update_time'] = $now;
            }
            $query = Db::name('online_daily_data')
                ->where('source', (string)($row['source'] ?? 'ctrip'))
                ->where('data_type', 'advertising')
                ->where('data_date', (string)$row['data_date'])
                ->where('dimension', (string)($row['dimension'] ?? ''));
            if (!empty($row['hotel_id'])) {
                $query->where('hotel_id', (string)$row['hotel_id']);
            } else {
                $query->where('hotel_name', (string)($row['hotel_name'] ?? ''));
            }
            if (array_key_exists('system_hotel_id', $row) && $row['system_hotel_id'] !== null) {
                $query->where('system_hotel_id', (int)$row['system_hotel_id']);
            } else {
                $query->whereNull('system_hotel_id');
            }
            $exists = $query->find();
            if (!$exists && isset($columns['create_time'])) {
                $row['create_time'] = $now;
            }
            $data = array_intersect_key($this->applyOnlineDailyDataValidationFields($row, $columns), $columns);
            if ($exists) {
                Db::name('online_daily_data')->where('id', $exists['id'])->update($data);
            } else {
                Db::name('online_daily_data')->insert($data);
            }
            $savedCount++;
        }
        return $savedCount;
    }

    private function extractCtripCapturedSection(array $payload, string $section): array
    {
        $rows = [];
        foreach ($this->ctripCapturedSectionAliases($section) as $key) {
            if (array_key_exists($key, $payload)) {
                $rows = array_merge($rows, $this->normalizeCtripCapturedSectionList($payload[$key], $section));
            }
        }

        if (isset($payload['responses']) && is_array($payload['responses'])) {
            foreach ($payload['responses'] as $response) {
                if (!is_array($response) || !$this->ctripCaptureResponseMatchesSection($response, $section)) {
                    continue;
                }
                if ($section === 'business' && $this->isCtripOverviewSpecialResponse($response)) {
                    continue;
                }
                $data = $response['data'] ?? $response['body'] ?? $response['json'] ?? [];
                $rows = array_merge($rows, $this->normalizeCtripCapturedSectionList($data, $section));
            }
        }

        $seen = [];
        $deduped = [];
        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }
            $identity = (string)($row['_fingerprint'] ?? md5(json_encode($row, JSON_UNESCAPED_UNICODE)));
            if (isset($seen[$identity])) {
                continue;
            }
            $seen[$identity] = true;
            $deduped[] = $row;
        }
        return $deduped;
    }

    private function isCtripOverviewSpecialResponse(array $response): bool
    {
        $url = strtolower((string)($response['url'] ?? ''));
        foreach ([
            'getcompetehotelreportv1',
            'gethotwordsv1',
            'gethothotelsv1',
            'getflowhotelsv1',
            'getuserbehaviorv1',
            'getuserbehavorv1',
            'gettrafficreportv1',
            'getlastweekreportv1',
        ] as $needle) {
            if (str_contains($url, $needle)) {
                return true;
            }
        }

        $data = $response['data'] ?? $response['body'] ?? $response['json'] ?? [];
        return is_array($data) && isset($data['data']['hotRooms']) && is_array($data['data']['hotRooms']);
    }

    private function ctripCapturedSectionAliases(string $section): array
    {
        return match ($section) {
            'business' => ['business', 'overview', 'hotelList', 'marketOverview'],
            'traffic' => ['traffic', 'businessData', 'peerTrends', 'rankList', 'categoryRankList', 'competitionRankList'],
            default => [$section],
        };
    }

    private function normalizeCtripCapturedSectionList($value, string $section): array
    {
        if (!is_array($value)) {
            return [];
        }
        if ($this->isSequentialArray($value)) {
            $rows = [];
            foreach ($value as $item) {
                if (!is_array($item)) {
                    continue;
                }
                if ($this->looksLikeCtripCapturedSectionRow($item, $section)) {
                    $rows[] = $item;
                } else {
                    $rows = array_merge($rows, $this->normalizeCtripCapturedSectionList($item, $section));
                }
            }
            return $rows;
        }

        if ($this->looksLikeCtripCapturedSectionRow($value, $section)) {
            return [$value];
        }

        foreach ($this->ctripCapturedListPaths($section) as $path) {
            $nested = $this->readNestedMeituanValue($value, $path);
            if (is_array($nested)) {
                $rows = $this->normalizeCtripCapturedSectionList($nested, $section);
                if (!empty($rows)) {
                    return $rows;
                }
            }
        }

        $rows = [];
        foreach ($value as $nested) {
            if (is_array($nested)) {
                $rows = array_merge($rows, $this->normalizeCtripCapturedSectionList($nested, $section));
            }
        }
        return $rows;
    }

    private function ctripCapturedListPaths(string $section): array
    {
        return match ($section) {
            'traffic' => [
                ['data', 'list'],
                ['data', 'rows'],
                ['data', 'traffic'],
                ['data', 'businessData'],
                ['data', 'peerTrends'],
                ['data', 'rankList'],
                ['data', 'ranking'],
                ['data', 'rankData'],
                ['data', 'categoryRank'],
                ['data', 'categoryRankList'],
                ['data', 'competitionRank'],
                ['data', 'competitionRankList'],
                ['data', 'competeRank'],
                ['data', 'competeRankList'],
                ['data', 'scanFlowDetails'],
                ['data', 'flowData'],
                ['data', 'trafficData'],
                ['data', 'statData'],
                ['result', 'list'],
                ['result', 'rows'],
                ['result', 'rankList'],
                ['list'],
                ['rows'],
                ['rankList'],
                ['categoryRankList'],
                ['competitionRankList'],
                ['data'],
            ],
            default => [
                ['data', 'hotelList'],
                ['data', 'list'],
                ['data', 'rows'],
                ['data', 'overview'],
                ['data', 'marketOverview'],
                ['data', 'flowHotelItemVos'],
                ['data', 'hotRooms'],
                ['result', 'hotelList'],
                ['result', 'list'],
                ['hotelList'],
                ['list'],
                ['rows'],
                ['data'],
            ],
        };
    }

    private function looksLikeCtripCapturedSectionRow(array $value, string $section): bool
    {
        $keys = $section === 'traffic'
            ? $this->ctripTrafficRowKeys()
            : [
                'amount', 'totalAmount', 'saleAmount', 'orderAmount', 'bookingAmount', 'gmv', '成交收入', '成交金额',
                'quantity', 'roomNights', '成交间夜',
                'bookOrderNum', 'orderCount', '订单数',
                'closeRate', 'averagePrice',
                'ordamount', 'ordquantity', 'comhtluv',
                'lossOrderVo', 'flowHotelItemVos', 'hotRooms',
                'lastWeekCommentScore', 'lastWeekCheckoutRoomNights', 'lastWeekBookQuantity',
                'totalListExposure', 'totalDetailExposure',
                'listExposure', 'detailExposure', 'flowRate', 'orderFillingNum', 'orderSubmitNum',
                'commentScore', 'uv', 'yesterdayUv', '昨日UV',
                'psi', 'PSI', 'serviceScore', 'ctripRatingall',
                'replyRate', 'replyrate5m', '回复率',
                'favoriteCount', 'hotelCollect', '收藏数',
                'visitorRank', '访客排名',
            ];
        foreach ($keys as $key) {
            if (array_key_exists($key, $value)) {
                return true;
            }
        }
        return false;
    }

    private function ctripTrafficRowKeys(): array
    {
        return [
            'listExposure', 'list_exposure', 'exposure', 'exposureCount', 'impressions', 'showCount',
            'PV', 'pv', 'pageView', 'pageViews', 'page_view',
            'detailExposure', 'detail_exposure', 'detailVisitors', 'detailUv', 'visitorCount',
            'UV', 'uv', 'uniqueVisitors', 'unique_visitors', 'views',
            'orderFillingNum', 'order_filling_num', 'orderVisitors', 'clickCount', 'clickNum', 'clicks',
            'orderSubmitNum', 'order_submit_num', 'submitUsers', 'submitNum', 'orderCount', 'orderNum',
            'bookOrderNum', 'dealNum', 'orders',
            'flowRate', 'flow_rate', 'conversionRate', 'conversion_rate', 'convertionRate',
            'convertRate', 'transforRate', 'transferRate', 'transRate', 'cvr',
            'rank', 'ranking', 'rankNo', 'rankIndex', 'competitionRank', 'competitorRank',
            'competeRank', 'categoryRank', 'cateRank', 'categoryRanking', 'rankJson',
            'rawRankJson', 'rankingJson',
        ];
    }

    private function ctripCaptureResponseMatchesSection(array $response, string $section): bool
    {
        $type = strtolower((string)($response['type'] ?? $response['section'] ?? ''));
        if ($type !== '' && in_array($type, $this->ctripCapturedSectionAliases($section), true)) {
            return true;
        }

        $url = strtolower((string)($response['url'] ?? ''));
        if ($url === '') {
            return false;
        }

        $needles = $section === 'traffic'
            ? ['queryscanflowdetailsv2', 'queryflowtransfornew', 'queryhomepagerealtimedata', 'getflowdata', 'gettrafficdata', 'getstatdata']
            : ['getdayreportrealtimedate', 'fetchmarketoverviewv2', 'getdayreportflowcompete', 'getdayreportserverquantity', 'fetchcurrenthotelseqinfov1', 'fetchvisitortitlev2', 'fetchcapacityoverviewv4', 'queryflowtransfornewv1', 'getcompetehotelreportv1', 'gethotwordsv1', 'gethothotelsv1', 'getflowhotelsv1', 'gethotroomsv1', 'getuserbehaviorv1', 'gettrafficreportv1', 'getlastweekreportv1', 'getdayreportcompetehotelreport'];
        foreach ($needles as $needle) {
            if (str_contains($url, $needle)) {
                return true;
            }
        }
        return false;
    }

    private function extractCtripCapturedComments(array $payload): array
    {
        $rows = [];
        foreach (['reviews', 'comments', 'commentList'] as $key) {
            if (array_key_exists($key, $payload)) {
                $rows = array_merge($rows, $this->normalizeCtripCapturedCommentList($payload[$key]));
            }
        }

        if (isset($payload['responses']) && is_array($payload['responses'])) {
            foreach ($payload['responses'] as $response) {
                if (!is_array($response)) {
                    continue;
                }
                $url = strtolower((string)($response['url'] ?? ''));
                $section = strtolower((string)($response['section'] ?? $response['type'] ?? ''));
                if ($section !== 'reviews' && !str_contains($url, 'getcommentlist')) {
                    continue;
                }
                $data = $response['data'] ?? $response['body'] ?? $response['json'] ?? [];
                $rows = array_merge($rows, $this->normalizeCtripCapturedCommentList($data));
            }
        }

        $seen = [];
        $deduped = [];
        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }
            $identity = $this->extractCtripCommentId($row);
            if ($identity === '') {
                $identity = md5(json_encode([
                    $row['content'] ?? $row['commentContent'] ?? $row['_dom_text'] ?? '',
                    $row['user_name'] ?? $row['userName'] ?? '',
                    $row['comment_time'] ?? $row['commentTime'] ?? '',
                ], JSON_UNESCAPED_UNICODE));
            }
            if (isset($seen[$identity])) {
                continue;
            }
            $seen[$identity] = true;
            $deduped[] = $row;
        }

        return $deduped;
    }

    private function normalizeCtripCapturedCommentList($value): array
    {
        if (!is_array($value)) {
            return [];
        }
        if ($this->isSequentialArray($value)) {
            return array_values(array_filter($value, static fn($item): bool => is_array($item)));
        }

        $paths = [
            ['data', 'commentList'],
            ['data', 'comments'],
            ['data', 'list'],
            ['data', 'rows'],
            ['result', 'commentList'],
            ['result', 'comments'],
            ['result', 'list'],
            ['commentList'],
            ['comments'],
            ['list'],
            ['rows'],
            ['data'],
        ];
        foreach ($paths as $path) {
            $nested = $this->readNestedMeituanValue($value, $path);
            if (is_array($nested)) {
                $rows = $this->normalizeCtripCapturedCommentList($nested);
                if (!empty($rows)) {
                    return $rows;
                }
            }
        }

        return $this->looksLikeCtripCapturedCommentRow($value) ? [$value] : [];
    }

    private function looksLikeCtripCapturedCommentRow(array $value): bool
    {
        foreach (['review_id', 'reviewId', 'comment_id', 'commentId', 'id', 'commentContent', 'reviewContent', 'content', 'comment', 'score', 'rating', 'totalScore', 'commentScore'] as $key) {
            if (array_key_exists($key, $value)) {
                return true;
            }
        }
        return false;
    }

    private function resolveMeituanCaptureChromePath(): string
    {
        $configured = trim((string)(getenv('CHROME_PATH') ?: env('CHROME_PATH', '')));
        if ($configured !== '' && is_file($configured)) {
            return $configured;
        }
        return '';
    }

    private function runMeituanCaptureProcess(array $args, string $cwd, int $timeoutSeconds): array
    {
        $command = implode(' ', array_map('escapeshellarg', $args));
        $descriptors = [
            0 => ['pipe', 'r'],
            1 => ['pipe', 'w'],
            2 => ['pipe', 'w'],
        ];
        $process = proc_open($command, $descriptors, $pipes, $cwd);
        if (!is_resource($process)) {
            return ['success' => false, 'message' => '无法启动美团抓取进程', 'stdout' => '', 'stderr' => ''];
        }

        fclose($pipes[0]);
        stream_set_blocking($pipes[1], false);
        stream_set_blocking($pipes[2], false);
        $stdout = '';
        $stderr = '';
        $startedAt = time();
        $timedOut = false;

        while (true) {
            $stdout .= (string)stream_get_contents($pipes[1]);
            $stderr .= (string)stream_get_contents($pipes[2]);
            $status = proc_get_status($process);
            if (!$status['running']) {
                break;
            }
            if (time() - $startedAt > $timeoutSeconds) {
                $timedOut = true;
                proc_terminate($process);
                break;
            }
            usleep(250000);
        }

        $stdout .= (string)stream_get_contents($pipes[1]);
        $stderr .= (string)stream_get_contents($pipes[2]);
        fclose($pipes[1]);
        fclose($pipes[2]);
        $exitCode = proc_close($process);

        if ($timedOut) {
            return [
                'success' => false,
                'message' => '美团浏览器抓取超时，请确认弹出的浏览器已完成登录并能访问 eBooking 页面',
                'stdout' => $stdout,
                'stderr' => $stderr,
            ];
        }
        if ($exitCode !== 0 && $exitCode !== -1) {
            return [
                'success' => false,
                'message' => '美团浏览器抓取失败，退出码 ' . $exitCode,
                'stdout' => $stdout,
                'stderr' => $stderr,
            ];
        }

        return ['success' => true, 'message' => 'ok', 'stdout' => $stdout, 'stderr' => $stderr];
    }

    private function appendCtripApprovedMappingsArg(array $args, array $source, string $projectRoot): array
    {
        $approvedMappings = $this->resolveCtripApprovedMappingsPath($source, $projectRoot);
        if ($approvedMappings['configured'] && $approvedMappings['path'] !== '') {
            $args[] = '--approved-mappings=' . $approvedMappings['path'];
        }

        return [
            'args' => $args,
            'approved_mappings' => $approvedMappings,
            'error' => $approvedMappings['configured'] && $approvedMappings['path'] === '' ? (string)$approvedMappings['error'] : '',
        ];
    }

    private function appendCtripCaptureGateArgs(array $args, array $source): array
    {
        $fieldCoverageRate = $this->firstPresentCtripConfigValue($source, [
            'min_field_coverage_rate',
            'minFieldCoverageRate',
            'field_coverage_rate',
            'fieldCoverageRate',
        ], 80);
        if (is_numeric($fieldCoverageRate)) {
            $rate = max(0.0, min(100.0, (float)$fieldCoverageRate));
            $args[] = '--min-field-coverage-rate=' . $this->formatCtripCaptureGateNumber($rate);
        }

        $maxMissingFields = $this->firstPresentCtripConfigValue($source, [
            'max_missing_fields',
            'maxMissingFields',
        ], null);
        if ($maxMissingFields !== null && $maxMissingFields !== '' && is_numeric($maxMissingFields)) {
            $args[] = '--max-missing-fields=' . (string)max(0, (int)$maxMissingFields);
        }

        $requireFieldCoverage = $this->firstPresentCtripConfigValue($source, [
            'require_field_coverage',
            'requireFieldCoverage',
        ], null);
        if ($requireFieldCoverage !== null && $this->meituanBool($requireFieldCoverage)) {
            $args[] = '--require-field-coverage';
        }

        return $args;
    }

    private function isCtripLoginOnlyRequest(array $source): bool
    {
        foreach (['login_only', 'loginOnly', 'auth_only', 'authOnly', 'prepare_profile', 'prepareProfile'] as $key) {
            if (array_key_exists($key, $source) && $this->meituanBool($source[$key])) {
                return true;
            }
        }

        return false;
    }

    private function appendCtripLoginOnlyArg(array $args, array $source): array
    {
        if ($this->isCtripLoginOnlyRequest($source)) {
            $args[] = '--login-only=true';
        }

        return $args;
    }

    private function buildCtripLoginOnlyResponsePayload(array $payload, string $outputPath, string $stdout): array
    {
        return [
            'mode' => (string)($payload['mode'] ?? 'login_only'),
            'profile_id' => (string)($payload['profile_id'] ?? ''),
            'auth_status' => $payload['auth_status'] ?? null,
            'capture_gate' => $payload['capture_gate'] ?? null,
            'pages' => $payload['pages'] ?? [],
            'saved_count' => 0,
            'row_count' => 0,
            'counts' => [
                'business' => 0,
                'traffic' => 0,
                'standard_rows' => 0,
            ],
            'output' => $outputPath,
            'stdout' => $stdout,
        ];
    }

    private function formatCtripCaptureGateNumber(float $value): string
    {
        if (abs($value - round($value)) < 0.000001) {
            return (string)(int)round($value);
        }
        return rtrim(rtrim(number_format($value, 2, '.', ''), '0'), '.');
    }

    private function prepareCtripCookieApiCaptureFiles(array $requestData, string $projectRoot, ?int $systemHotelId): array
    {
        $config = $this->buildCtripCookieApiCaptureConfigFromRequest($requestData, $systemHotelId);
        $outputDir = $projectRoot . DIRECTORY_SEPARATOR . 'runtime' . DIRECTORY_SEPARATOR . 'ctrip_capture';
        if (!is_dir($outputDir) && !mkdir($outputDir, 0775, true) && !is_dir($outputDir)) {
            throw new \InvalidArgumentException('无法创建携程 Cookie API 采集输出目录');
        }

        $profileId = $this->safeMeituanCaptureFilePart((string)($config['profile_id'] ?? 'ctrip_cookie_api'));
        $prefix = $profileId . '_' . date('YmdHis');
        $inputPath = $outputDir . DIRECTORY_SEPARATOR . $prefix . '.input.json';
        $outputPath = $outputDir . DIRECTORY_SEPARATOR . $prefix . '.json';

        file_put_contents($inputPath, json_encode($config, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT | JSON_INVALID_UTF8_SUBSTITUTE) . PHP_EOL, LOCK_EX);

        return [
            'config' => $config,
            'input_path' => $inputPath,
            'output_path' => $outputPath,
        ];
    }

    private function buildCtripProfileStatus(array $requestData, ?int $systemHotelId = null, bool $probeCookie = false): array
    {
        $hotelId = $systemHotelId !== null ? (int)$systemHotelId : 0;
        $profileId = $this->ctripProfileStoreIdFromConfig($requestData, $hotelId);
        $safeProfileId = $profileId !== '' ? $this->safeMeituanCaptureFilePart($profileId) : '';
        $relativeDir = $safeProfileId !== '' ? 'storage/ctrip_profile_' . $safeProfileId : '';
        $projectRoot = dirname(__DIR__, 2);
        $profileDir = $relativeDir !== ''
            ? $projectRoot . DIRECTORY_SEPARATOR . str_replace('/', DIRECTORY_SEPARATOR, $relativeDir)
            : '';
        $exists = $profileDir !== '' && is_dir($profileDir);

        $status = [
            'profile_id' => $profileId,
            'profile_dir' => $relativeDir,
            'exists' => $exists,
            'cookie_probe_requested' => $probeCookie,
            'cookie_extractable' => false,
            'cookie_count' => 0,
            'skipped_count' => 0,
            'last_modified_at' => $exists ? date('Y-m-d H:i:s', (int)filemtime($profileDir)) : '',
            'status' => $exists ? 'profile_found' : 'missing_profile',
            'next_action' => $exists
                ? '可直接用于携程 Cookie API；如 Cookie 探测失败，请重新登录携程 Profile'
                : '点击“只登录并保存 Profile”完成携程登录，或直接粘贴有效 Cookie',
        ];

        if (!$exists || !$probeCookie) {
            return $status;
        }

        $requestData['profile_id'] = $profileId;
        try {
            $meta = $this->createCtripCookieApiCookieFileFromProfile($requestData, $projectRoot, $hotelId);
            $this->removeAutoFetchCookieFile((string)($meta['cookie_file'] ?? ''));
            $cookieCount = (int)($meta['cookie_count'] ?? 0);
            $status['cookie_extractable'] = $cookieCount > 0;
            $status['cookie_count'] = $cookieCount;
            $status['skipped_count'] = (int)($meta['skipped_count'] ?? 0);
            $status['status'] = $cookieCount > 0 ? 'ready' : 'profile_found_without_cookie';
            $status['next_action'] = $cookieCount > 0
                ? '可使用该 Profile 执行携程 Cookie API 诊断采集'
                : 'Profile 存在但未提取到可用携程 Cookie，请重新登录携程后台';
        } catch (\Throwable $e) {
            $status['status'] = 'profile_cookie_unreadable';
            $status['cookie_error'] = $this->trimMeituanCaptureLog($e->getMessage());
            $status['next_action'] = 'Profile 存在但 Cookie 不可读取，请关闭相关浏览器窗口后重试，或重新登录携程 Profile';
        }

        return $status;
    }

    private function buildMeituanProfileStatus(array $requestData, ?int $systemHotelId = null, bool $probeLogin = false): array
    {
        $hotelId = $systemHotelId !== null ? (int)$systemHotelId : 0;
        if ($hotelId > 0) {
            $source = $this->firstBrowserProfileSource($hotelId, 'meituan');
            $sourceConfig = $source ? $this->decodeBrowserProfileSourceConfig($source) : [];
            $requestData = array_merge($sourceConfig, $this->resolveMeituanFetchConfigForHotel($hotelId), $requestData);
        }

        $storeId = $this->meituanProfileStoreIdFromConfig($requestData);
        $safeStoreId = $storeId !== '' ? $this->safeMeituanCaptureFilePart($storeId) : '';
        $relativeDir = $safeStoreId !== '' ? 'storage/meituan_profile_' . $safeStoreId : '';
        $projectRoot = dirname(__DIR__, 2);
        $profileDir = $relativeDir !== ''
            ? $projectRoot . DIRECTORY_SEPARATOR . str_replace('/', DIRECTORY_SEPARATOR, $relativeDir)
            : '';
        $exists = $profileDir !== '' && is_dir($profileDir);
        $cached = ($hotelId > 0 && $storeId !== '') ? $this->readPlatformProfileStatusCache('meituan', $hotelId, $storeId) : [];

        $status = [
            'store_id' => $storeId,
            'poi_id' => (string)($requestData['poi_id'] ?? $requestData['poiId'] ?? ''),
            'profile_dir' => $relativeDir,
            'exists' => $exists,
            'login_probe_requested' => $probeLogin,
            'last_modified_at' => $exists ? date('Y-m-d H:i:s', (int)filemtime($profileDir)) : '',
            'last_login_check_time' => (string)($cached['checked_at'] ?? ''),
            'auth_status' => $cached['auth_status'] ?? null,
            'capture_gate' => $cached['capture_gate'] ?? null,
            'status' => $exists ? 'profile_found' : 'missing_profile',
            'current_status' => $exists ? '待登录' : '待登录',
            'status_code' => $exists ? 'waiting_login' : 'waiting_login',
            'next_action' => $exists
                ? '点击“检测登录”确认美团 Profile 是否仍有效'
                : '点击“登录美团”完成平台验证后复用 Profile',
        ];

        if (!$exists || !$probeLogin) {
            return $status;
        }

        $probe = $this->runMeituanProfileLoginProbe($requestData, $projectRoot, $hotelId, $storeId);
        $authStatus = is_array($probe['auth_status'] ?? null) ? $probe['auth_status'] : [
            'ok' => false,
            'status' => 'login_required',
            'message' => (string)($probe['message'] ?? 'Meituan login probe failed.'),
        ];
        $isOk = !empty($authStatus['ok']);
        $status['auth_status'] = $authStatus;
        $status['capture_gate'] = $probe['capture_gate'] ?? null;
        $status['output'] = $probe['output'] ?? '';
        $status['last_login_check_time'] = date('Y-m-d H:i:s');
        $status['status'] = $isOk ? 'ready' : 'login_required';
        $status['status_code'] = $isOk ? 'logged_in' : 'login_expired';
        $status['current_status'] = $isOk ? '已登录' : '登录失效';
        $status['next_action'] = $isOk ? '可使用该 Profile 执行美团自动采集' : '重新登录美团平台账号';

        if ($hotelId > 0 && $storeId !== '') {
            $this->cachePlatformProfileStatus('meituan', $hotelId, $storeId, [
                'checked_at' => $status['last_login_check_time'],
                'auth_status' => $authStatus,
                'capture_gate' => $status['capture_gate'],
                'status_code' => $status['status_code'],
                'output' => $status['output'],
            ]);
        }

        return $status;
    }

    private function runMeituanProfileLoginProbe(array $requestData, string $projectRoot, int $systemHotelId, string $storeId): array
    {
        $scriptPath = $projectRoot . DIRECTORY_SEPARATOR . 'scripts' . DIRECTORY_SEPARATOR . 'meituan_browser_capture.mjs';
        if (!is_file($scriptPath)) {
            return ['message' => '未找到美团浏览器抓取脚本'];
        }
        $nodeBinary = $this->resolveMeituanCaptureNodeBinary();
        if ($nodeBinary === '') {
            return ['message' => '未找到 Node.js'];
        }
        $outputDir = $projectRoot . DIRECTORY_SEPARATOR . 'runtime' . DIRECTORY_SEPARATOR . 'meituan_capture';
        if (!is_dir($outputDir) && !mkdir($outputDir, 0775, true) && !is_dir($outputDir)) {
            return ['message' => '无法创建美团登录检测输出目录'];
        }
        $outputPath = $outputDir . DIRECTORY_SEPARATOR . 'meituan_login_probe_' . $this->safeMeituanCaptureFilePart($storeId) . '_' . date('YmdHis') . '.json';
        $args = [
            $nodeBinary,
            $scriptPath,
            '--store-id=' . $storeId,
            '--system-hotel-id=' . (string)$systemHotelId,
            '--output=' . $outputPath,
            '--login-only=true',
            '--headless=true',
            '--login-timeout-ms=30000',
            '--sections=traffic',
        ];
        $poiId = trim((string)($requestData['poi_id'] ?? $requestData['poiId'] ?? ''));
        if ($poiId !== '') {
            $args[] = '--poi-id=' . $poiId;
        }
        $chromePath = $this->resolveMeituanCaptureChromePath();
        if ($chromePath !== '') {
            $args[] = '--chrome-path=' . $chromePath;
        }

        $runResult = $this->runMeituanCaptureProcess($args, $projectRoot, 90);
        if (!is_file($outputPath)) {
            return [
                'message' => (string)($runResult['message'] ?? '美团登录检测未生成结果文件'),
                'stdout' => $this->trimMeituanCaptureLog((string)($runResult['stdout'] ?? '')),
                'stderr' => $this->trimMeituanCaptureLog((string)($runResult['stderr'] ?? '')),
            ];
        }

        $payload = json_decode((string)file_get_contents($outputPath), true);
        if (!is_array($payload)) {
            return ['message' => '美团登录检测 JSON 无法解析', 'output' => $outputPath];
        }
        $payload['output'] = $outputPath;
        return $payload;
    }

    private function createCtripCookieApiCookieFileFromProfile(array $requestData, string $projectRoot, int $systemHotelId): array
    {
        $profileId = $this->ctripProfileStoreIdFromConfig($requestData, $systemHotelId);
        if ($profileId === '') {
            throw new \InvalidArgumentException('missing Ctrip Cookie and browser Profile ID');
        }

        $safeProfileId = $this->safeMeituanCaptureFilePart($profileId);
        $profileDir = $projectRoot . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'ctrip_profile_' . $safeProfileId;
        if (!is_dir($profileDir)) {
            throw new \InvalidArgumentException("missing Ctrip Cookie and storage/ctrip_profile_{$safeProfileId}");
        }

        $extractor = $projectRoot . DIRECTORY_SEPARATOR . 'scripts' . DIRECTORY_SEPARATOR . 'extract_chromium_cookie_header.php';
        if (!is_file($extractor)) {
            throw new \InvalidArgumentException('missing Chromium Cookie extractor');
        }

        $phpBinary = $this->resolveLocalPhpBinary();
        if ($phpBinary === '') {
            throw new \InvalidArgumentException('missing PHP binary for Chromium Cookie extraction');
        }

        $dir = $projectRoot . DIRECTORY_SEPARATOR . 'runtime' . DIRECTORY_SEPARATOR . 'ota_cookie_injection';
        if (!is_dir($dir) && !mkdir($dir, 0775, true) && !is_dir($dir)) {
            throw new \InvalidArgumentException('failed to create Cookie temp dir');
        }
        try {
            $suffix = bin2hex(random_bytes(6));
        } catch (\Throwable $e) {
            $suffix = str_replace('.', '', uniqid('', true));
        }
        $cookieFile = $dir . DIRECTORY_SEPARATOR . $this->safeMeituanCaptureFilePart('ctrip_profile_' . $safeProfileId . '_' . $suffix) . '.txt';

        $runResult = $this->runMeituanCaptureProcess([
            $phpBinary,
            $extractor,
            '--profile-dir=' . $profileDir,
            '--output=' . $cookieFile,
        ], $projectRoot, 30);
        if (!$runResult['success'] || !is_file($cookieFile)) {
            $this->removeAutoFetchCookieFile($cookieFile);
            throw new \InvalidArgumentException('failed to extract Ctrip Cookie from browser Profile: ' . $this->trimMeituanCaptureLog((string)($runResult['stderr'] ?? $runResult['stdout'] ?? '')));
        }

        $meta = json_decode(trim((string)($runResult['stdout'] ?? '')), true);
        if (!is_array($meta)) {
            $meta = [];
        }
        return [
            'cookie_file' => $cookieFile,
            'profile_id' => $profileId,
            'cookie_count' => (int)($meta['cookie_count'] ?? 0),
            'skipped_count' => (int)($meta['skipped_count'] ?? 0),
        ];
    }

    private function resolveLocalPhpBinary(): string
    {
        $configured = trim((string)(getenv('PHP_BINARY') ?: env('PHP_BINARY', '')));
        $candidates = array_filter([
            $configured,
            defined('PHP_BINARY') ? PHP_BINARY : '',
            'C:\\xampp\\php\\php.exe',
            'D:\\xampp\\php\\php.exe',
            'C:\\php\\php.exe',
            'php',
        ]);
        foreach ($candidates as $candidate) {
            $candidate = trim((string)$candidate);
            if ($candidate === '') {
                continue;
            }
            if ($candidate === 'php' || is_file($candidate)) {
                return $candidate;
            }
        }
        return '';
    }

    private function buildCtripCookieApiCaptureConfigFromRequest(array $requestData, ?int $systemHotelId): array
    {
        $dataDate = $this->normalizeOnlineDataDate($requestData['data_date'] ?? $requestData['dataDate'] ?? '');
        if ($dataDate === '') {
            $dataDate = date('Y-m-d');
        }
        $hotelId = trim((string)(
            $requestData['hotel_id']
            ?? $requestData['hotelId']
            ?? $requestData['ctrip_hotel_id']
            ?? $requestData['ctripHotelId']
            ?? ''
        ));
        $profileId = trim((string)($requestData['profile_id'] ?? $requestData['profileId'] ?? $hotelId ?: 'ctrip_cookie_api'));
        $endpoints = $this->normalizeCtripCookieApiEndpointsFromRequest($requestData, $dataDate, $hotelId);
        if ($endpoints === []) {
            throw new \InvalidArgumentException('请提供携程接口 Request URL，或 endpoints/endpoints_json 接口清单');
        }

        return [
            'source' => 'ctrip_cookie_api',
            'profile_id' => $profileId,
            'hotel_id' => $hotelId,
            'hotel_name' => trim((string)($requestData['hotel_name'] ?? $requestData['hotelName'] ?? '')),
            'system_hotel_id' => $systemHotelId,
            'data_date' => $dataDate,
            'endpoints' => $endpoints,
        ];
    }

    private function normalizeCtripCookieApiEndpointsFromRequest(array $requestData, string $dataDate = '', string $hotelId = ''): array
    {
        $raw = $requestData['endpoints']
            ?? $requestData['requests']
            ?? $requestData['request_urls']
            ?? $requestData['requestUrls']
            ?? $requestData['endpoints_json']
            ?? $requestData['endpointsJson']
            ?? null;

        $items = [];
        if ($raw !== null && $raw !== '') {
            if (is_array($raw)) {
                $items = $raw;
            } elseif (is_scalar($raw)) {
                $text = trim((string)$raw);
                if ($text !== '' && (str_starts_with($text, '[') || str_starts_with($text, '{'))) {
                    $decoded = $this->parseJsonParams($text);
                    $items = $this->isSequentialArray($decoded) ? $decoded : [$decoded];
                } else {
                    $items = array_values(array_filter(array_map('trim', preg_split('/[\r\n,]+/', $text) ?: [])));
                }
            }
        }

        if ($items === []) {
            $singleUrl = trim((string)($requestData['request_url'] ?? $requestData['requestUrl'] ?? $requestData['url'] ?? ''));
            if ($singleUrl !== '') {
                $items[] = [
                    'request_url' => $singleUrl,
                    'method' => $requestData['method'] ?? 'GET',
                    'payload' => $this->readCtripEndpointEvidenceObject($requestData, [
                        'payload',
                        'payload_json',
                        'payloadJson',
                        'request_payload',
                        'requestPayload',
                        'request_payload_json',
                    ]),
                    'headers' => $this->readCtripEndpointEvidenceObject($requestData, [
                        'headers',
                        'headers_json',
                        'headersJson',
                        'request_headers',
                        'request_headers_json',
                        'requestHeadersJson',
                    ], true),
                ];
            }
        }

        $endpoints = [];
        foreach ($items as $item) {
            if (is_string($item)) {
                $item = ['request_url' => $item, 'method' => 'GET'];
            }
            if (!is_array($item)) {
                continue;
            }
            $requestUrl = trim((string)($item['request_url'] ?? $item['requestUrl'] ?? $item['url'] ?? ''));
            if ($requestUrl === '') {
                continue;
            }
            if (!$this->isAllowedOtaRequestUrl($requestUrl, ['ctrip.com', 'ctripbiz.com', 'ctripbiz.cn'])) {
                throw new \InvalidArgumentException('携程 Cookie API 采集仅允许 HTTPS 的 ctrip.com / ctripbiz.com / ctripbiz.cn 接口');
            }
            $method = strtoupper(trim((string)($item['method'] ?? $item['request_method'] ?? $item['requestMethod'] ?? 'GET')));
            if (!in_array($method, ['GET', 'POST'], true)) {
                throw new \InvalidArgumentException('携程 Cookie API 采集 method 仅支持 GET 或 POST');
            }
            $payload = $item['payload'] ?? $item['request_payload'] ?? $item['requestPayload'] ?? $item['params'] ?? [];
            if (is_string($payload) && trim($payload) !== '') {
                $payload = $this->parseJsonParams($payload);
            }
            if (!is_array($payload)) {
                $payload = [];
            }
            $payload = $this->normalizeCtripCookieApiPayloadDefaults((string)$requestUrl, $method, $payload, $dataDate, $hotelId);
            $headers = $item['headers'] ?? $item['request_headers'] ?? $item['requestHeaders'] ?? [];
            if (is_string($headers) && trim($headers) !== '') {
                $headers = str_starts_with(trim($headers), '{')
                    ? $this->parseJsonParams($headers)
                    : $this->parseCtripEndpointEvidenceHeaderLines($headers);
            }
            $endpoints[] = [
                'request_url' => $requestUrl,
                'method' => $method,
                'payload' => is_array($payload) ? $payload : [],
                'headers' => is_array($headers) ? $headers : [],
                'section' => trim((string)($item['section'] ?? $item['capture_section'] ?? $item['captureSection'] ?? '')),
            ];
        }

        return $endpoints;
    }

    private function normalizeCtripCookieApiPayloadDefaults(string $requestUrl, string $method, array $payload, string $dataDate = '', string $hotelId = ''): array
    {
        if ($method !== 'POST' || $payload !== []) {
            return $payload;
        }

        $window = $this->buildCtripCookieApiDateWindow($dataDate);
        $url = strtolower((string)$requestUrl);
        $path = strtolower((string)(parse_url($requestUrl, PHP_URL_PATH) ?? ''));
        $endpoint = $path === '' ? '' : strtolower(basename($path));

        $setIfMissing = static function (array &$target, string $key, mixed $value): void {
            if (!array_key_exists($key, $target) || $target[$key] === '') {
                $target[$key] = $value;
            }
        };
        $contains = static function (string $value, array $patterns) use ($url, $endpoint): bool {
            foreach ($patterns as $pattern) {
                if (str_contains($value, (string)$pattern)) {
                    return true;
                }
            }
            return false;
        };
        $hasDateWindow = isset($window['startDate']) && isset($window['endDate']);
        $setDateWindow = function (array &$target) use ($hasDateWindow, $window, $setIfMissing): void {
            if (!$hasDateWindow) {
                return;
            }
            $setIfMissing($target, 'startDate', $window['startDate']);
            $setIfMissing($target, 'endDate', $window['endDate']);
        };

        if (
            $contains($url, ['querymarketdetails', 'queryhotroom', 'queryordertrend', 'queryhoteloccupiedroomtrend', 'queryroomtensities', 'queryhoteltensities', 'querymarketroomtensity', 'queryroomoccupiedtrend'])
            || $contains($endpoint, ['querymarketdetails', 'queryhotroom', 'queryordertrend', 'queryhoteloccupiedroomtrend', 'queryroomtensities', 'queryhoteltensities', 'querymarketroomtensity', 'queryroomoccupiedtrend'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'EBK');
            $setDateWindow($payload);
            return $payload;
        }

        if (
            $contains($url, ['queryscanflowdetailsv2', 'queryflowtransformnewv1', 'queryflowtransfornewv1', 'queryflowtransfernewv1', 'queryflowtransform', 'queryflowsource', 'querycityhotkeywords', 'querysearchflowdetails'])
            || $contains($endpoint, ['queryscanflowdetailsv2', 'queryflowtransformnewv1', 'queryflowtransfornewv1', 'queryflowtransfernewv1', 'queryflowtransform', 'queryflowsource', 'querycityhotkeywords', 'querysearchflowdetails'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'EBK');
            $setDateWindow($payload);
            return $payload;
        }

        if (
            $contains($url, ['querycampaignsummaryreport'])
            || $contains($endpoint, ['querycampaignsummaryreport'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'EBK');
            $setIfMissing($payload, 'pageIndex', 1);
            $setIfMissing($payload, 'pageSize', 20);
            $setDateWindow($payload);
            return $payload;
        }

        if (
            $contains($url, ['queryuser', 'getuserimagelist', 'getorderdistribution'])
            || $contains($endpoint, ['queryusersex', 'queryusertype', 'queryuserpriceinfo', 'queryusersource', 'queryuserbookingdays', 'queryuserstaydays', 'queryuserfeatures', 'queryuserage', 'queryuserpoint', 'queryusertraveltime', 'queryuserstar', 'queryuserprice', 'queryordertype', 'queryuserorders', 'getuserimagelist', 'getorderdistribution'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'EBK');
            $setDateWindow($payload);
            $normalizedHotelId = trim((string)$hotelId);
            if ($normalizedHotelId !== '') {
                $setIfMissing($payload, 'hotelId', $normalizedHotelId);
                $setIfMissing($payload, 'nodeId', $normalizedHotelId);
            }
            return $payload;
        }

        if (
            $contains($url, ['getimindex', 'getimdatedistribute', 'getimsessiondistribute', 'getimorderconversionbyday', 'getimorderconversiondetail'])
            || $contains($endpoint, ['getimindex', 'getimdatedistribute', 'getimsessiondistribute', 'getimorderconversionbyday', 'getimorderconversiondetail'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'EBK');
            $setDateWindow($payload);
            $normalizedHotelId = trim((string)$hotelId);
            if ($normalizedHotelId !== '') {
                $setIfMissing($payload, 'hotelId', $normalizedHotelId);
                $setIfMissing($payload, 'nodeId', $normalizedHotelId);
            }
            return $payload;
        }

        if (
            $contains($url, ['getmanagementdata', 'getmasterhotellabel', 'getflowdata', 'getservicedata', 'getflowsource', 'gettripartiteorderloss', 'getlossordercompetehotel', 'getcompetingrank'])
            || $contains($endpoint, ['getmanagementdata', 'getmasterhotellabel', 'getflowdata', 'getservicedata', 'getflowsource', 'gettripartiteorderloss', 'getlossordercompetehotel', 'getcompetingrank'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'EBK');
            $setDateWindow($payload);
            $normalizedHotelId = trim((string)$hotelId);
            if ($normalizedHotelId !== '') {
                $setIfMissing($payload, 'hotelId', $normalizedHotelId);
                $setIfMissing($payload, 'nodeId', $normalizedHotelId);
            }
            return $payload;
        }

        if (
            $contains($url, ['getbbkcomprehensivetable'])
            || $contains($endpoint, ['getbbkcomprehensivetable'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $aliasDate = $hasDateWindow ? $window['startDate'] : '';
            $setIfMissing($payload, 'date', $aliasDate);
            $setIfMissing($payload, 'reportDate', $aliasDate);
            return $payload;
        }

        if (
            $contains($url, ['datacenterbusinessreportdetail', 'datacentercomparisonreportdetail', 'datacentercomparatorreportdetail'])
            || $contains($endpoint, ['datacenterbusinessreportdetail', 'datacentercomparisonreportdetail', 'datacentercomparatorreportdetail'])
        ) {
            $setIfMissing($payload, 'hostType', 'HE');
            $setIfMissing($payload, 'platform', 'BBK');
            $setDateWindow($payload);
            $normalizedHotelId = trim((string)$hotelId);
            if ($normalizedHotelId !== '') {
                $setIfMissing($payload, 'hotelId', $normalizedHotelId);
                $setIfMissing($payload, 'nodeId', $normalizedHotelId);
            }
            return $payload;
        }

        return $payload;
    }

    private function buildCtripCookieApiDateWindow(string $dataDate): array
    {
        $dataDate = $this->normalizeOnlineDataDate($dataDate);
        if ($dataDate === '') {
            return [];
        }

        return [
            'startDate' => $dataDate,
            'endDate' => $dataDate,
        ];
    }

    private function prepareCtripEndpointEvidenceValidationFiles(array $requestData, string $projectRoot): array
    {
        $bundle = $this->buildCtripEndpointEvidenceBundleFromRequest($requestData);
        $outputDir = $projectRoot . DIRECTORY_SEPARATOR . 'runtime' . DIRECTORY_SEPARATOR . 'ctrip_endpoint_evidence';
        if (!is_dir($outputDir) && !mkdir($outputDir, 0775, true) && !is_dir($outputDir)) {
            throw new \InvalidArgumentException('无法创建携程接口证据输出目录');
        }

        $path = parse_url((string)$bundle['request_url'], PHP_URL_PATH);
        $endpointName = $path ? basename((string)$path) : 'endpoint';
        $prefix = $this->safeMeituanCaptureFilePart($endpointName ?: 'endpoint') . '_' . date('YmdHis');
        $inputPath = $outputDir . DIRECTORY_SEPARATOR . $prefix . '.input.json';
        $outputPath = $outputDir . DIRECTORY_SEPARATOR . $prefix . '.result.json';
        $markdownPath = $outputDir . DIRECTORY_SEPARATOR . $prefix . '.md';
        $candidatePath = $outputDir . DIRECTORY_SEPARATOR . $prefix . '.candidate.json';

        file_put_contents($inputPath, json_encode($bundle, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT) . PHP_EOL);

        return [
            'bundle' => $bundle,
            'input_path' => $inputPath,
            'output_path' => $outputPath,
            'markdown_path' => $markdownPath,
            'candidate_path' => $candidatePath,
        ];
    }

    private function buildCtripEndpointEvidenceBundleFromRequest(array $requestData): array
    {
        $requestUrl = trim((string)($requestData['request_url'] ?? $requestData['requestUrl'] ?? $requestData['url'] ?? ''));
        if ($requestUrl === '') {
            throw new \InvalidArgumentException('Request URL不能为空');
        }
        if (!$this->isAllowedOtaRequestUrl($requestUrl, ['ctrip.com', 'ctripbiz.com', 'ctripbiz.cn'])) {
            throw new \InvalidArgumentException('携程接口证据只允许 HTTPS 的 ctrip.com / ctripbiz.com / ctripbiz.cn 域名');
        }

        $method = strtoupper(trim((string)($requestData['method'] ?? $requestData['request_method'] ?? 'POST')));
        if (!in_array($method, ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'], true)) {
            $method = 'POST';
        }

        return [
            'request_url' => $requestUrl,
            'method' => $method,
            'headers' => $this->redactCtripEndpointEvidenceValue($this->readCtripEndpointEvidenceObject($requestData, [
                'headers',
                'headers_json',
                'headersJson',
                'request_headers',
                'request_headers_json',
                'requestHeadersJson',
            ], true)),
            'payload' => $this->redactCtripEndpointEvidenceValue($this->readCtripEndpointEvidenceObject($requestData, [
                'payload',
                'payload_json',
                'payloadJson',
                'request_payload',
                'requestPayload',
                'request_payload_json',
            ])),
            'response' => $this->redactCtripEndpointEvidenceValue($this->readCtripEndpointEvidenceObject($requestData, [
                'response',
                'response_json',
                'responseJson',
                'preview',
                'preview_json',
                'previewJson',
                'response_preview',
                'responsePreview',
            ])),
            'page_context' => $this->redactCtripEndpointEvidenceValue($this->readCtripEndpointEvidenceObject($requestData, [
                'page_context',
                'pageContext',
                'page_context_json',
                'pageContextJson',
            ])),
            'params' => $this->redactCtripEndpointEvidenceValue($this->readCtripEndpointEvidenceObject($requestData, [
                'params',
                'parameters',
                'params_json',
                'paramsJson',
            ])),
        ];
    }

    private function readCtripEndpointEvidenceObject(array $requestData, array $keys, bool $allowHeaderLines = false): array
    {
        foreach ($keys as $key) {
            if (!array_key_exists($key, $requestData)) {
                continue;
            }
            $value = $requestData[$key];
            if (is_array($value)) {
                return $value;
            }
            if (!is_scalar($value)) {
                continue;
            }
            $raw = trim((string)$value);
            if ($raw === '') {
                return [];
            }
            if ($allowHeaderLines && !str_starts_with($raw, '{') && !str_starts_with($raw, '[')) {
                return $this->parseCtripEndpointEvidenceHeaderLines($raw);
            }
            try {
                return $this->parseJsonParams($raw);
            } catch (\InvalidArgumentException $e) {
                throw new \InvalidArgumentException($key . ' JSON格式不正确');
            }
        }

        return [];
    }

    private function parseCtripEndpointEvidenceHeaderLines(string $raw): array
    {
        $headers = [];
        foreach (preg_split('/\r?\n/', $raw) ?: [] as $line) {
            $line = trim((string)$line);
            if ($line === '' || !str_contains($line, ':')) {
                continue;
            }
            [$name, $value] = explode(':', $line, 2);
            $name = trim($name);
            if ($name !== '') {
                $headers[$name] = trim($value);
            }
        }
        return $headers;
    }

    private function readCtripCookieHeaderFromRequest(array $requestData): string
    {
        foreach (['cookies', 'cookie', 'cookie_header', 'cookieHeader'] as $key) {
            if (!array_key_exists($key, $requestData)) {
                continue;
            }
            $cookie = $this->normalizeCtripCookieHeaderText($requestData[$key]);
            if ($cookie !== '') {
                return $cookie;
            }
        }

        $headers = $this->readCtripEndpointEvidenceObject($requestData, [
            'headers',
            'headers_json',
            'headersJson',
            'request_headers',
            'request_headers_json',
            'requestHeadersJson',
        ], true);
        foreach ($headers as $name => $value) {
            $headerName = strtolower(trim((string)$name));
            if ($headerName !== 'cookie' && $headerName !== 'cookies') {
                continue;
            }
            $cookie = $this->normalizeCtripCookieHeaderText($value);
            if ($cookie !== '') {
                return $cookie;
            }
        }

        return '';
    }

    private function normalizeCtripCookieHeaderText(mixed $value): string
    {
        if (is_array($value)) {
            foreach ($value as $key => $item) {
                $headerName = strtolower(trim((string)$key));
                if ($headerName !== 'cookie' && $headerName !== 'cookies') {
                    continue;
                }
                $cookie = $this->normalizeCtripCookieHeaderText($item);
                if ($cookie !== '') {
                    return $cookie;
                }
            }
            return '';
        }
        if (!is_scalar($value)) {
            return '';
        }

        $raw = trim((string)$value);
        if ($raw === '') {
            return '';
        }

        $firstChar = $raw[0] ?? '';
        if ($firstChar === '{' || $firstChar === '[') {
            $decoded = json_decode($raw, true);
            if (is_array($decoded)) {
                $cookie = $this->normalizeCtripCookieHeaderText($decoded);
                if ($cookie !== '') {
                    return $cookie;
                }
            }
        }

        $raw = str_replace(["\r\n", "\r"], "\n", $raw);
        if (preg_match('/(?:^|\n)\s*cookie\s*:\s*([^\n]+)/i', $raw, $matches) === 1) {
            return $this->cleanCtripCookieHeaderCandidate((string)$matches[1]);
        }
        if (preg_match('/(?:^|\s)-H\s+(["\'])Cookie:\s*([^"\']+)\1/i', $raw, $matches) === 1) {
            return $this->cleanCtripCookieHeaderCandidate((string)$matches[2]);
        }
        if (str_contains($raw, "\n")) {
            return '';
        }

        $raw = trim($raw, " \t\n\r\0\x0B\"'");
        if (stripos($raw, 'cookie:') === 0) {
            $raw = trim(substr($raw, strlen('cookie:')));
        }
        if (stripos($raw, 'curl ') === 0) {
            return '';
        }

        return $this->cleanCtripCookieHeaderCandidate($raw);
    }

    private function cleanCtripCookieHeaderCandidate(string $candidate): string
    {
        $candidate = trim($candidate, " \t\n\r\0\x0B\"'");
        if ($candidate === '' || !str_contains($candidate, '=')) {
            return '';
        }
        return preg_replace('/\s*;\s*/', '; ', $candidate) ?? $candidate;
    }

    private function redactCtripEndpointEvidenceValue(mixed $value, string $key = ''): mixed
    {
        if ($this->isSensitiveCtripEndpointEvidenceKey($key)) {
            return '[REDACTED]';
        }
        if (is_array($value)) {
            $redacted = [];
            foreach ($value as $childKey => $childValue) {
                $redacted[$childKey] = $this->redactCtripEndpointEvidenceValue($childValue, (string)$childKey);
            }
            return $redacted;
        }
        if (is_string($value)) {
            if (preg_match('/1[3-9]\d{9}/', $value)) {
                return '[REDACTED]';
            }
            return mb_strlen($value) > 1000 ? mb_substr($value, 0, 1000) . '...' : $value;
        }
        return $value;
    }

    private function isSensitiveCtripEndpointEvidenceKey(string $key): bool
    {
        $normalized = strtolower(preg_replace('/[^a-z0-9]/i', '', $key) ?: '');
        if ($normalized === '') {
            return false;
        }
        foreach ([
            'cookie',
            'authorization',
            'token',
            'spidertoken',
            'usertoken',
            'usersign',
            'password',
            'passwd',
            'sign',
            'signature',
            'randomkey',
            'cticket',
            'guestname',
            'customername',
            'passengername',
            'guestphone',
            'mobile',
            'phone',
            'tel',
            'idcard',
            'credential',
            'certno',
            'orderid',
            'orderno',
            'ordercode',
        ] as $needle) {
            if (str_contains($normalized, $needle)) {
                return true;
            }
        }
        return false;
    }

    private function readLocalJsonFile(string $path): array
    {
        if (!is_file($path)) {
            throw new \InvalidArgumentException('JSON文件不存在: ' . $path);
        }
        $data = json_decode((string)file_get_contents($path), true);
        if (!is_array($data)) {
            throw new \InvalidArgumentException('JSON文件无法解析: ' . $path);
        }
        return $data;
    }

    private function buildCtripProfileCaptureConfigOptions(array $source, array $original = []): array
    {
        $sectionValue = $this->firstPresentCtripConfigValue(
            $source,
            ['profile_sections', 'capture_sections', 'captureSections'],
            $this->firstPresentCtripConfigValue($original, ['profile_sections', 'capture_sections', 'captureSections'], 'default')
        );
        $sections = $this->normalizeCtripProfileCaptureSections($sectionValue);
        $mappingPath = $this->firstPresentCtripConfigValue(
            $source,
            ['approved_mappings_path', 'approved_mapping_path', 'p3_mappings_path', 'approvedMappingsPath', 'approvedMappingPath', 'p3MappingsPath'],
            $this->firstPresentCtripConfigValue(
                $original,
                ['approved_mappings_path', 'approved_mapping_path', 'p3_mappings_path', 'approvedMappingsPath', 'approvedMappingPath', 'p3MappingsPath'],
                ''
            )
        );

        return [
            'capture_sections' => $sections,
            'profile_sections' => $sections,
            'approved_mappings_path' => trim(str_replace("\0", '', is_scalar($mappingPath) ? (string)$mappingPath : '')),
        ];
    }

    private function firstPresentCtripConfigValue(array $source, array $keys, mixed $default = ''): mixed
    {
        foreach ($keys as $key) {
            if (array_key_exists($key, $source)) {
                return $source[$key];
            }
        }
        return $default;
    }

    private function normalizeCtripProfileCaptureSections(mixed $value): string
    {
        $raw = is_array($value)
            ? implode(',', array_map(static fn($item): string => (string)$item, $value))
            : (string)$value;
        $items = preg_split('/[,\s]+/', strtolower($raw)) ?: [];
        $sections = [];
        foreach ($items as $item) {
            $item = trim($item);
            if ($item === '' || !preg_match('/^[a-z][a-z0-9_-]*$/', $item)) {
                continue;
            }
            $sections[$item] = true;
        }

        return implode(',', array_keys($sections)) ?: 'core';
    }

    private function normalizeProfileCaptureSections(mixed $value, string $fallback): string
    {
        $raw = is_array($value)
            ? implode(',', array_map(static fn($item): string => (string)$item, $value))
            : (string)$value;
        $raw = preg_replace('/[^a-zA-Z,_\-\s]+/', '', $raw) ?: '';
        $items = preg_split('/[,\s]+/', strtolower($raw)) ?: [];
        $sections = [];
        foreach ($items as $item) {
            $item = trim($item);
            if ($item === '') {
                continue;
            }
            $sections[$item] = true;
        }

        return implode(',', array_keys($sections)) ?: $fallback;
    }

    private function resolveCtripApprovedMappingsPath(array $source, string $projectRoot): array
    {
        $rawPath = '';
        foreach ([
            'approved_mappings_path',
            'approved_mapping_path',
            'p3_mappings_path',
            'approvedMappingsPath',
            'approvedMappingPath',
            'p3MappingsPath',
        ] as $key) {
            if (!array_key_exists($key, $source)) {
                continue;
            }
            $value = $source[$key];
            if (is_scalar($value)) {
                $rawPath = trim(str_replace("\0", '', (string)$value));
                if ($rawPath !== '') {
                    break;
                }
            }
        }

        if ($rawPath === '') {
            return ['configured' => false, 'path' => '', 'error' => ''];
        }

        if (preg_match('/^[a-z][a-z0-9+.-]*:\/\//i', $rawPath) === 1) {
            return ['configured' => true, 'path' => '', 'error' => '携程 approved mapping 仅支持项目目录内的本地 JSON 文件'];
        }

        $root = realpath($projectRoot);
        if ($root === false || !is_dir($root)) {
            return ['configured' => true, 'path' => '', 'error' => '项目目录不可用，无法加载携程 approved mapping'];
        }

        $candidate = $this->isAbsoluteLocalPath($rawPath)
            ? $rawPath
            : $root . DIRECTORY_SEPARATOR . ltrim($rawPath, "\\/");
        $rootComparable = $this->normalizeLocalPathForComparison($root);
        $candidateComparable = $this->normalizeLocalPathForComparison($candidate);
        if (
            preg_match('/(^|[\\\\\/])\.\.([\\\\\/]|$)/', $rawPath) === 1
            || ($this->isAbsoluteLocalPath($rawPath)
                && $candidateComparable !== $rootComparable
                && !str_starts_with($candidateComparable, $rootComparable . '/'))
        ) {
            return ['configured' => true, 'path' => '', 'error' => '携程 approved mapping 必须位于项目目录内'];
        }

        $resolved = realpath($candidate);
        if ($resolved === false || !is_file($resolved)) {
            return ['configured' => true, 'path' => '', 'error' => '携程 approved mapping 文件不存在'];
        }

        $resolvedComparable = $this->normalizeLocalPathForComparison($resolved);
        if ($resolvedComparable !== $rootComparable && !str_starts_with($resolvedComparable, $rootComparable . '/')) {
            return ['configured' => true, 'path' => '', 'error' => '携程 approved mapping 必须位于项目目录内'];
        }

        if (strtolower(pathinfo($resolved, PATHINFO_EXTENSION)) !== 'json') {
            return ['configured' => true, 'path' => '', 'error' => '携程 approved mapping 必须是 JSON 文件'];
        }

        if (!is_readable($resolved)) {
            return ['configured' => true, 'path' => '', 'error' => '携程 approved mapping 文件不可读取'];
        }

        return ['configured' => true, 'path' => $resolved, 'error' => ''];
    }

    private function isAbsoluteLocalPath(string $path): bool
    {
        return preg_match('/^[A-Za-z]:[\\\\\/]/', $path) === 1
            || str_starts_with($path, '\\\\')
            || str_starts_with($path, '//')
            || str_starts_with($path, '/');
    }

    private function normalizeLocalPathForComparison(string $path): string
    {
        return strtolower(rtrim(str_replace('\\', '/', $path), '/'));
    }

    private function safeMeituanCaptureFilePart(string $value): string
    {
        $safe = preg_replace('/[^a-zA-Z0-9_-]+/', '_', $value) ?: 'default';
        return substr($safe, 0, 80);
    }

    private function createAutoFetchCookieFile(string $projectRoot, string $platform, int $hotelId, string $cookies): string
    {
        $cookies = trim($cookies);
        if ($cookies === '') {
            return '';
        }

        $dir = $projectRoot . DIRECTORY_SEPARATOR . 'runtime' . DIRECTORY_SEPARATOR . 'ota_cookie_injection';
        if (!is_dir($dir) && !mkdir($dir, 0775, true) && !is_dir($dir)) {
            return '';
        }

        try {
            $suffix = bin2hex(random_bytes(6));
        } catch (\Throwable $e) {
            $suffix = str_replace('.', '', uniqid('', true));
        }

        $path = $dir . DIRECTORY_SEPARATOR . $this->safeMeituanCaptureFilePart($platform . '_' . $hotelId . '_' . $suffix) . '.txt';
        return file_put_contents($path, $cookies, LOCK_EX) === false ? '' : $path;
    }

    private function removeAutoFetchCookieFile(string $path): void
    {
        if ($path !== '' && is_file($path)) {
            @unlink($path);
        }
    }

    private function createCtripProfileFieldConfigFile(string $projectRoot, ?array $payload = null): string
    {
        $dir = $projectRoot . DIRECTORY_SEPARATOR . 'runtime' . DIRECTORY_SEPARATOR . 'ctrip_capture';
        if (!is_dir($dir) && !mkdir($dir, 0775, true) && !is_dir($dir)) {
            return '';
        }

        try {
            $suffix = bin2hex(random_bytes(6));
        } catch (\Throwable $e) {
            $suffix = str_replace('.', '', uniqid('', true));
        }

        $payload = $payload ?? $this->buildCtripProfileFieldConfigPayload($this->readCtripProfileCaptureFields(true));
        $json = json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
        if (!is_string($json)) {
            return '';
        }

        $path = $dir . DIRECTORY_SEPARATOR . 'ctrip_profile_field_config_' . $suffix . '.json';
        return file_put_contents($path, $json, LOCK_EX) === false ? '' : $path;
    }

    private function buildCtripProfileFieldConfigPayload(array $fields): array
    {
        $activeFields = [];
        $allowedKeys = [];
        $allowedSections = [];
        $moduleMap = $this->activeCtripProfileCaptureModuleMap();
        foreach ($fields as $field) {
            if (!is_array($field) || $this->isCtripProfileCaptureFieldDeleted($field) || empty($field['enabled'])) {
                continue;
            }
            $section = (string)($field['section'] ?? '');
            if ($section === '' || !isset($moduleMap[$section])) {
                continue;
            }
            $fieldKey = strtolower(trim((string)($field['field_key'] ?? '')));
            if ($fieldKey === '') {
                continue;
            }
            $allowedKeys[$fieldKey] = true;
            $allowedSections[$section] = true;
            $activeFields[] = [
                'id' => (string)($field['id'] ?? ''),
                'field_key' => $fieldKey,
                'field_name' => (string)($field['field_name'] ?? ''),
                'section' => $section,
                'data_type' => (string)($field['data_type'] ?? ''),
                'source_interface' => (string)($field['source_interface'] ?? ''),
                'source_keys' => (string)($field['source_keys'] ?? ''),
                'status' => (string)($field['status'] ?? ''),
            ];
        }

        return [
            'version' => self::CTRIP_PROFILE_FIELDS_CONFIG_VERSION,
            'source' => self::CTRIP_PROFILE_FIELDS_CONFIG_KEY,
            'generated_at' => date('Y-m-d H:i:s'),
            'allowed_sections' => array_keys($allowedSections),
            'allowed_field_keys' => array_keys($allowedKeys),
            'fields' => $activeFields,
        ];
    }

    private function resolveCtripProfileCaptureSectionsForRun(array $requestData, array $fieldConfigPayload, bool $loginOnly = false): array
    {
        $allowedSections = array_values(array_unique(array_filter(array_map(
            static fn($item): string => strtolower(trim((string)$item)),
            is_array($fieldConfigPayload['allowed_sections'] ?? null) ? $fieldConfigPayload['allowed_sections'] : []
        ), static fn(string $item): bool => $item !== '')));
        if (empty($allowedSections)) {
            return $loginOnly ? ['business_overview'] : [];
        }

        $sectionValue = $requestData['sections'] ?? $requestData['capture_sections'] ?? $requestData['captureSections'] ?? 'default';
        $requestedRaw = $this->normalizeProfileCaptureSections($sectionValue, 'default');
        $presetTokens = ['default' => true, 'core' => true, 'wide' => true, 'all' => true];
        $tokens = array_values(array_unique(array_filter(
            array_map(static fn($item): string => strtolower(trim((string)$item)), explode(',', $requestedRaw)),
            static fn(string $item): bool => $item !== ''
        )));
        if (empty($tokens) || (count($tokens) === 1 && isset($presetTokens[$tokens[0]]))) {
            return $this->filterAllowedCtripProfilePresetSections($tokens[0] ?? 'default', $allowedSections);
        }

        $aliases = [
            'business' => 'business_overview',
            'overview' => 'business_overview',
            'outline' => 'business_overview',
            'weekly' => 'business_weekly_overview',
            'week' => 'business_weekly_overview',
            'sales' => 'sales_report',
            'sale' => 'sales_report',
            'traffic' => 'traffic_report',
            'flow' => 'traffic_report',
            'rank' => 'competitor_rank',
            'ranking' => 'competitor_rank',
            'ads' => 'ads_pyramid',
            'ad' => 'ads_pyramid',
            'psi' => 'quality_psi',
            'quality' => 'quality_psi',
            'comment' => 'comment_review',
            'comments' => 'comment_review',
            'review' => 'comment_review',
            'reviews' => 'comment_review',
            'market' => 'market_calendar',
            'user' => 'user_profile',
            'profile' => 'user_profile',
        ];
        $allowedMap = array_fill_keys($allowedSections, true);
        $selected = [];
        foreach ($tokens as $token) {
            $section = $aliases[$token] ?? $token;
            if (isset($allowedMap[$section]) && !in_array($section, $selected, true)) {
                $selected[] = $section;
            }
        }

        return $selected;
    }

    /**
     * @param array<int, string> $allowedSections
     * @return array<int, string>
     */
    private function filterAllowedCtripProfilePresetSections(string $preset, array $allowedSections): array
    {
        $presetSections = match ($preset) {
            'all', 'wide' => $allowedSections,
            'core' => ['homepage', 'business_overview', 'business_weekly_overview', 'sales_report', 'traffic_report'],
            default => ['business_overview', 'business_weekly_overview', 'traffic_report'],
        };
        $allowedMap = array_fill_keys($allowedSections, true);
        $selected = array_values(array_filter(
            $presetSections,
            static fn(string $section): bool => isset($allowedMap[$section])
        ));
        return $selected !== [] ? $selected : $allowedSections;
    }

    private function trimMeituanCaptureLog(string $value): string
    {
        $value = trim($value);
        if (mb_strlen($value) <= 2000) {
            return $value;
        }
        return mb_substr($value, -2000);
    }

    private function buildMeituanCapturedDailyRows(array $payload, ?int $systemHotelId = null): array
    {
        $context = $this->buildMeituanCaptureContext($payload, $systemHotelId);
        $rows = [];

        foreach ($this->extractMeituanCapturedSection($payload, 'traffic') as $item) {
            $row = $this->normalizeMeituanCapturedTrafficRow($item, $context);
            if ($row !== null) {
                $rows[] = $row;
            }
        }

        foreach ($this->extractMeituanCapturedSection($payload, 'ads') as $item) {
            $row = $this->normalizeMeituanCapturedAdsRow($item, $context);
            if ($row !== null) {
                $rows[] = $row;
            }
        }

        foreach ($this->extractMeituanCapturedSection($payload, 'orders') as $item) {
            $row = $this->normalizeMeituanCapturedOrderRow($item, $context);
            if ($row !== null) {
                $rows[] = $row;
            }
        }

        return $rows;
    }

    private function buildMeituanCaptureContext(array $payload, ?int $systemHotelId): array
    {
        return [
            'system_hotel_id' => $systemHotelId,
            'store_id' => (string)$this->firstMeituanValue($payload, ['store_id', 'storeId'], ''),
            'poi_id' => (string)$this->firstMeituanValue($payload, ['poi_id', 'poiId', 'hotel_id', 'hotelId'], ''),
            'poi_name' => (string)$this->firstMeituanValue($payload, ['poi_name', 'poiName', 'hotel_name', 'hotelName', 'store_name', 'storeName'], ''),
            'captured_at' => (string)$this->firstMeituanValue($payload, ['captured_at', 'capturedAt', 'scraped_at', 'scrapedAt'], date('Y-m-d H:i:s')),
            'default_data_date' => (string)$this->firstMeituanValue($payload, ['default_data_date', 'defaultDataDate', 'data_date', 'dataDate'], date('Y-m-d')),
            'data_period' => (string)$this->firstMeituanValue($payload, ['data_period', 'dataPeriod'], ''),
            'snapshot_time' => (string)$this->firstMeituanValue($payload, ['snapshot_time', 'snapshotTime'], ''),
        ];
    }

    private function extractMeituanCapturedSection(array $payload, string $section): array
    {
        $rows = [];
        foreach ($this->meituanCapturedSectionAliases($section) as $key) {
            if (array_key_exists($key, $payload)) {
                $rows = array_merge($rows, $this->normalizeMeituanCapturedList($payload[$key], $section));
            }
        }

        if (isset($payload['responses']) && is_array($payload['responses'])) {
            foreach ($payload['responses'] as $response) {
                if (!is_array($response) || !$this->meituanCaptureResponseMatchesSection($response, $section)) {
                    continue;
                }
                $data = $response['data'] ?? $response['body'] ?? $response['json'] ?? [];
                $rows = array_merge($rows, $this->normalizeMeituanCapturedList($data, $section));
            }
        }

        return $rows;
    }

    private function meituanCapturedSectionAliases(string $section): array
    {
        return match ($section) {
            'reviews' => ['reviews', 'review', 'comments', 'commentList', 'commentsInfo'],
            'traffic' => ['traffic', 'businessData', 'business_data', 'weightTraffic', 'weight_traffic', 'peerTrends', 'peer_trends'],
            'ads' => ['ads', 'advertising', 'adData', 'cureShops', 'cure_shops'],
            'orders' => ['orders', 'orderList', 'order_list'],
            default => [$section],
        };
    }

    private function meituanCaptureResponseMatchesSection(array $response, string $section): bool
    {
        $type = strtolower((string)($response['type'] ?? $response['section'] ?? ''));
        if ($type !== '' && in_array($type, $this->meituanCapturedSectionAliases($section), true)) {
            return true;
        }

        $url = strtolower((string)($response['url'] ?? ''));
        if ($url === '') {
            return false;
        }

        $needles = match ($section) {
            'reviews' => ['querygeneralcommentinfo', 'commentsinfo', 'comments/statistics'],
            'traffic' => ['businessdata', 'weighttraffic', 'traffic', 'peertrends'],
            'ads' => ['cureshops'],
            'orders' => ['/orders/list', '/order/unhandled/count'],
            default => [],
        };

        foreach ($needles as $needle) {
            if (str_contains($url, $needle)) {
                return true;
            }
        }
        return false;
    }

    private function normalizeMeituanCapturedList($value, string $section): array
    {
        if (!is_array($value)) {
            return [];
        }

        if ($this->isSequentialArray($value)) {
            return array_values(array_filter($value, static fn($item): bool => is_array($item)));
        }

        foreach ($this->meituanCapturedListPaths($section) as $path) {
            $nested = $this->readNestedMeituanValue($value, $path);
            if (is_array($nested)) {
                $list = $this->normalizeMeituanCapturedList($nested, $section);
                if (!empty($list)) {
                    return $list;
                }
            }
        }

        return $this->looksLikeMeituanCapturedRow($value, $section) ? [$value] : [];
    }

    private function meituanCapturedListPaths(string $section): array
    {
        return match ($section) {
            'reviews' => [
                ['data', 'commentList'],
                ['data', 'comments'],
                ['data', 'list'],
                ['commentList'],
                ['comments'],
                ['list'],
                ['data'],
            ],
            'traffic' => [
                ['data', 'businessData'],
                ['data', 'weightTraffic'],
                ['data', 'weight_traffic'],
                ['data', 'traffic'],
                ['data', 'peerTrends'],
                ['data', 'list'],
                ['data', 'rows'],
                ['businessData'],
                ['weightTraffic'],
                ['weight_traffic'],
                ['traffic'],
                ['peerTrends'],
                ['list'],
                ['rows'],
                ['data'],
            ],
            'ads' => [
                ['data', 'cureShops'],
                ['data', 'list'],
                ['data', 'rows'],
                ['cureShops'],
                ['list'],
                ['rows'],
                ['data'],
            ],
            'orders' => [
                ['data', 'orders'],
                ['data', 'list'],
                ['data', 'orderList'],
                ['orders'],
                ['orderList'],
                ['list'],
                ['data'],
            ],
            default => [['data'], ['list']],
        };
    }

    private function looksLikeMeituanCapturedRow(array $value, string $section): bool
    {
        $keys = match ($section) {
            'reviews' => ['review_id', 'reviewId', 'commentId', 'comment', 'content', 'commentContent'],
            'traffic' => ['exposure_count', 'exposureCount', 'page_views', 'pageViews', 'unique_visitors', 'businessData', 'weightTraffic'],
            'ads' => ['cureShops', 'exposure_count', 'click_count', 'adId', 'campaignId'],
            'orders' => ['order_id', 'orderId', 'orderStatus', 'order_status', 'total_amount', 'totalAmount'],
            default => [],
        };
        foreach ($keys as $key) {
            if (array_key_exists($key, $value)) {
                return true;
            }
        }
        return false;
    }

    private function normalizeMeituanCapturedReviewRow(array $item, array $context): ?array
    {
        $reviewId = (string)$this->firstMeituanValue($item, ['review_id', 'reviewId', 'comment_id', 'commentId', 'id', 'orderId'], '');
        $content = (string)$this->firstMeituanValue($item, ['content', 'comment', 'commentContent', 'review_content'], '');
        $reply = (string)$this->firstMeituanValue($item, ['reply', 'bizReply', 'merchantReply', 'replyContent'], '');
        if ($reviewId === '' && $content === '' && $reply === '') {
            return null;
        }

        $score = $this->normalizeMeituanScore($this->firstMeituanValue($item, ['score', 'star', 'rating', 'totalScore'], 0));
        $dataDate = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['review_time', 'reviewTime', 'commentTime', 'createTime', 'stay_date', 'stayDate'], ''))
            ?: ($context['default_data_date'] ?? date('Y-m-d'));
        $isNegative = $this->meituanBool($this->firstMeituanValue($item, ['is_negative', 'isNegative', 'badComment'], false))
            || ($score > 0 && $score < 3.0);
        $identity = $reviewId !== '' ? $reviewId : substr(md5(json_encode($item, JSON_UNESCAPED_UNICODE)), 0, 12);

        return $this->baseMeituanCapturedRow($item, $context, [
            'data_date' => $dataDate,
            'amount' => 0,
            'quantity' => 1,
            'book_order_num' => 0,
            'comment_score' => $score,
            'data_value' => $score,
            'data_type' => 'review',
            'dimension' => 'review:' . ($isNegative ? 'negative' : 'normal') . ':' . $identity,
        ]);
    }

    private function normalizeMeituanCapturedTrafficRow(array $item, array $context): ?array
    {
        $exposure = (int)$this->meituanNumber($item, ['exposure_count', 'exposureCount', 'listExposure', 'impression', 'impressions', 'exposure'], 0);
        $pageViews = (int)$this->meituanNumber($item, ['page_views', 'pageViews', 'detailExposure', 'detailVisitors', 'unique_visitors', 'uniqueVisitors', 'visitor_count', 'visitorCount', 'uv', 'UV', 'pv', 'views'], 0);
        $clicks = (int)$this->meituanNumber($item, ['click_count', 'clickCount', 'clickNum', 'clicks', 'click'], 0);
        $conversion = $this->normalizeMeituanPercentValue($this->firstMeituanValue($item, ['conversion_rate', 'conversionRate', 'flowRate', 'orderRate'], null));
        if ($conversion === null) {
            $conversion = $this->trafficRate((float)($pageViews ?: $clicks), (float)$exposure);
        }

        if ($exposure <= 0 && $pageViews <= 0 && $clicks <= 0) {
            return null;
        }

        $dataDate = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['data_date', 'dataDate', 'date', 'statDate', 'stat_date'], ''))
            ?: ($context['default_data_date'] ?? date('Y-m-d'));

        return $this->baseMeituanCapturedRow($item, $context, [
            'data_date' => $dataDate,
            'amount' => 0,
            'quantity' => 0,
            'book_order_num' => 0,
            'comment_score' => 0,
            'data_value' => $exposure,
            'data_type' => 'traffic',
            'dimension' => 'traffic',
            'platform' => 'Meituan',
            'compare_type' => 'self',
            'list_exposure' => $exposure,
            'detail_exposure' => $pageViews ?: $clicks,
            'flow_rate' => round($conversion, 2),
            'order_filling_num' => $clicks,
            'order_submit_num' => (int)$this->meituanNumber($item, ['order_submit_num', 'orderSubmitNum', 'submit_users', 'submitUsers'], 0),
        ]);
    }

    private function normalizeMeituanCapturedAdsRow(array $item, array $context): ?array
    {
        $exposure = (int)$this->meituanNumber($item, ['exposure_count', 'exposureCount', 'impression', 'impressions', 'exposure'], 0);
        $clicks = (int)$this->meituanNumber($item, ['click_count', 'clickCount', 'clickNum', 'clicks', 'click'], 0);
        $conversion = $this->normalizeMeituanPercentValue($this->firstMeituanValue($item, ['conversion_rate', 'conversionRate', 'flowRate', 'orderRate'], null));
        if ($conversion === null) {
            $conversion = $this->trafficRate((float)$clicks, (float)$exposure);
        }

        if ($exposure <= 0 && $clicks <= 0) {
            return null;
        }

        $dataDate = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['data_date', 'dataDate', 'date', 'statDate', 'stat_date'], ''))
            ?: ($context['default_data_date'] ?? date('Y-m-d'));

        return $this->baseMeituanCapturedRow($item, $context, [
            'data_date' => $dataDate,
            'amount' => 0,
            'quantity' => 0,
            'book_order_num' => 0,
            'comment_score' => 0,
            'data_value' => $exposure,
            'data_type' => 'advertising',
            'dimension' => 'ads',
            'platform' => 'Meituan',
            'compare_type' => 'self',
            'list_exposure' => $exposure,
            'detail_exposure' => $clicks,
            'flow_rate' => round($conversion, 2),
            'order_filling_num' => $clicks,
            'order_submit_num' => 0,
        ]);
    }

    private function normalizeMeituanCapturedOrderRow(array $item, array $context): ?array
    {
        $orderId = (string)$this->firstMeituanValue($item, ['order_id', 'orderId', 'id'], '');
        $status = (string)$this->firstMeituanValue($item, ['order_status', 'orderStatus', 'status'], 'unknown');
        $amount = $this->meituanNumber($item, ['total_amount', 'totalAmount', 'amount', 'payAmount', 'pay_amount'], 0.0);
        $roomCount = (int)$this->meituanNumber($item, ['room_count', 'roomCount', 'rooms'], 1.0);
        $nights = (int)$this->meituanNumber($item, ['nights', 'night_count', 'nightCount'], 0.0);
        if ($nights <= 0) {
            $nights = $this->calculateMeituanOrderNights($item);
        }
        $roomCount = max(1, $roomCount);
        $nights = max(1, $nights);

        if ($orderId === '' && $amount <= 0) {
            return null;
        }

        $dataDate = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['order_time', 'orderTime', 'createTime', 'check_in_date', 'checkInDate'], ''))
            ?: ($context['default_data_date'] ?? date('Y-m-d'));
        $identity = $orderId !== ''
            ? $this->hashOnlineOrderIdentifier($orderId)
            : hash('sha256', 'ota_order_fallback|' . json_encode($item, JSON_UNESCAPED_UNICODE | JSON_INVALID_UTF8_SUBSTITUTE));

        return $this->baseMeituanCapturedRow($item, $context, [
            'data_date' => $dataDate,
            'amount' => round($amount, 2),
            'quantity' => $roomCount * $nights,
            'book_order_num' => (int)$this->meituanNumber($item, ['order_count', 'orderCount'], 1.0),
            'comment_score' => 0,
            'data_value' => $this->meituanNumber($item, ['avg_price', 'avgPrice'], $amount > 0 ? round($amount / ($roomCount * $nights), 2) : 0.0),
            'data_type' => 'order',
            'dimension' => 'order:' . $status . ':' . $identity,
            'platform' => 'Meituan',
            'compare_type' => 'self',
        ]);
    }

    private function baseMeituanCapturedRow(array $item, array $context, array $fields): array
    {
        $hotelId = (string)$this->firstMeituanValue($item, ['poi_id', 'poiId', 'hotel_id', 'hotelId', 'shopId', 'shop_id'], $context['poi_id'] ?: $context['store_id']);
        $hotelName = (string)$this->firstMeituanValue($item, ['poi_name', 'poiName', 'hotel_name', 'hotelName', 'shopName', 'shop_name', 'name'], $context['poi_name']);
        $raw = $this->sanitizeOnlineOrderRawData($item, ($fields['data_type'] ?? '') === 'order');
        $raw['_capture_context'] = array_filter([
            'store_id' => $context['store_id'] ?? '',
            'poi_id' => $context['poi_id'] ?? '',
            'captured_at' => $context['captured_at'] ?? '',
        ], static fn($value): bool => $value !== null && $value !== '');

        return array_merge([
            'hotel_id' => $hotelId,
            'hotel_name' => $hotelName,
            'system_hotel_id' => $context['system_hotel_id'] ?? null,
            'source' => 'meituan',
            'qunar_comment_score' => 0,
            'raw_data' => json_encode($raw, JSON_UNESCAPED_UNICODE | JSON_INVALID_UTF8_SUBSTITUTE),
        ], array_filter([
            'data_period' => $context['data_period'] ?? '',
            'snapshot_time' => $context['snapshot_time'] ?? '',
        ], static fn($value): bool => $value !== null && $value !== ''), $fields);
    }

    /**
     * @param array<string, mixed> $raw
     * @return array<string, mixed>
     */
    private function sanitizeOnlineOrderRawData(array $raw, bool $orderContext = false): array
    {
        $sanitized = [];
        foreach ($raw as $key => $value) {
            $keyText = (string)$key;
            if ($this->isOnlineSensitiveConfigKey($keyText)) {
                continue;
            }

            $childOrderContext = $orderContext || $this->isOnlineOrderContainerKey($keyText);
            if (is_array($value)) {
                $sanitized[$key] = $this->sanitizeOnlineOrderRawData($value, $childOrderContext);
                continue;
            }

            if ($childOrderContext || $this->isOnlineOrderPiiKey($keyText)) {
                $this->appendRedactedOnlineOrderField($sanitized, $keyText, $value, $childOrderContext);
                continue;
            }

            $sanitized[$key] = $value;
        }
        return $sanitized;
    }

    /**
     * @param array<string|int, mixed> $target
     */
    private function appendRedactedOnlineOrderField(array &$target, string $key, mixed $value, bool $orderContext): void
    {
        if ($this->isOnlineOrderIdKey($key, $orderContext)) {
            $text = trim((string)$value);
            if ($text !== '') {
                $target[$this->redactedOnlineOrderFieldName($key, 'hash')] = $this->hashOnlineOrderIdentifier($text);
            }
            return;
        }
        if ($this->isOnlinePhoneKey($key)) {
            $masked = $this->maskOnlinePhone((string)$value);
            if ($masked !== '') {
                $target[$this->redactedOnlineOrderFieldName($key, 'masked')] = $masked;
            }
            return;
        }
        if ($this->isOnlineGuestNameKey($key, $orderContext)) {
            $masked = $this->maskOnlineName((string)$value);
            if ($masked !== '') {
                $target[$this->redactedOnlineOrderFieldName($key, 'masked')] = $masked;
            }
            return;
        }
        if ($this->isOnlineSensitiveOrderTextKey($key)) {
            return;
        }

        $target[$key] = $value;
    }

    private function isOnlineSensitiveConfigKey(string $key): bool
    {
        return preg_match('/cookie|token|authorization|mtgsig|password|secret|spidertoken|csrf|session/i', $key) === 1;
    }

    private function isOnlineOrderContainerKey(string $key): bool
    {
        return preg_match('/order[_-]?(list|rows|items|data|detail|details|info)|orders/i', $key) === 1;
    }

    private function isOnlineOrderPiiKey(string $key): bool
    {
        return $this->isOnlineOrderIdKey($key, false)
            || $this->isOnlinePhoneKey($key)
            || $this->isOnlineGuestNameKey($key, false)
            || $this->isOnlineSensitiveOrderTextKey($key);
    }

    private function isOnlineOrderIdKey(string $key, bool $orderContext): bool
    {
        if ($orderContext && preg_match('/^(id|sn)$/i', $key) === 1) {
            return true;
        }
        return preg_match('/^(order[_-]?(id|no|num|number|sn)|booking[_-]?(id|no|number))$/i', $key) === 1;
    }

    private function isOnlinePhoneKey(string $key): bool
    {
        return preg_match('/(phone|mobile|tel)$/i', $key) === 1;
    }

    private function isOnlineGuestNameKey(string $key, bool $orderContext): bool
    {
        if ($orderContext && preg_match('/^(name|full[_-]?name)$/i', $key) === 1) {
            return true;
        }
        return preg_match('/(guest|customer|contact|user|traveller|passenger)[_-]?name$/i', $key) === 1;
    }

    private function isOnlineSensitiveOrderTextKey(string $key): bool
    {
        return preg_match('/(certificate|credential|id[_-]?card|card[_-]?no|passport|remark|memo|note|address)/i', $key) === 1;
    }

    private function redactedOnlineOrderFieldName(string $key, string $suffix): string
    {
        if ($this->isOnlineOrderIdKey($key, true)) {
            return 'order_id_hash';
        }
        $name = preg_replace('/(?<!^)[A-Z]/', '_$0', $key) ?? $key;
        $name = strtolower((string)preg_replace('/[^a-zA-Z0-9]+/', '_', $name));
        $name = trim($name, '_');
        return ($name !== '' ? $name : 'field') . '_' . $suffix;
    }

    private function hashOnlineOrderIdentifier(string $value): string
    {
        return hash('sha256', 'ota_order|' . $value);
    }

    private function maskOnlinePhone(string $value): string
    {
        $digits = preg_replace('/\D+/', '', $value) ?? '';
        if ($digits === '') {
            return '';
        }
        if (strlen($digits) <= 4) {
            return str_repeat('*', strlen($digits));
        }
        return str_repeat('*', strlen($digits) - 4) . substr($digits, -4);
    }

    private function maskOnlineName(string $value): string
    {
        $value = trim($value);
        if ($value === '') {
            return '';
        }
        return mb_substr($value, 0, 1) . '***';
    }

    private function saveMeituanCapturedDailyRows(array $rows): int
    {
        $columns = $this->getOnlineDailyDataColumns();
        $savedCount = 0;
        $now = date('Y-m-d H:i:s');

        foreach ($rows as $row) {
            if (!is_array($row) || empty($row['data_date']) || empty($row['data_type'])) {
                continue;
            }
            $row = $this->applyOnlineDailyDataPeriodFields($row, $columns, $row);

            if (isset($columns['update_time'])) {
                $row['update_time'] = $now;
            }

            $query = Db::name('online_daily_data')
                ->where('source', 'meituan')
                ->where('data_type', (string)$row['data_type'])
                ->where('data_date', (string)$row['data_date'])
                ->where('dimension', (string)($row['dimension'] ?? ''));
            $this->applyOnlineDailyDataPeriodQuery($query, $row, $columns);

            if (!empty($row['hotel_id'])) {
                $query->where('hotel_id', (string)$row['hotel_id']);
            } else {
                $query->where('hotel_name', (string)($row['hotel_name'] ?? ''));
            }

            if (array_key_exists('system_hotel_id', $row) && $row['system_hotel_id'] !== null) {
                $query->where('system_hotel_id', (int)$row['system_hotel_id']);
            } else {
                $query->whereNull('system_hotel_id');
            }

            $exists = $query->find();
            if (!$exists && isset($columns['create_time'])) {
                $row['create_time'] = $now;
            }

            $data = array_intersect_key($this->applyOnlineDailyDataValidationFields($row, $columns), $columns);
            if ($exists) {
                Db::name('online_daily_data')->where('id', $exists['id'])->update($data);
            } else {
                Db::name('online_daily_data')->insert($data);
            }
            $savedCount++;
        }

        return $savedCount;
    }

    private function summarizeMeituanCapturedRows(array $rows): array
    {
        $counts = [];
        foreach ($rows as $row) {
            $type = (string)($row['data_type'] ?? 'unknown');
            $counts[$type] = ($counts[$type] ?? 0) + 1;
        }
        ksort($counts);
        return $counts;
    }

    private function firstMeituanValue(array $data, array $keys, $default = null)
    {
        foreach ($keys as $key) {
            if (array_key_exists($key, $data) && $data[$key] !== null && $data[$key] !== '') {
                return $data[$key];
            }
        }
        return $default;
    }

    private function meituanNumber(array $data, array $keys, float $default = 0.0): float
    {
        $value = $this->firstMeituanValue($data, $keys, null);
        if (is_string($value)) {
            $value = str_replace([',', '%', '￥', '¥', '元', ' '], '', trim($value));
        }
        return is_numeric($value) ? (float)$value : $default;
    }

    private function normalizeMeituanPercentValue($value): ?float
    {
        if ($value === null || $value === '') {
            return null;
        }
        if (is_string($value)) {
            $value = str_replace([',', '%'], '', trim($value));
        }
        if (!is_numeric($value)) {
            return null;
        }
        return round($this->normalizeTrafficPercent((float)$value), 2);
    }

    private function normalizeMeituanScore($value): float
    {
        if (is_string($value)) {
            $value = str_replace([',', '%'], '', trim($value));
        }
        if (!is_numeric($value)) {
            return 0.0;
        }
        $score = (float)$value;
        if ($score > 5 && $score <= 50) {
            return round($score / 10, 1);
        }
        if ($score > 50 && $score <= 100) {
            return round($score / 20, 1);
        }
        return round($score, 1);
    }

    private function calculateMeituanOrderNights(array $item): int
    {
        $checkIn = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['check_in_date', 'checkInDate'], ''));
        $checkOut = $this->normalizeOnlineDataDate($this->firstMeituanValue($item, ['check_out_date', 'checkOutDate'], ''));
        if ($checkIn === '' || $checkOut === '') {
            return 0;
        }
        $start = strtotime($checkIn);
        $end = strtotime($checkOut);
        if ($start === false || $end === false || $end <= $start) {
            return 0;
        }
        return (int)max(1, floor(($end - $start) / 86400));
    }

    private function readNestedMeituanValue(array $data, array $path)
    {
        $current = $data;
        foreach ($path as $key) {
            if (!is_array($current) || !array_key_exists($key, $current)) {
                return null;
            }
            $current = $current[$key];
        }
        return $current;
    }

    private function isSequentialArray(array $value): bool
    {
        if ($value === []) {
            return true;
        }
        return array_keys($value) === range(0, count($value) - 1);
    }

    private function meituanBool($value): bool
    {
        if (is_bool($value)) {
            return $value;
        }
        if (is_numeric($value)) {
            return (int)$value === 1;
        }
        return in_array(strtolower(trim((string)$value)), ['1', 'true', 'yes', 'y'], true);
    }

    /**
     * Parse and save Meituan comment API data.
     */
    private function parseAndSaveMeituanComments(array $comments, string $poiId, string $partnerId, ?int $systemHotelId = null): int
    {
        return 0;

        $savedCount = 0;
        $dataDate = date('Y-m-d');

        foreach ($comments as $comment) {
            try {
                $commentId = $comment['id'] ?? $comment['commentId'] ?? null;
                if (!$commentId) {
                    continue;
                }

                // 检查是否已存在相同的评论
                $existing = Db::name('online_daily_data')
                    ->where('source', 'meituan')
                    ->where('data_type', 'review')
                    ->where('raw_data', 'like', '%"' . $commentId . '"%')
                    ->first();

                if ($existing) {
                    continue;
                }

                // 提取评论内容（美团字段：comment）
                $content = $comment['comment'] ?? $comment['content'] ?? $comment['commentContent'] ?? '';

                // 美团评分是50分制：50=5星, 40=4星, 30=3星...
                $score = $comment['score'] ?? $comment['star'] ?? 0;
                $starRating = $score / 10; // 转换为星级（1-5）

                // 时间处理（美团返回毫秒时间戳）
                $commentTime = $comment['commentTime'] ?? $comment['createTime'] ?? null;
                if ($commentTime && is_numeric($commentTime)) {
                    $commentTime = date('Y-m-d H:i:s', $commentTime / 1000);
                } else {
                    $commentTime = $commentTime ?: null;
                }

                $userName = $comment['userName'] ?? $comment['nickName'] ?? '匿名用户';
                $hotelName = $comment['poiName'] ?? $comment['hotelName'] ?? '';
                $bizReply = $comment['bizReply'] ?? ''; // 商家回复
                $badComment = $comment['badComment'] ?? false; // 是否差评

                // 检查内容是否为空（如果评论为空但有商家回复也保存）
                if (empty($content) && empty($bizReply)) {
                    continue;
                }

                // 保存到数据库
                $insertData = [
                    'hotel_id' => $systemHotelId,
                    'hotel_name' => $hotelName,
                    'source' => 'meituan',
                    'data_type' => 'review',
                    'data_date' => $dataDate,
                    'amount' => 0,
                    'quantity' => 1,
                    'book_order_num' => 0,
                    'comment_score' => $starRating,
                    'qunar_comment_score' => 0,
                    'raw_data' => json_encode($comment, JSON_UNESCAPED_UNICODE),
                    'create_time' => date('Y-m-d H:i:s'),
                    'update_time' => date('Y-m-d H:i:s'),
                ];
                $insertData = $this->applyOnlineDailyDataValidationFields($insertData);

                $inserted = Db::name('online_daily_data')->insertGetId($insertData);
                if ($inserted) {
                    $savedCount++;
                }
            } catch (\Throwable $e) {
                // 记录错误但继续处理下一条
                error_log('保存美团评论失败: ' . $e->getMessage());
            }
        }

        return $savedCount;
    }

    /**
     * 确保字符串是有效的UTF-8编码
     */
    private function ensureUtf8String(?string $str): string
    {
        if (empty($str)) {
            return '';
        }

        // 方法1: 使用iconv移除无效字符
        if (function_exists('iconv')) {
            $converted = @iconv('UTF-8', 'UTF-8//IGNORE', $str);
            if ($converted !== false) {
                $str = $converted;
            }
        }

        // 方法2: 检测并转换编码
        $encoding = mb_detect_encoding($str, ['UTF-8', 'GBK', 'GB2312', 'BIG5', 'ISO-8859-1'], true);
        if ($encoding && $encoding !== 'UTF-8') {
            $str = mb_convert_encoding($str, 'UTF-8', $encoding);
        }

        // 方法3: 最后检查是否为有效UTF-8，如果无效则使用强制转换
        if (!mb_check_encoding($str, 'UTF-8')) {
            // 强制转换为UTF-8，忽略无效字符
            $str = utf8_encode($str);
        }

        // 移除控制字符（保留换行和制表符）
        $str = preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/u', '', $str);

        return $str;
    }

    /**
     * 递归确保数组中所有字符串都是UTF-8编码
     */
    private function ensureUtf8($data)
    {
        if (is_array($data)) {
            foreach ($data as $key => $value) {
                $data[$key] = $this->ensureUtf8($value);
            }
            return $data;
        } elseif (is_string($data)) {
            return $this->ensureUtf8String($data);
        }
        return $data;
    }

    /**
     * 发送美团HTTP请求
     */
    private function sendMeituanRequest(string $url, array $params, string $cookies, array $authData = []): array
    {
        if (!$this->isAllowedOtaRequestUrl($url, ['meituan.com'])) {
            return ['success' => false, 'error' => '仅允许请求美团官方域名'];
        }

        $fullUrl = $url;
        if (!empty($params)) {
            $fullUrl .= (strpos($url, '?') === false ? '?' : '&') . http_build_query($params);
        }

        // 基础请求头
        $headers = [
            'Cookie: ' . $cookies,
            'User-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
            'Accept: application/json, text/plain, */*',
            'Accept-Language: zh-CN,zh;q=0.9,en;q=0.8',
            'Referer: https://eb.meituan.com/',
            'Origin: https://eb.meituan.com',
        ];

        // 添加认证数据作为额外的请求头
        if (!empty($authData)) {
            if (!empty($authData['token'])) {
                $headers[] = 'Authorization: Bearer ' . $authData['token'];
            }
            if (!empty($authData['access_token'])) {
                $headers[] = 'access-token: ' . $authData['access_token'];
            }
            if (!empty($authData['auth_token'])) {
                $headers[] = 'auth-token: ' . $authData['auth_token'];
            }
            // 美团可能使用的其他认证header
            foreach ($authData as $key => $value) {
                if (strpos(strtolower($key), 'token') !== false && !in_array($key, ['token', 'access_token', 'auth_token'])) {
                    $headerKey = str_replace('_', '-', $key);
                    $headers[] = $headerKey . ': ' . $value;
                }
            }
        }

        // 使用file_get_contents替代curl（沙箱环境无curl扩展）
        $options = [
            'http' => [
                'method' => 'GET',
                'timeout' => 30,
                'header' => implode("\r\n", $headers),
            ],
            'ssl' => $this->buildStreamSslOptions(),
        ];

        $context = stream_context_create($options);
        $response = @file_get_contents($fullUrl, false, $context);

        if ($response === false) {
            $error = error_get_last();
            $errorMsg = is_array($error) ? ($error['message'] ?? '请求失败') : '请求失败';
            return ['success' => false, 'error' => $errorMsg];
        }

        // 解析HTTP响应头获取状态码
        $httpCode = 200;
        if (isset($http_response_header)) {
            foreach ($http_response_header as $header) {
                if (preg_match('/HTTP\/\d+\.?\d*\s+(\d+)/', $header, $matches)) {
                    $httpCode = (int)$matches[1];
                    break;
                }
            }
        }

        // 在JSON解析之前清理响应字符串中的无效UTF-8字符
        $response = $this->sanitizeJsonString($response);

        $data = json_decode($response, true);
        if (json_last_error() !== JSON_ERROR_NONE) {
            return ['success' => false, 'error' => 'JSON解析失败: ' . substr((string)$response, 0, 200)];
        }

        // 递归清理数据中的无效UTF-8字符
        $data = $this->ensureUtf8($data);

        // 检查美团API业务状态码
        // 美团API可能返回: { code: 0, msg: 'success' } 或 { status: 0, message: 'success' }
        $businessCode = $data['code'] ?? $data['status'] ?? null;
        $businessMsg = $data['msg'] ?? $data['message'] ?? $data['data']['msg'] ?? '';

        // 美团API成功状态码通常是0
        if ($businessCode !== null && $businessCode !== 0 && $businessCode !== '0') {
            return [
                'success' => false,
                'error' => '美团API返回错误: ' . ($businessMsg ?: "状态码: $businessCode"),
                'data' => $data,
                'raw' => $response,
                'http_code' => $httpCode,
            ];
        }

        return [
            'success' => true,
            'data' => $data,
            'raw' => $response,
            'http_code' => $httpCode,
        ];
    }

    private function normalizeMeituanManualDateRange(string $startDate, string $endDate): array
    {
        $start = $this->normalizeOnlineDataDate($startDate);
        $end = $this->normalizeOnlineDataDate($endDate);
        if ($start === '' && $end === '') {
            $start = date('Y-m-d', strtotime('-1 day'));
            $end = $start;
        } elseif ($start === '') {
            $start = $end;
        } elseif ($end === '') {
            $end = $start;
        }
        if (strtotime($start) === false || strtotime($end) === false || strtotime($start) > strtotime($end)) {
            throw new \InvalidArgumentException('日期范围无效');
        }
        return [$start, $end];
    }

    private function sendMeituanManualRequest(string $url, array $params, string $cookies, string $method, array $allowedHostSuffixes, string $section): array
    {
        $emptyResult = [
            'http_code' => 0,
            'raw_response' => '',
            'decoded_data' => null,
            'request_url' => $url,
            'error' => '',
        ];
        if (!$this->isAllowedOtaRequestUrl($url, $allowedHostSuffixes)) {
            return array_merge($emptyResult, ['error' => '仅允许请求美团/点评官方业务域名']);
        }

        $lowerUrl = strtolower($url);
        if ($section === 'orders' && str_contains($lowerUrl, '/order-eb/index.html')) {
            return array_merge($emptyResult, ['error' => '请填写 Network 中 /orders/list 等 JSON 接口 Request URL，不要填写订单页面 URL']);
        }
        if ($section === 'ads' && str_contains($lowerUrl, '/shopdiy/account/pccpcentry')) {
            return array_merge($emptyResult, ['error' => '请填写 Network 中 cureShops 等 JSON 接口 Request URL，不要填写推广通入口页面 URL']);
        }

        $method = strtoupper($method) === 'POST' ? 'POST' : 'GET';
        $requestUrl = $url;
        $content = '';
        if ($method === 'GET') {
            if (!empty($params)) {
                $requestUrl .= (str_contains($requestUrl, '?') ? '&' : '?') . http_build_query($params);
            }
        } else {
            $content = json_encode($params, JSON_UNESCAPED_UNICODE);
            if ($content === false) {
                return array_merge($emptyResult, ['error' => '请求 Body JSON 编码失败: ' . json_last_error_msg()]);
            }
        }

        $parts = parse_url($url);
        $host = strtolower((string)($parts['host'] ?? ''));
        $origin = str_contains($host, 'dianping.com') ? 'https://ebmidas.dianping.com' : 'https://eb.meituan.com';
        $referer = $section === 'ads'
            ? 'https://ebmidas.dianping.com/shopdiy/account/pcCpcEntry'
            : 'https://eb.meituan.com/';
        $headers = [
            'Cookie: ' . $cookies,
            'User-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
            'Accept: application/json, text/plain, */*',
            'Accept-Language: zh-CN,zh;q=0.9',
            'Origin: ' . $origin,
            'Referer: ' . $referer,
        ];
        if ($method === 'POST') {
            $headers[] = 'Content-Type: application/json;charset=UTF-8';
            $headers[] = 'Content-Length: ' . strlen($content);
        }

        $context = stream_context_create([
            'http' => [
                'method' => $method,
                'header' => implode("\r\n", $headers),
                'content' => $method === 'POST' ? $content : '',
                'timeout' => 30,
                'ignore_errors' => true,
            ],
            'ssl' => $this->buildStreamSslOptions(),
        ]);
        $rawResponse = @file_get_contents($requestUrl, false, $context);
        $httpCode = 0;
        if (isset($http_response_header)) {
            foreach ($http_response_header as $header) {
                if (preg_match('/HTTP\/\d+\.?\d*\s+(\d+)/', $header, $matches)) {
                    $httpCode = (int)$matches[1];
                    break;
                }
            }
        }

        $result = array_merge($emptyResult, [
            'http_code' => $httpCode,
            'request_url' => $requestUrl,
            'raw_response' => $rawResponse === false ? '' : (string)$rawResponse,
        ]);
        if ($rawResponse === false) {
            $error = error_get_last();
            $result['error'] = is_array($error) ? (string)($error['message'] ?? '请求失败') : '请求失败';
            return $result;
        }
        if ($httpCode > 0 && $httpCode !== 200) {
            $result['error'] = in_array($httpCode, [301, 302, 401, 403], true)
                ? 'Cookie 可能已失效或无权限，请重新登录美团后台后复制 Cookie'
                : '美团接口 HTTP 错误: ' . $httpCode;
            return $result;
        }
        if (preg_match('/^\s*<!DOCTYPE|^\s*<html/i', (string)$rawResponse)) {
            $result['error'] = '接口返回 HTML 页面，请填写 Network 中的 JSON 接口 Request URL';
            return $result;
        }

        $sanitizedResponse = $this->sanitizeJsonString((string)$rawResponse);
        $decodedData = json_decode($sanitizedResponse, true);
        if (json_last_error() !== JSON_ERROR_NONE || !is_array($decodedData)) {
            $result['error'] = 'JSON 解析失败: ' . json_last_error_msg();
            return $result;
        }
        $decodedData = $this->ensureUtf8($decodedData);
        $businessCode = $decodedData['code'] ?? $decodedData['status'] ?? null;
        $businessMsg = $decodedData['msg'] ?? $decodedData['message'] ?? $decodedData['data']['msg'] ?? '';
        if ($businessCode !== null && !in_array((string)$businessCode, ['0', '200', 'success', 'SUCCESS'], true)) {
            $result['decoded_data'] = $decodedData;
            $result['error'] = '美团接口返回错误: ' . ($businessMsg ?: ('状态码: ' . (string)$businessCode));
            return $result;
        }

        $result['decoded_data'] = $decodedData;
        return $result;
    }

    /**
     * 清理JSON字符串中的无效UTF-8字符
     */
    private function sanitizeJsonString(string $json): string
    {
        // 方法1: 使用iconv移除无效字符
        if (function_exists('iconv')) {
            $converted = @iconv('UTF-8', 'UTF-8//IGNORE', $json);
            if ($converted !== false) {
                $json = $converted;
            }
        }

        // 方法2: 使用正则表达式移除无效的UTF-8字节序列
        // 有效的UTF-8字节模式
        $json = preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/u', '', $json);

        // 方法3: 移除或替换无效的多字节序列
        // 使用mb_convert_encoding进行清理
        if (function_exists('mb_convert_encoding')) {
            // 检测编码
            $encoding = mb_detect_encoding($json, ['UTF-8', 'GBK', 'GB2312', 'BIG5', 'ISO-8859-1'], true);
            if ($encoding && $encoding !== 'UTF-8') {
                $json = mb_convert_encoding($json, 'UTF-8', $encoding);
            }
        }

        return $json;
    }

    /**
     * 解析并保存美团数据到数据库
     * 支持竞对排名数据（roundrank节点）
     */
    private function parseAndSaveMeituanData($responseData, $startDate, $endDate, ?int $systemHotelId = null, array $context = []): int
    {
        try {
            $dataList = [];

            if ($this->shouldLogOtaDebug()) {
                \think\facade\Log::info('美团数据解析 - 原始响应结构: ' . json_encode([
                    'keys' => array_keys($responseData),
                    'data_keys' => isset($responseData['data']) && is_array($responseData['data']) ? array_keys($responseData['data']) : 'not_array',
                    'data_type' => isset($responseData['data']) ? gettype($responseData['data']) : 'not_set',
                    'data_value_type' => isset($responseData['data']) ? gettype($responseData['data']) : 'not_set',
                ], JSON_UNESCAPED_UNICODE));
            }

            // 美团竞对排名数据结构解析
            // 实际结构: { data: { peerRankData: [{ dimName, roundRanks: [...], aiMetricName }] } }
            if (isset($responseData['data']['peerRankData']) && is_array($responseData['data']['peerRankData'])) {
                // 遍历每个榜单类型（入住间夜榜、交易额榜等）
                foreach ($responseData['data']['peerRankData'] as $rankData) {
                    if (isset($rankData['roundRanks']) && is_array($rankData['roundRanks'])) {
                        foreach ($rankData['roundRanks'] as $item) {
                            $item['_dimName'] = $rankData['dimName'] ?? '';
                            $item['_aiMetricName'] = $rankData['aiMetricName'] ?? '';
                            $dataList[] = $item;
                        }
                    }
                }
                \think\facade\Log::info('美团数据解析 - 使用结构: data.peerRankData[].roundRanks, 数量: ' . count($dataList));
            }
            // 结构2: { data: { roundrank: [...] } } - 竞对排名数据
            elseif (isset($responseData['data']['roundrank']) && is_array($responseData['data']['roundrank'])) {
                $dataList = $responseData['data']['roundrank'];
                \think\facade\Log::info('美团数据解析 - 使用结构2: data.roundrank, 数量: ' . count($dataList));
            }
            // 结构3: { data: { rankList: [...] } }
            elseif (isset($responseData['data']['rankList']) && is_array($responseData['data']['rankList'])) {
                $dataList = $responseData['data']['rankList'];
                \think\facade\Log::info('美团数据解析 - 使用结构3: data.rankList, 数量: ' . count($dataList));
            }
            // 结构4: { data: { list: [...] } }
            elseif (isset($responseData['data']['list']) && is_array($responseData['data']['list'])) {
                $dataList = $responseData['data']['list'];
                \think\facade\Log::info('美团数据解析 - 使用结构4: data.list, 数量: ' . count($dataList));
            }
            // 结构5: { data: [...] }
            elseif (isset($responseData['data']) && is_array($responseData['data'])) {
                if (isset($responseData['data'][0])) {
                    $dataList = $responseData['data'];
                    \think\facade\Log::info('美团数据解析 - 使用结构5: data是数组, 数量: ' . count($dataList));
                } else {
                    foreach ($responseData['data'] as $key => $value) {
                        if (is_array($value)) {
                            $dataList = array_merge($dataList, $value);
                        }
                    }
                    \think\facade\Log::info('美团数据解析 - 使用结构5展开: 数量: ' . count($dataList));
                }
            }
            // 结构6: { list: [...] }
            elseif (isset($responseData['list']) && is_array($responseData['list'])) {
                $dataList = $responseData['list'];
                \think\facade\Log::info('美团数据解析 - 使用结构6: list, 数量: ' . count($dataList));
            }
            // 结构7: { roundrank: [...] }
            elseif (isset($responseData['roundrank']) && is_array($responseData['roundrank'])) {
                $dataList = $responseData['roundrank'];
                \think\facade\Log::info('美团数据解析 - 使用结构7: roundrank, 数量: ' . count($dataList));
            }

            if (empty($dataList)) {
                // 无数据可解析，记录警告
                \think\facade\Log::warning('美团数据解析 - 未能解析到有效数据');
                return 0;
            }

            $savedCount = 0;
            $dataDate = $startDate ?: date('Y-m-d', strtotime('-1 day'));

            // 记录第一个数据项的字段结构
            if ($this->shouldLogOtaDebug() && !empty($dataList[0])) {
                \think\facade\Log::info('美团数据解析 - 首条数据字段: ' . json_encode(array_keys($dataList[0]), JSON_UNESCAPED_UNICODE));
                \think\facade\Log::info('美团数据解析 - 首条数据样例: ' . json_encode($dataList[0], JSON_UNESCAPED_UNICODE));
            }

            foreach ($dataList as $item) {
                if (!is_array($item)) continue;

                // 美团数据简化存储：只保存 poiName 和 dataValue
                $hotelId = $item['poiId'] ?? $item['poi_id'] ?? $item['shopId'] ?? $item['shop_id'] ?? $item['hotelId'] ?? null;
                if (empty($hotelId)) {
                    \think\facade\Log::warning('美团数据解析 - 跳过无酒店ID的数据: ' . json_encode($item, JSON_UNESCAPED_UNICODE));
                    continue;
                }

                $hotelName = $item['poiName'] ?? $item['poi_name'] ?? $item['shopName'] ?? $item['shop_name'] ?? $item['hotelName'] ?? $item['name'] ?? '';

                // 美团竞对排名数据：平台新版可能只返回 percent，不再返回 dataValue。
                $sourceDataValue = $this->nullableNumberFromKeys($item, ['dataValue', 'data_value', 'monthRoomNights', 'month_room_nights']);
                $rankPercent = $this->meituanRankPercentValue($item);
                $dataValue = $sourceDataValue ?? 0.0;
                $metricStatus = $sourceDataValue !== null
                    ? 'platform_value_returned'
                    : ($rankPercent !== null ? 'platform_percent_only' : 'platform_value_missing');

                $itemDate = $item['date'] ?? $item['dataDate'] ?? $item['statDate'] ?? $item['stat_date'] ?? $dataDate;
                $dimName = $item['_dimName'] ?? ($item['dimension'] ?? '');
                $aiMetricName = $item['_aiMetricName'] ?? ($item['aiMetricName'] ?? '');

                // 判断榜单类型：P_XS=销售榜(包含销售间夜榜+销售额榜), P_RZ=入住榜, P_ZH=转化榜, P_LL=流量榜
                $rankType = $item['rankType'] ?? $item['rank_type'] ?? '';
                $platformTagInfo = $this->extractMeituanPlatformTagInfo($item);
                $hasVipTag = $this->hasMeituanVipPlatformTag($platformTagInfo['tags']);
                $platformTagText = !empty($platformTagInfo['tags']) ? implode(' / ', $platformTagInfo['tags']) : '未返回';

                // 精确匹配子榜单类型 - 扩展关键词匹配
                // 结合dimName和aiMetricName进行判断，提高准确性
                $combinedName = $dimName . '|' . $aiMetricName;

                $isSalesAmountRank = strpos($combinedName, '销售额') !== false || strpos($combinedName, '交易额') !== false || strpos($combinedName, '房费收入') !== false || strpos($combinedName, '收入') !== false || strpos($combinedName, '金额') !== false;
                // 销售间夜榜：包含"间夜"但不包含"额"（避免与销售额混淆）
                // 同时检查aiMetricName，因为有些API返回的dimName可能是"销售榜"，而aiMetricName才是"销售间夜"
                $isRoomNightRank = (strpos($combinedName, '间夜') !== false && strpos($combinedName, '额') === false) || strpos($combinedName, '入住') !== false || strpos($combinedName, ' Nights') !== false || strpos($combinedName, 'nights') !== false || strpos($aiMetricName, '间夜') !== false;
                $isConversionRank = strpos($combinedName, '转化') !== false || strpos($combinedName, '支付') !== false || $rankType === 'P_ZH';
                $isTrafficRank = strpos($combinedName, '曝光') !== false || strpos($combinedName, '浏览') !== false || strpos($combinedName, '流量') !== false || strpos($combinedName, '访客') !== false || $rankType === 'P_LL';

                // 详细调试日志：记录每个数据项的判断过程
                \think\facade\Log::info("美团数据解析 - 详细判断: dimName=$dimName, rankType=$rankType, dataValue=$dataValue, percent=" . ($rankPercent ?? 'null') . ", metricStatus=$metricStatus, isSalesAmountRank=" . ($isSalesAmountRank ? 'true' : 'false') . ", isRoomNightRank=" . ($isRoomNightRank ? 'true' : 'false'));
                \think\facade\Log::info("美团数据解析 - 完整数据项: " . json_encode($item, JSON_UNESCAPED_UNICODE));

                // 根据榜单类型设置 amount 和 quantity
                if ($isRoomNightRank) {
                    // 间夜榜（销售间夜榜、入住间夜榜）：dataValue 是间夜数
                    $amount = 0;
                    $quantity = intval($dataValue);
                } elseif ($isSalesAmountRank) {
                    // 销售额榜（交易额榜、房费收入榜）：dataValue 是销售额（元）
                    $amount = $dataValue;
                    $quantity = 0;
                } elseif ($isConversionRank || $isTrafficRank) {
                    // 转化榜和流量榜：dataValue 可能是百分比或次数，保存到 data_value
                    $amount = 0;
                    $quantity = 0;
                } else {
                    // 无法识别的榜单类型：根据数值大小智能判断
                    if ($dataValue > 10000) {
                        // 数值较大，可能是销售额
                        $amount = $dataValue;
                        $quantity = 0;
                    } else {
                        // 数值较小，可能是间夜数
                        $amount = 0;
                        $quantity = intval($dataValue);
                    }
                }

                // 详细记录榜单类型判断结果
                \think\facade\Log::info("美团数据解析 - 榜单判断: dimName=$dimName, rankType=$rankType, isSalesAmountRank=" . ($isSalesAmountRank ? 'true' : 'false') . ", isRoomNightRank=" . ($isRoomNightRank ? 'true' : 'false') . ", isConversionRank=" . ($isConversionRank ? 'true' : 'false') . ", isTrafficRank=" . ($isTrafficRank ? 'true' : 'false'));
                \think\facade\Log::info("美团数据解析 - 保存数据: hotelName=$hotelName, dataValue=$dataValue, percent=" . ($rankPercent ?? 'null') . ", metricStatus=$metricStatus, amount=$amount, quantity=$quantity, dataDate=$itemDate, dimName=$dimName");

                // 检查是否已存在（按酒店名称、日期、来源、维度去重）
                $columns = $this->getOnlineDailyDataColumns();
                $periodFilter = $this->applyOnlineDailyDataPeriodFields([
                    'data_date' => $itemDate,
                    'source' => 'meituan',
                    'data_type' => 'business',
                    'dimension' => $dimName,
                ], $columns, $item);

                $query = Db::name('online_daily_data')
                    ->where('hotel_name', $hotelName)
                    ->where('data_date', $itemDate)
                    ->where('source', 'meituan')
                    ->where('dimension', $dimName);
                $this->applyOnlineDailyDataPeriodQuery($query, $periodFilter, $columns);

                if ($systemHotelId !== null) {
                    $query->where('system_hotel_id', $systemHotelId);
                }

                $exists = $query->find();

                // 保存数据：根据榜单类型设置 amount 或 quantity
                $data = [
                    'hotel_id' => (string)$hotelId,
                    'hotel_name' => $hotelName,
                    'system_hotel_id' => $systemHotelId,
                    'data_date' => $itemDate,
                    'data_value' => $dataValue,
                    'amount' => $amount,
                    'quantity' => $quantity,
                    'book_order_num' => 0,
                    'comment_score' => 0,
                    'qunar_comment_score' => 0,
                    'source' => 'meituan',
                    'dimension' => $dimName,
                    'data_type' => 'business',
                    'raw_data' => json_encode([
                        'poiName' => $hotelName,
                        'dataValue' => $sourceDataValue,
                        'percent' => $rankPercent,
                        'metricStatus' => $metricStatus,
                        'rankType' => $rankType,
                        'rank' => $item['rank'] ?? $item['ranking'] ?? null,
                        'dateRange' => $context['date_range'] ?? $item['dateRange'] ?? $item['date_range'] ?? '',
                        'startDate' => $context['start_date'] ?? $startDate,
                        'endDate' => $context['end_date'] ?? $endDate,
                        'dimension' => $dimName,
                        'aiMetricName' => $aiMetricName,
                        'platformTags' => $platformTagInfo['tags'],
                        'platformTagStatus' => $platformTagInfo['status'],
                        'platformTagText' => $platformTagText,
                        'hasVipTag' => $hasVipTag,
                        'sourceLabel' => $sourceDataValue !== null ? '美团榜单返回' : ($rankPercent !== null ? '美团仅返回百分比' : '美团榜单未返回数值'),
                    ], JSON_UNESCAPED_UNICODE),
                ];
                $data = $this->applyOnlineDailyDataValidationFields($data);

                if ($exists) {
                    Db::name('online_daily_data')
                        ->where('id', $exists['id'])
                        ->update($data);
                } else {
                    Db::name('online_daily_data')->insert($data);
                }
                $savedCount++;
            }

            return $savedCount;
        } catch (\Throwable $e) {
            return 0;
        }
    }

    /**
     * 解析并保存数据到数据库
     * @param int|null $systemHotelId 系统酒店ID，用于门店隔离
     */
    private function parseAndSaveData($responseData, $startDate, $endDate, ?int $systemHotelId = null): int
    {
        $dataList = $this->extractCtripBusinessDataList($responseData);

        if (empty($dataList)) {
            // 记录未能解析的数据结构
            \think\facade\Log::warning('parseAndSaveData: 未能解析到有效数据', [
                'response_keys' => array_keys($responseData),
                'response_sample' => json_encode(array_slice($responseData, 0, 3), JSON_UNESCAPED_UNICODE)
            ]);
            return 0;
        }

        $savedCount = 0;
        $dataDate = $startDate ?: ($endDate ?: date('Y-m-d'));
        $columns = $this->getOnlineDailyDataColumns();
        $now = date('Y-m-d H:i:s');

        foreach ($dataList as $item) {
            if (!is_array($item)) continue;
            if (!$this->canSaveCtripLegacyBusinessMetricItem($item)) {
                continue;
            }

            // 尝试多种字段名获取酒店ID，masterHotelId 优先作为携程酒店实体归属 ID。
            $hotelId = $this->resolveCtripPlatformHotelId($item);
            if (empty($hotelId)) continue;

            // 尝试多种字段名获取酒店名称
            $hotelName = $item['hotelName'] ?? $item['hotel_name'] ?? $item['HotelName'] ?? $item['name'] ?? '';

            // 尝试多种字段名获取其他数据
            $amount = $this->meituanNumber($item, ['amount', 'Amount', 'totalAmount', 'total_amount', 'saleAmount', 'orderAmount', 'gmv', 'turnover', 'bookingAmount', '成交收入', '成交金额', '销售额'], 0);
            $quantity = (int)$this->meituanNumber($item, ['quantity', 'Quantity', 'roomNights', 'room_nights', 'checkOutQuantity', 'roomNightCount', 'nightNum', '成交间夜', '间夜', '房晚'], 0);
            $bookOrderNum = (int)$this->meituanNumber($item, ['bookOrderNum', 'book_order_num', 'orderCount', 'order_count', 'orderNum', 'orders', 'bookings', '成交订单数', '订单数'], 0);
            $commentScore = floatval($item['commentScore'] ?? $item['comment_score'] ?? $item['score'] ?? $item['avgScore'] ?? $item['ctripRatingall'] ?? 0);
            $qunarCommentScore = floatval($item['qunarCommentScore'] ?? $item['qunar_comment_score'] ?? $item['qunarScore'] ?? 0);
            $listExposure = (int)$this->meituanNumber($item, ['self_list_exposure', 'listExposure', 'list_exposure'], 0);
            $detailExposure = (int)$this->meituanNumber($item, ['self_detail_exposure', 'detailExposure', 'detail_exposure'], 0);
            $orderFillingNum = (int)$this->meituanNumber($item, ['self_order_filling_num', 'orderFillingNum', 'order_filling_num'], 0);
            $orderSubmitNum = (int)$this->meituanNumber($item, ['self_order_submit_num', 'orderSubmitNum', 'order_submit_num'], 0);
            $flowRate = $this->normalizeMeituanPercentValue($this->firstMeituanValue($item, ['self_flow_rate', 'flowRate', 'flow_rate'], null)) ?? 0.0;

            // 如果有日期字段，优先使用接口返回日期；没有返回时使用请求日期
            $itemDate = $item['dataDate']
                ?? $item['date']
                ?? $item['data_date']
                ?? $item['statDate']
                ?? $item['stat_date']
                ?? $item['bizDate']
                ?? $item['businessDate']
                ?? $item['reportDate']
                ?? $dataDate;
            if (is_string($itemDate) && preg_match('/^\d{4}-\d{2}-\d{2}/', $itemDate, $matches)) {
                $itemDate = $matches[0];
            }
            $periodFilter = $this->applyOnlineDailyDataPeriodFields([
                'data_date' => $itemDate,
                'data_type' => 'business',
                'source' => 'ctrip',
                'dimension' => '',
            ], $columns, $item);

            // 检查是否已存在（按来源、系统酒店、平台酒店、日期去重）
            $query = Db::name('online_daily_data')
                ->where('source', 'ctrip')
                ->where('hotel_id', (string)$hotelId)
                ->where('data_date', $itemDate);
            $this->applyOnlineDailyDataPeriodQuery($query, $periodFilter, $columns);

            if ($systemHotelId !== null) {
                $query->where('system_hotel_id', $systemHotelId);
            } else {
                $query->whereNull('system_hotel_id');
            }

            $exists = $query->find();

            $data = [
                'hotel_id' => (string)$hotelId,
                'hotel_name' => $hotelName,
                'system_hotel_id' => $systemHotelId, // 系统酒店ID，用于门店隔离
                'data_date' => $itemDate,
                'amount' => $amount,
                'quantity' => $quantity,
                'book_order_num' => $bookOrderNum,
                'comment_score' => $commentScore,
                'qunar_comment_score' => $qunarCommentScore,
                'source' => 'ctrip',
                'data_type' => 'business',
                'dimension' => '',
                'raw_data' => json_encode($item, JSON_UNESCAPED_UNICODE),
            ];

            if (isset($columns['update_time'])) {
                $data['update_time'] = $now;
            }
            if (isset($columns['list_exposure'])) {
                $data['list_exposure'] = $listExposure;
            }
            if (isset($columns['detail_exposure'])) {
                $data['detail_exposure'] = $detailExposure;
            }
            if (isset($columns['flow_rate'])) {
                $data['flow_rate'] = $flowRate;
            }
            if (isset($columns['order_filling_num'])) {
                $data['order_filling_num'] = $orderFillingNum;
            }
            if (isset($columns['order_submit_num'])) {
                $data['order_submit_num'] = $orderSubmitNum;
            }
            $data = $this->applyOnlineDailyDataValidationFields($data, $columns);

            if ($exists) {
                Db::name('online_daily_data')
                    ->where('id', $exists['id'])
                    ->update($data);
            } else {
                if (isset($columns['create_time'])) {
                    $data['create_time'] = $now;
                }
                Db::name('online_daily_data')->insert($data);
            }
            $savedCount++;
        }

        return $savedCount;
    }

    private function canSaveCtripLegacyBusinessMetricItem(array $item): bool
    {
        $sourceUrl = strtolower((string)($item['_source_url'] ?? $item['source_url'] ?? $item['url'] ?? ''));
        $endpointId = strtolower((string)($item['_endpoint_id'] ?? $item['endpoint_id'] ?? ''));
        if ($sourceUrl === '' && $endpointId === '') {
            return true;
        }
        if ($this->isCtripRankOnlyBusinessItem($item)) {
            return false;
        }

        foreach ([
            'queryhomepagerealtimedata',
            'getdayreportrealtimedate',
            'fetchmarketoverviewv2',
            'fetchcapacityoverviewv4',
            'getdayreportflowcompete',
            'getdayreportserverquantity',
            'fetchvisitortitlev2',
        ] as $needle) {
            if (str_contains($sourceUrl, $needle) || str_contains($endpointId, $needle)) {
                return true;
            }
        }

        return false;
    }

    private function isCtripRankOnlyBusinessItem(array $item): bool
    {
        $sourceUrl = strtolower((string)($item['_source_url'] ?? $item['source_url'] ?? $item['url'] ?? ''));
        $endpointId = strtolower((string)($item['_endpoint_id'] ?? $item['endpoint_id'] ?? ''));
        if ($endpointId === 'weekly_compete_report' || $endpointId === 'competitor_rank') {
            return true;
        }
        if (str_contains($sourceUrl, 'getcompetehotelreportv1') || str_contains($sourceUrl, 'getcompetingrank')) {
            return true;
        }

        foreach (['bookingGMVrank', 'bookingOrdersrank', 'stayInRNrank', 'rentalRaterank'] as $key) {
            if (array_key_exists($key, $item)) {
                return true;
            }
        }

        return false;
    }

    private function extractCtripBusinessDataList($responseData): array
    {
        $dataList = [];

        if (isset($responseData['data']['hotelList']) && is_array($responseData['data']['hotelList'])) {
            return $responseData['data']['hotelList'];
        }
        if (isset($responseData['data']) && is_array($responseData['data']) && isset($responseData['data'][0])) {
            return $responseData['data'];
        }
        if (isset($responseData['data']) && is_array($responseData['data']) && !isset($responseData['data'][0])) {
            foreach ($responseData['data'] as $value) {
                if (is_array($value) && isset($value[0]) && is_array($value[0]) && (isset($value[0]['hotelId']) || isset($value[0]['hotel_id']) || isset($value[0]['HotelId']))) {
                    $dataList = array_merge($dataList, $value);
                }
            }
        }
        if (!empty($dataList)) {
            return $dataList;
        }
        if (isset($responseData['hotelList']) && is_array($responseData['hotelList'])) {
            return $responseData['hotelList'];
        }
        if (isset($responseData['Response']['hotelList']) && is_array($responseData['Response']['hotelList'])) {
            return $responseData['Response']['hotelList'];
        }
        if (is_array($responseData) && isset($responseData[0])) {
            return $responseData;
        }

        return $this->extractHotelData($responseData);
    }

    private function buildCtripBusinessDisplayHotels($responseData): array
    {
        if (is_array($responseData) && isset($responseData['date_results']) && is_array($responseData['date_results'])) {
            $hotelMap = [];
            foreach ($responseData['date_results'] as $dateResult) {
                if (!is_array($dateResult)) {
                    continue;
                }
                foreach ($this->buildCtripBusinessDisplayHotels($dateResult['data'] ?? []) as $hotel) {
                    $this->mergeCtripBusinessDisplayHotel($hotelMap, $hotel, true);
                }
            }
            return $this->sortBusinessDisplayHotels($hotelMap, 'quantity');
        }

        $hotelMap = [];
        foreach ($this->extractCtripBusinessDataList($responseData) as $item) {
            if (!is_array($item)) {
                continue;
            }
            $hotel = $this->ctripBusinessDisplayHotelFromItem($item);
            if ($hotel !== null) {
                $this->mergeCtripBusinessDisplayHotel($hotelMap, $hotel, false);
            }
        }

        return $this->sortBusinessDisplayHotels($hotelMap, 'quantity');
    }

    private function ctripBusinessDisplayHotelFromItem(array $item): ?array
    {
        if (isset($item['raw_data']) && is_string($item['raw_data']) && $item['raw_data'] !== '') {
            $raw = json_decode($item['raw_data'], true);
            if (is_array($raw)) {
                $item = array_replace($raw, $item);
            }
        }

        $hotelId = (string)($item['hotelId'] ?? $item['hotel_id'] ?? $item['HotelId'] ?? $item['hotelID'] ?? $item['id'] ?? '');
        $hotelName = (string)($item['hotelName'] ?? $item['hotel_name'] ?? $item['HotelName'] ?? $item['name'] ?? '');
        if ($hotelId === '' && $hotelName === '') {
            return null;
        }

        return [
            'hotelId' => $hotelId,
            'hotelName' => $hotelName !== '' ? $hotelName : 'unknown',
            'amount' => $this->numberFromKeys($item, ['amount', 'Amount', 'totalAmount', 'total_amount', 'saleAmount']),
            'quantity' => (int)$this->numberFromKeys($item, ['quantity', 'Quantity', 'roomNights', 'room_nights', 'checkOutQuantity', 'checkInQuantity']),
            'bookOrderNum' => (int)$this->numberFromKeys($item, ['bookOrderNum', 'book_order_num', 'orderCount', 'order_count']),
            'totalOrderNum' => (int)$this->numberFromKeys($item, ['totalOrderNum', 'total_order_num', 'bookOrderNum', 'book_order_num', 'orderCount', 'order_count']),
            'commentScore' => $this->numberFromKeys($item, ['commentScore', 'comment_score', 'score', 'avgScore']),
            'qunarCommentScore' => $this->numberFromKeys($item, ['qunarCommentScore', 'qunar_comment_score', 'qunarScore']),
            'totalDetailNum' => (int)$this->numberFromKeys($item, ['totalDetailNum', 'total_detail_num', 'detailVisitors', 'exposure', 'exposureCount', 'pv', 'pageView', 'viewCount']),
            'qunarDetailVisitors' => (int)$this->numberFromKeys($item, ['qunarDetailVisitors', 'qunar_detail_visitors', 'views', 'uv', 'visitorCount', 'detailUv']),
            'convertionRate' => $this->numberFromKeys($item, ['convertionRate', 'convertion_rate', 'conversionRate']),
            'qunarDetailCR' => $this->numberFromKeys($item, ['qunarDetailCR', 'qunar_detail_cr']),
            'amountRank' => (int)$this->numberFromKeys($item, ['amountRank', 'amount_rank'], 0),
            'quantityRank' => (int)$this->numberFromKeys($item, ['quantityRank', 'quantity_rank'], 0),
            'commentScoreRank' => (int)$this->numberFromKeys($item, ['commentScoreRank', 'comment_score_rank'], 0),
            'qunarDetailCRRank' => (int)$this->numberFromKeys($item, ['qunarDetailCRRank', 'qunar_detail_cr_rank'], 0),
            'sourceLabel' => '携程竞争圈返回',
            'sourceStatusText' => '携程竞争圈返回',
            'metricSourceStatus' => $this->buildCtripMetricSourceStatusFromItem($item),
        ];
    }

    private function mergeCtripBusinessDisplayHotel(array &$hotelMap, array $hotel, bool $sumValues): void
    {
        $key = (string)($hotel['hotelId'] ?? '') . '_' . (string)($hotel['hotelName'] ?? '');
        if (!isset($hotelMap[$key])) {
            $hotelMap[$key] = $hotel;
            return;
        }

        foreach (['amount', 'quantity', 'bookOrderNum', 'totalOrderNum', 'totalDetailNum', 'qunarDetailVisitors'] as $field) {
            $hotelMap[$key][$field] = $sumValues
                ? (float)($hotelMap[$key][$field] ?? 0) + (float)($hotel[$field] ?? 0)
                : max((float)($hotelMap[$key][$field] ?? 0), (float)($hotel[$field] ?? 0));
        }
        foreach (['quantity', 'bookOrderNum', 'totalOrderNum', 'totalDetailNum', 'qunarDetailVisitors'] as $field) {
            $hotelMap[$key][$field] = (int)($hotelMap[$key][$field] ?? 0);
        }
        foreach (['commentScore', 'qunarCommentScore', 'convertionRate', 'qunarDetailCR'] as $field) {
            $hotelMap[$key][$field] = max((float)($hotelMap[$key][$field] ?? 0), (float)($hotel[$field] ?? 0));
        }
        foreach (['amountRank', 'quantityRank', 'commentScoreRank', 'qunarDetailCRRank'] as $field) {
            $existing = (int)($hotelMap[$key][$field] ?? 0);
            $incoming = (int)($hotel[$field] ?? 0);
            if ($incoming > 0) {
                $hotelMap[$key][$field] = $existing === 0 ? $incoming : min($existing, $incoming);
            }
        }
        $hotelMap[$key]['sourceLabel'] = '携程竞争圈返回';
        $hotelMap[$key]['sourceStatusText'] = '携程竞争圈返回';
        $hotelMap[$key]['metricSourceStatus'] = $this->mergeCtripMetricSourceStatus(
            is_array($hotelMap[$key]['metricSourceStatus'] ?? null) ? $hotelMap[$key]['metricSourceStatus'] : [],
            is_array($hotel['metricSourceStatus'] ?? null) ? $hotel['metricSourceStatus'] : []
        );
    }

    private function buildCtripMetricSourceStatusFromItem(array $item): array
    {
        $status = [];
        foreach ($this->ctripBusinessMetricSourceKeyMap() as $field => $keys) {
            $status[$field] = $this->hasAnySourceKey($item, $keys) ? '携程竞争圈返回' : '系统未返回';
        }
        return $status;
    }

    private function ctripBusinessMetricSourceKeyMap(): array
    {
        return [
            'amount' => ['amount', 'Amount', 'totalAmount', 'total_amount', 'saleAmount'],
            'quantity' => ['quantity', 'Quantity', 'roomNights', 'room_nights', 'checkOutQuantity', 'checkInQuantity'],
            'bookOrderNum' => ['bookOrderNum', 'book_order_num', 'orderCount', 'order_count'],
            'totalOrderNum' => ['totalOrderNum', 'total_order_num', 'bookOrderNum', 'book_order_num', 'orderCount', 'order_count'],
            'commentScore' => ['commentScore', 'comment_score', 'score', 'avgScore'],
            'qunarCommentScore' => ['qunarCommentScore', 'qunar_comment_score', 'qunarScore'],
            'totalDetailNum' => ['totalDetailNum', 'total_detail_num', 'detailVisitors', 'exposure', 'exposureCount', 'pv', 'pageView', 'viewCount'],
            'qunarDetailVisitors' => ['qunarDetailVisitors', 'qunar_detail_visitors', 'views', 'uv', 'visitorCount', 'detailUv'],
            'convertionRate' => ['convertionRate', 'convertion_rate', 'conversionRate'],
            'qunarDetailCR' => ['qunarDetailCR', 'qunar_detail_cr'],
            'amountRank' => ['amountRank', 'amount_rank'],
            'quantityRank' => ['quantityRank', 'quantity_rank'],
            'commentScoreRank' => ['commentScoreRank', 'comment_score_rank'],
            'qunarDetailCRRank' => ['qunarDetailCRRank', 'qunar_detail_cr_rank'],
        ];
    }

    private function hasAnySourceKey(array $item, array $keys): bool
    {
        foreach ($keys as $key) {
            if (array_key_exists($key, $item)) {
                return true;
            }
        }
        return false;
    }

    private function mergeCtripMetricSourceStatus(array $base, array $incoming): array
    {
        foreach ($incoming as $field => $status) {
            if ($status === '携程竞争圈返回' || !isset($base[$field])) {
                $base[$field] = $status;
            }
        }
        return $base;
    }

    private function buildMeituanBusinessDisplayHotels($responseData, array $context = []): array
    {
        $hotelMap = [];
        foreach ($this->extractMeituanBusinessRankRows($responseData) as $item) {
            if (!is_array($item)) {
                continue;
            }
            $hotelId = (string)($item['poiId'] ?? $item['poi_id'] ?? $item['shopId'] ?? $item['shop_id'] ?? $item['hotelId'] ?? '');
            $hotelName = (string)($item['poiName'] ?? $item['poi_name'] ?? $item['shopName'] ?? $item['shop_name'] ?? $item['hotelName'] ?? $item['name'] ?? '');
            if ($hotelId === '' && $hotelName === '') {
                continue;
            }

            $key = $this->meituanBusinessDisplayHotelKey($hotelId, $hotelName);
            if (!isset($hotelMap[$key])) {
                $hotelMap[$key] = $this->emptyMeituanBusinessDisplayHotelRow($hotelId, $hotelName, $context);
            }

            $metricType = $this->classifyMeituanBusinessDisplayMetric((string)($item['_dimName'] ?? $item['dimension'] ?? ''), (string)($item['_aiMetricName'] ?? $item['aiMetricName'] ?? ''), (string)($item['rankType'] ?? $item['rank_type'] ?? ''));
            $value = $this->nullableNumberFromKeys($item, ['dataValue', 'data_value', 'monthRoomNights', 'month_room_nights']);
            $rankPercent = $this->meituanRankPercentValue($item);
            if ($metricType !== '') {
                if ($value !== null) {
                    $hotelMap[$key][$metricType] = max((float)($hotelMap[$key][$metricType] ?? 0), $value);
                    $hotelMap[$key]['metricSourceStatus'][$metricType] = '美团榜单返回';
                } elseif ($rankPercent !== null && empty($hotelMap[$key]['metricSourceStatus'][$metricType])) {
                    $hotelMap[$key]['metricSourceStatus'][$metricType] = '美团仅返回百分比';
                }
                if ($rankPercent !== null) {
                    $hotelMap[$key]['metricRankPercent'][$metricType] = $rankPercent;
                }
            }
            $platformTagInfo = $this->extractMeituanPlatformTagInfo($item);
            $hotelMap[$key]['platformTags'] = $this->mergeStringList($hotelMap[$key]['platformTags'] ?? [], $platformTagInfo['tags']);
            if (($platformTagInfo['status'] ?? '') !== 'not_returned') {
                $hotelMap[$key]['platformTagStatus'] = $platformTagInfo['status'];
            }
            if ($hotelName !== '') {
                $hotelMap[$key]['nameAliases'] = $this->mergeStringList($hotelMap[$key]['nameAliases'] ?? [], [$hotelName]);
            }
            $rank = (int)$this->numberFromKeys($item, ['rank', 'ranking'], 0);
            if ($rank > 0) {
                $existingRank = (int)($hotelMap[$key]['rank'] ?? 0);
                $hotelMap[$key]['rank'] = $existingRank === 0 ? $rank : min($existingRank, $rank);
                $sourceLabel = $value !== null ? '美团榜单返回' : ($rankPercent !== null ? '美团仅返回百分比' : '美团榜单未返回数值');
                $hotelMap[$key]['rankHistory'][] = $this->buildMeituanRankHistoryEntry($item, $context, $metricType, $rank, $value ?? 0.0, $rankPercent, $sourceLabel);
            }
        }

        $hotelMap = $this->applyMeituanPercentDerivedMetrics($hotelMap, $context);
        return $this->sortBusinessDisplayHotels($hotelMap, 'roomNights');
    }

    private function mergeMeituanBusinessDisplayHotels(array $rows, array $context = []): array
    {
        $hotelMap = [];
        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }
            $poiId = (string)($row['poiId'] ?? $row['poi_id'] ?? $row['hotelId'] ?? '');
            $hotelName = (string)($row['hotelName'] ?? $row['hotel_name'] ?? $row['poiName'] ?? '');
            if ($poiId === '' && $hotelName === '') {
                continue;
            }
            $key = $this->meituanBusinessDisplayHotelKey($poiId, $hotelName);
            if (!isset($hotelMap[$key])) {
                $hotelMap[$key] = $this->emptyMeituanBusinessDisplayHotelRow($poiId, $hotelName, $context);
            }

            foreach (['roomNights', 'roomRevenue', 'salesRoomNights', 'sales', 'viewConversion', 'payConversion', 'exposure', 'views'] as $field) {
                $hotelMap[$key][$field] = max((float)($hotelMap[$key][$field] ?? 0), (float)($row[$field] ?? 0));
                $incomingStatus = (string)($row['metricSourceStatus'][$field] ?? '');
                if ((float)($row[$field] ?? 0) > 0 || $this->isMeituanMetricSourceUsable($incomingStatus)) {
                    $hotelMap[$key]['metricSourceStatus'][$field] = $incomingStatus !== '' ? $incomingStatus : '美团榜单返回';
                } elseif ($incomingStatus !== '' && empty($hotelMap[$key]['metricSourceStatus'][$field])) {
                    $hotelMap[$key]['metricSourceStatus'][$field] = $incomingStatus;
                }
            }
            foreach ((is_array($row['metricRankPercent'] ?? null) ? $row['metricRankPercent'] : []) as $field => $percent) {
                if (is_numeric($percent)) {
                    $hotelMap[$key]['metricRankPercent'][$field] = (float)$percent;
                }
            }
            foreach ((is_array($row['metricDerived'] ?? null) ? $row['metricDerived'] : []) as $field => $derived) {
                if (is_array($derived)) {
                    $hotelMap[$key]['metricDerived'][$field] = $derived;
                }
            }
            $hotelMap[$key]['platformTags'] = $this->mergeStringList($hotelMap[$key]['platformTags'] ?? [], is_array($row['platformTags'] ?? null) ? $row['platformTags'] : []);
            if (($row['platformTagStatus'] ?? '') !== '' && ($row['platformTagStatus'] ?? '') !== 'not_returned') {
                $hotelMap[$key]['platformTagStatus'] = (string)$row['platformTagStatus'];
            }
            $hotelMap[$key]['nameAliases'] = $this->mergeStringList($hotelMap[$key]['nameAliases'] ?? [], is_array($row['nameAliases'] ?? null) ? $row['nameAliases'] : [$hotelName]);
            if (!empty($row['isSelf'])) {
                $hotelMap[$key]['isSelf'] = true;
            }
            if (is_array($row['rankHistory'] ?? null)) {
                $hotelMap[$key]['rankHistory'] = array_merge($hotelMap[$key]['rankHistory'] ?? [], $row['rankHistory']);
            }
            $rank = (int)($row['rank'] ?? 0);
            if ($rank > 0) {
                $existingRank = (int)($hotelMap[$key]['rank'] ?? 0);
                $hotelMap[$key]['rank'] = $existingRank === 0 ? $rank : min($existingRank, $rank);
                if (empty($row['rankHistory'])) {
                    $hotelMap[$key]['rankHistory'][] = [
                        'dateRange' => (string)($row['dateRange'] ?? $context['date_range'] ?? ''),
                        'dateRangeLabel' => $this->meituanDateRangeLabel((string)($row['dateRange'] ?? $context['date_range'] ?? '')),
                        'rankType' => (string)($row['rankType'] ?? $context['rank_type'] ?? ''),
                        'rankTypeLabel' => $this->meituanRankTypeLabel((string)($row['rankType'] ?? $context['rank_type'] ?? '')),
                        'metric' => '',
                        'metricLabel' => '平台排名',
                        'rank' => $rank,
                        'value' => 0.0,
                        'sourceLabel' => '美团榜单返回',
                    ];
                }
            }
        }

        $hotelMap = $this->applyMeituanPercentDerivedMetrics($hotelMap, $context);
        return $this->sortBusinessDisplayHotels($hotelMap, 'roomNights');
    }

    private function extractMeituanBusinessRankRows($responseData): array
    {
        if (!is_array($responseData)) {
            return [];
        }
        foreach ([
            $responseData['data']['peerRankData'] ?? null,
            $responseData['data']['data']['peerRankData'] ?? null,
            $responseData['peerRankData'] ?? null,
        ] as $peerRankData) {
            if (is_array($peerRankData)) {
                $rows = [];
                foreach ($peerRankData as $rankData) {
                    if (!is_array($rankData) || !isset($rankData['roundRanks']) || !is_array($rankData['roundRanks'])) {
                        continue;
                    }
                    foreach ($rankData['roundRanks'] as $item) {
                        if (!is_array($item)) {
                            continue;
                        }
                        $item['_dimName'] = $rankData['dimName'] ?? '';
                        $item['_aiMetricName'] = $rankData['aiMetricName'] ?? '';
                        $rows[] = $item;
                    }
                }
                return $rows;
            }
        }

        foreach ([
            $responseData['data']['roundrank'] ?? null,
            $responseData['data']['rankList'] ?? null,
            $responseData['data']['list'] ?? null,
            $responseData['data'] ?? null,
            $responseData['list'] ?? null,
            $responseData['roundrank'] ?? null,
        ] as $rows) {
            if (is_array($rows) && isset($rows[0]) && is_array($rows[0])) {
                return $rows;
            }
        }

        return [];
    }

    private function classifyMeituanBusinessDisplayMetric(string $dimName, string $metricName, string $rankType): string
    {
        $upperMetric = strtoupper($metricName);
        $combined = $dimName . '|' . $upperMetric;
        if (str_contains($upperMetric, 'P_RZ_NIGHT_COUNT') || str_contains($upperMetric, 'NIGHT_COUNT') || str_contains($upperMetric, 'ROOM_NIGHT') || str_contains($combined, '间夜')) {
            return str_contains($upperMetric, 'P_XS') ? 'salesRoomNights' : 'roomNights';
        }
        if (str_contains($upperMetric, 'P_RZ_ROOM_PAY') || str_contains($combined, '房费') || str_contains($combined, '收入')) {
            return 'roomRevenue';
        }
        if ((str_contains($upperMetric, 'P_XS') && str_contains($upperMetric, 'AMT')) || str_contains($combined, '销售额')) {
            return 'sales';
        }
        if (str_contains($upperMetric, 'VIEW_CONVERT') || str_contains($combined, '浏览转化')) {
            return 'viewConversion';
        }
        if (str_contains($upperMetric, 'PAY_CONVERT') || str_contains($combined, '支付转化')) {
            return 'payConversion';
        }
        if (str_contains($upperMetric, 'EXPOSURE') || str_contains($combined, '曝光')) {
            return 'exposure';
        }
        if (str_contains($upperMetric, 'VIEW') || str_contains($combined, '浏览')) {
            return 'views';
        }
        if ($rankType === 'P_LL') {
            return 'exposure';
        }
        return '';
    }

    private function numberFromKeys(array $data, array $keys, float $default = 0.0): float
    {
        foreach ($keys as $key) {
            if (array_key_exists($key, $data) && $data[$key] !== null && $data[$key] !== '') {
                $value = is_string($data[$key]) ? str_replace([',', '%', ' '], '', trim($data[$key])) : $data[$key];
                return is_numeric($value) ? (float)$value : $default;
            }
        }
        return $default;
    }

    private function nullableNumberFromKeys(array $data, array $keys): ?float
    {
        foreach ($keys as $key) {
            if (!array_key_exists($key, $data) || $data[$key] === null || $data[$key] === '') {
                continue;
            }
            $value = is_string($data[$key]) ? str_replace([',', '%', ' '], '', trim($data[$key])) : $data[$key];
            if (is_numeric($value)) {
                return (float)$value;
            }
        }
        return null;
    }

    private function meituanRankPercentValue(array $item): ?float
    {
        return $this->nullableNumberFromKeys($item, [
            'percent',
            'rankPercent',
            'rank_percent',
            'dataPercent',
            'data_percent',
            'ratio',
            'percentage',
        ]);
    }

    private function emptyMeituanBusinessDisplayHotelRow(string $poiId, string $hotelName, array $context = []): array
    {
        $targetPoiId = (string)($context['target_poi_id'] ?? '');
        $displayName = $hotelName !== '' ? $hotelName : 'unknown';
        return [
            'poiId' => $poiId,
            'hotelName' => $displayName,
            'normalizedHotelName' => $this->normalizeMeituanHotelName($displayName),
            'nameAliases' => $hotelName !== '' ? [$hotelName] : [],
            'roomNights' => 0.0,
            'roomRevenue' => 0.0,
            'salesRoomNights' => 0.0,
            'sales' => 0.0,
            'viewConversion' => 0.0,
            'payConversion' => 0.0,
            'exposure' => 0.0,
            'views' => 0.0,
            'rank' => 0,
            'rankHistory' => [],
            'rankByRange' => [],
            'platformTags' => [],
            'platformTagText' => '未返回',
            'platformTagStatus' => 'not_returned',
            'platformTagSourceText' => '系统未返回',
            'hasVipTag' => false,
            'metricSourceStatus' => [],
            'metricRankPercent' => [],
            'metricDerived' => [],
            'sourceLabel' => '美团榜单返回',
            'sourceStatusText' => '美团榜单返回',
            'isSelf' => $targetPoiId !== '' && $poiId !== '' && $targetPoiId === $poiId,
        ];
    }

    private function applyMeituanPercentDerivedMetrics(array $hotelMap, array $context = []): array
    {
        $selfKey = null;
        foreach ($hotelMap as $key => $row) {
            if (is_array($row) && !empty($row['isSelf'])) {
                $selfKey = (string)$key;
                break;
            }
        }
        if ($selfKey === null || !isset($hotelMap[$selfKey]) || !is_array($hotelMap[$selfKey])) {
            return $this->applyMeituanPercentScaleDerivedMetrics($hotelMap);
        }

        $fields = ['roomNights', 'roomRevenue', 'salesRoomNights', 'sales', 'viewConversion', 'payConversion', 'exposure', 'views'];
        foreach ($fields as $field) {
            $selfValue = $this->meituanSelfMetricValue($field, $hotelMap[$selfKey], $context);
            $selfPercent = $this->meituanMetricRankPercent($hotelMap[$selfKey], $field);
            if ($selfValue === null || $selfValue <= 0 || $selfPercent === null || $selfPercent <= 0) {
                continue;
            }

            foreach ($hotelMap as &$row) {
                if (!is_array($row)) {
                    continue;
                }
                $rowPercent = $this->meituanMetricRankPercent($row, $field);
                if ($rowPercent === null || $rowPercent < 0) {
                    continue;
                }

                $status = (string)($row['metricSourceStatus'][$field] ?? '');
                if ((float)($row[$field] ?? 0) > 0 && $this->isMeituanMetricSourceUsable($status)) {
                    continue;
                }

                $derivedValue = $this->roundMeituanDerivedMetric($field, $selfValue * $rowPercent / $selfPercent);
                $row[$field] = $derivedValue;
                $row['metricSourceStatus'][$field] = '按本店值和美团百分比推导';
                $row['metricDerived'][$field] = [
                    'method' => 'self_value_times_row_percent_div_self_percent',
                    'self_value' => $selfValue,
                    'self_percent' => $selfPercent,
                    'row_percent' => $rowPercent,
                ];

                if (is_array($row['rankHistory'] ?? null)) {
                    foreach ($row['rankHistory'] as &$history) {
                        if (is_array($history) && ($history['metric'] ?? '') === $field) {
                            $history['value'] = $derivedValue;
                            $history['sourceLabel'] = '按本店值和美团百分比推导';
                            $history['derived'] = $row['metricDerived'][$field];
                        }
                    }
                    unset($history);
                }
            }
            unset($row);
        }

        return $this->applyMeituanPercentScaleDerivedMetrics($hotelMap);
    }

    private function applyMeituanPercentScaleDerivedMetrics(array $hotelMap): array
    {
        foreach (['roomNights', 'roomRevenue', 'salesRoomNights', 'sales', 'exposure', 'views'] as $field) {
            $scale = $this->inferMeituanMinimalPercentScale($hotelMap, $field);
            if ($scale === null) {
                continue;
            }

            foreach ($hotelMap as &$row) {
                if (!is_array($row)) {
                    continue;
                }
                $rowPercent = $this->meituanMetricRankPercent($row, $field);
                if ($rowPercent === null || $rowPercent < 0) {
                    continue;
                }

                $status = (string)($row['metricSourceStatus'][$field] ?? '');
                if ((float)($row[$field] ?? 0) > 0 && $this->isMeituanMetricSourceUsable($status)) {
                    continue;
                }

                $derivedValue = $this->roundMeituanDerivedMetric($field, $scale * $rowPercent / 100);
                if ($this->isMeituanIntegerScaleMetric($field)) {
                    $derivedValue = (float)max(0, (int)round($derivedValue));
                }

                $row[$field] = $derivedValue;
                $row['metricSourceStatus'][$field] = '按美团百分比最小整数比例尺估算';
                $row['metricDerived'][$field] = [
                    'method' => 'percent_min_integer_scale',
                    'scale_value' => $scale,
                    'row_percent' => $rowPercent,
                    'percent_precision' => 2,
                    'source_scope' => 'meituan_rank_percent_only',
                ];

                if (is_array($row['rankHistory'] ?? null)) {
                    foreach ($row['rankHistory'] as &$history) {
                        if (is_array($history) && ($history['metric'] ?? '') === $field) {
                            $history['value'] = $derivedValue;
                            $history['sourceLabel'] = '按美团百分比最小整数比例尺估算';
                            $history['derived'] = $row['metricDerived'][$field];
                        }
                    }
                    unset($history);
                }
            }
            unset($row);
        }

        return $hotelMap;
    }

    private function inferMeituanMinimalPercentScale(array $hotelMap, string $field): ?int
    {
        $percents = [];
        foreach ($hotelMap as $row) {
            if (!is_array($row)) {
                continue;
            }
            $percent = $this->meituanMetricRankPercent($row, $field);
            if ($percent === null || $percent < 0 || $percent > 100.005) {
                continue;
            }
            $percents[sprintf('%.2F', round($percent, 2))] = round($percent, 2);
        }

        $positivePercents = array_values(array_filter($percents, static fn(float $percent): bool => $percent > 0));
        if (count($positivePercents) < 2 || abs(max($positivePercents) - 100.0) > 0.005) {
            return null;
        }

        sort($positivePercents, SORT_NUMERIC);
        $maxScale = 50000;
        for ($scale = 1; $scale <= $maxScale; $scale++) {
            if ($this->meituanPercentScaleMatches($scale, $positivePercents)) {
                return $scale;
            }
        }

        return null;
    }

    private function meituanPercentScaleMatches(int $scale, array $percents): bool
    {
        foreach ($percents as $percent) {
            $value = (int)round($scale * $percent / 100);
            if ($percent > 0 && $value <= 0) {
                return false;
            }
            $restoredPercent = round($value * 100 / $scale, 2);
            if (abs($restoredPercent - $percent) > 0.0050001) {
                return false;
            }
        }
        return true;
    }

    private function isMeituanIntegerScaleMetric(string $field): bool
    {
        return in_array($field, ['roomNights', 'salesRoomNights', 'exposure', 'views'], true);
    }

    private function meituanMetricRankPercent(array $row, string $field): ?float
    {
        $percents = is_array($row['metricRankPercent'] ?? null) ? $row['metricRankPercent'] : [];
        return isset($percents[$field]) && is_numeric($percents[$field]) ? (float)$percents[$field] : null;
    }

    private function meituanSelfMetricValue(string $field, array $selfRow, array $context = []): ?float
    {
        $values = $this->normalizeMeituanSelfMetricValues($context['self_metric_values'] ?? $context['selfMetricValues'] ?? []);
        if (isset($values[$field])) {
            return $values[$field];
        }
        $value = (float)($selfRow[$field] ?? 0);
        return $value > 0 ? $value : null;
    }

    private function normalizeMeituanSelfMetricValues($value): array
    {
        if (is_string($value)) {
            $decoded = json_decode($value, true);
            $value = is_array($decoded) ? $decoded : [];
        }
        if (!is_array($value)) {
            return [];
        }

        $aliases = [
            'roomNights' => ['roomNights', 'room_nights', 'quantity', 'stayRoomNights'],
            'roomRevenue' => ['roomRevenue', 'room_revenue', 'stayRevenue', 'stay_revenue'],
            'salesRoomNights' => ['salesRoomNights', 'sales_room_nights', 'salesQuantity'],
            'sales' => ['sales', 'salesAmount', 'sales_amount', 'amount'],
            'viewConversion' => ['viewConversion', 'view_conversion'],
            'payConversion' => ['payConversion', 'pay_conversion'],
            'exposure' => ['exposure', 'listExposure', 'list_exposure'],
            'views' => ['views', 'view', 'detailExposure', 'detail_exposure'],
        ];
        $result = [];
        foreach ($aliases as $field => $keys) {
            $number = $this->nullableNumberFromKeys($value, $keys);
            if ($number !== null) {
                $result[$field] = $number;
            }
        }
        return $result;
    }

    private function roundMeituanDerivedMetric(string $field, float $value): float
    {
        if (in_array($field, ['viewConversion', 'payConversion'], true)) {
            return round($value, 4);
        }
        return round($value, 2);
    }

    private function isMeituanMetricSourceUsable(string $status): bool
    {
        if (str_starts_with($status, '按美团百分比')) {
            return true;
        }
        return in_array($status, [
            '美团榜单返回',
            '美团榜单入库',
            '按本店值和美团百分比推导',
            '按销售间夜代理估算',
            '按曝光和浏览估算',
            '按订单量和浏览估算',
            '按订单量和曝光估算',
            '按浏览转化和支付转化估算',
        ], true);
    }

    private function meituanBusinessDisplayHotelKey(string $poiId, string $hotelName): string
    {
        if ($poiId !== '') {
            return 'poi:' . $poiId;
        }
        return 'name:' . $this->normalizeMeituanHotelName($hotelName);
    }

    private function normalizeMeituanHotelName(string $name): string
    {
        $value = str_replace(["\r", "\n", "\t", '（', '）'], [' ', ' ', ' ', '(', ')'], trim($name));
        $value = preg_replace('/\s+/u', ' ', $value) ?: $value;
        return trim($value);
    }

    private function extractMeituanPlatformTagInfo(array $item): array
    {
        $tagKeys = [
            'tags', 'tagList', 'tag_list', 'labels', 'labelList', 'label_list',
            'hotelTags', 'hotelTagList', 'poiTagList', 'rightsTags', 'rightsTagList',
            'badgeList', 'benefitTags', 'titleTags', 'identityTags', 'platformTags',
        ];
        $singleTagKeys = [
            'vipTag', 'memberTag', 'rightsTag', 'platformTag', 'crownLevel', 'crownTag',
            'brandTag', 'brandName', 'chainName', 'hotelBrand', 'groupName', 'starTag',
        ];
        $booleanVipKeys = ['isVip', 'isVIP', 'vip', 'vipFlag', 'memberFlag', 'isMemberHotel'];

        $tags = [];
        $returned = false;
        foreach ($tagKeys as $key) {
            if (array_key_exists($key, $item)) {
                $returned = true;
                $tags = $this->mergeStringList($tags, $this->collectMeituanTagTokens($item[$key]));
            }
        }
        foreach ($singleTagKeys as $key) {
            if (array_key_exists($key, $item)) {
                $returned = true;
                $tokens = $this->collectMeituanTagTokens($item[$key]);
                if (in_array($key, ['crownLevel', 'crownTag'], true)) {
                    $tokens = array_map(static function ($token): string {
                        $text = trim((string)$token);
                        return preg_match('/^\d+$/', $text) ? ('冠级' . $text) : $text;
                    }, $tokens);
                }
                $tags = $this->mergeStringList($tags, $tokens);
            }
        }
        foreach ($booleanVipKeys as $key) {
            if (array_key_exists($key, $item)) {
                $returned = true;
                if ($this->isExplicitTruthy($item[$key])) {
                    $tags = $this->mergeStringList($tags, ['VIP']);
                }
            }
        }

        $tags = array_values(array_filter(array_map([$this, 'normalizeMeituanPlatformTag'], $tags), static fn($tag): bool => $tag !== ''));
        $tags = $this->mergeStringList([], $tags);
        return [
            'tags' => $tags,
            'status' => !empty($tags) ? 'returned' : ($returned ? 'returned_empty' : 'not_returned'),
        ];
    }

    private function collectMeituanTagTokens($value): array
    {
        if ($value === null || $value === '') {
            return [];
        }
        if (is_scalar($value)) {
            return [(string)$value];
        }
        if (!is_array($value)) {
            return [];
        }

        $tokens = [];
        $preferredKeys = ['name', 'tagName', 'tag_name', 'label', 'text', 'title', 'value', 'displayName', 'rightsName'];
        foreach ($preferredKeys as $key) {
            if (array_key_exists($key, $value) && is_scalar($value[$key]) && trim((string)$value[$key]) !== '') {
                $tokens[] = (string)$value[$key];
            }
        }
        if (!empty($tokens)) {
            return $tokens;
        }
        foreach ($value as $child) {
            $tokens = $this->mergeStringList($tokens, $this->collectMeituanTagTokens($child));
        }
        return $tokens;
    }

    private function normalizeMeituanPlatformTag(string $tag): string
    {
        $value = trim(preg_replace('/\s+/u', ' ', $tag) ?: $tag);
        if ($value === '') {
            return '';
        }
        if (preg_match('/\bvip\b/i', $value)) {
            return 'VIP';
        }
        if (preg_match('/^(?:0|1|true|false|yes|no)$/i', $value) || preg_match('/^\d+$/', $value)) {
            return '';
        }
        if (function_exists('mb_strlen') && function_exists('mb_substr')) {
            return mb_strlen($value, 'UTF-8') > 24 ? mb_substr($value, 0, 24, 'UTF-8') : $value;
        }
        return strlen($value) > 72 ? substr($value, 0, 72) : $value;
    }

    private function hasMeituanVipPlatformTag(array $tags): bool
    {
        foreach ($tags as $tag) {
            if (preg_match('/\bvip\b/i', (string)$tag)) {
                return true;
            }
        }
        return false;
    }

    private function mergeStringList(array $base, array $incoming): array
    {
        $seen = [];
        $result = [];
        foreach (array_merge($base, $incoming) as $value) {
            $text = trim((string)$value);
            if ($text === '') {
                continue;
            }
            $key = strtolower($text);
            if (isset($seen[$key])) {
                continue;
            }
            $seen[$key] = true;
            $result[] = $text;
        }
        return $result;
    }

    private function isExplicitTruthy($value): bool
    {
        if (is_bool($value)) {
            return $value;
        }
        if (is_numeric($value)) {
            return (float)$value > 0;
        }
        $text = strtolower(trim((string)$value));
        return in_array($text, ['1', 'true', 'yes', 'y', 'vip'], true);
    }

    private function buildMeituanRankHistoryEntry(array $item, array $context, string $metricType, int $rank, float $value, ?float $rankPercent = null, string $sourceLabel = '美团榜单返回'): array
    {
        $dateRange = (string)($context['date_range'] ?? '');
        if ($dateRange === '') {
            $dateRange = (string)($item['dateRange'] ?? $item['date_range'] ?? '');
        }
        $rankType = (string)($context['rank_type'] ?? '');
        if ($rankType === '') {
            $rankType = (string)($item['rankType'] ?? $item['rank_type'] ?? '');
        }
        $metricLabel = (string)($item['_dimName'] ?? $item['dimension'] ?? $item['_aiMetricName'] ?? $item['aiMetricName'] ?? '平台排名');
        return [
            'dateRange' => $dateRange,
            'dateRangeLabel' => $this->meituanDateRangeLabel($dateRange),
            'rankType' => $rankType,
            'rankTypeLabel' => $this->meituanRankTypeLabel($rankType),
            'metric' => $metricType,
            'metricLabel' => $metricLabel,
            'rank' => $rank,
            'value' => $value,
            'percent' => $rankPercent,
            'sourceLabel' => $sourceLabel,
        ];
    }

    private function meituanRankTypeLabel(string $rankType): string
    {
        return [
            'P_RZ' => '入住榜',
            'P_XS' => '销售榜',
            'P_LL' => '流量榜',
            'P_ZH' => '转化榜',
        ][$rankType] ?? ($rankType !== '' ? $rankType : '未标明榜单');
    }

    private function meituanDateRangeLabel(string $dateRange): string
    {
        return [
            '0' => '实时',
            '1' => '昨日',
            '7' => '近7天',
            '30' => '近30天',
            'custom' => '自定义',
        ][$dateRange] ?? ($dateRange !== '' ? $dateRange : '未标明时间');
    }

    private function sortBusinessDisplayHotels(array $hotelMap, string $sortField): array
    {
        $rows = $this->enrichMeituanBusinessDisplayMetrics($this->enrichCtripBusinessDisplayMetrics(array_values($hotelMap)));
        $hasSortMetric = count(array_filter($rows, static fn(array $row): bool => (float)($row[$sortField] ?? 0) > 0)) > 0;
        usort($rows, static function (array $a, array $b) use ($sortField, $hasSortMetric): int {
            if ($hasSortMetric) {
                $metricCompare = ((float)($b[$sortField] ?? 0)) <=> ((float)($a[$sortField] ?? 0));
                if ($metricCompare !== 0) {
                    return $metricCompare;
                }
            }

            $aRank = (int)($a['currentPlatformRank'] ?? $a['rank'] ?? 0);
            $bRank = (int)($b['currentPlatformRank'] ?? $b['rank'] ?? 0);
            if ($aRank > 0 && $bRank > 0 && $aRank !== $bRank) {
                return $aRank <=> $bRank;
            }
            if ($aRank > 0 && $bRank <= 0) {
                return -1;
            }
            if ($bRank > 0 && $aRank <= 0) {
                return 1;
            }

            return strcmp((string)($a['hotelName'] ?? ''), (string)($b['hotelName'] ?? ''));
        });
        return $this->finalizeMeituanBusinessDisplayRows($rows, $sortField);
    }

    private function enrichCtripBusinessDisplayMetrics(array $rows): array
    {
        $adrValues = [];
        foreach ($rows as $row) {
            if (!$this->isCtripBusinessDisplayRow($row)) {
                continue;
            }
            $amount = (float)($row['amount'] ?? 0);
            $quantity = (int)($row['quantity'] ?? 0);
            if ($amount > 0 && $quantity > 0) {
                $adrValues[] = $amount / $quantity;
            }
        }
        $circleAdr = count($adrValues) > 0 ? array_sum($adrValues) / count($adrValues) : 0.0;

        foreach ($rows as &$row) {
            if (!$this->isCtripBusinessDisplayRow($row)) {
                continue;
            }

            $amount = (float)($row['amount'] ?? 0);
            $quantity = (int)($row['quantity'] ?? 0);
            $bookOrderNum = (int)($row['bookOrderNum'] ?? 0);
            $totalDetailNum = (int)($row['totalDetailNum'] ?? 0);

            $adr = $quantity > 0 ? round($amount / $quantity, 2) : 0.0;
            $ari = $circleAdr > 0 && $adr > 0 ? round($adr / $circleAdr * 100, 2) : 0.0;
            $sci = $ari > 0 ? round($ari * log(max(1, $quantity)), 2) : 0.0;
            $bookingRate = $totalDetailNum > 0 ? round($bookOrderNum / $totalDetailNum * 100, 2) : 0.0;

            $row['adr'] = $adr;
            $row['adrText'] = $quantity > 0 ? number_format($adr, 2, '.', '') : '-';
            $row['ari'] = $ari;
            $row['ariText'] = $ari > 0 ? number_format($ari, 1, '.', '') : '-';
            $row['sci'] = $sci;
            $row['sciText'] = $sci > 0 ? number_format($sci, 0, '.', '') : '-';
            $row['bookingRate'] = $bookingRate;
            $row['bookingRateText'] = $totalDetailNum > 0 ? number_format($bookingRate, 1, '.', '') . '%' : '-';
            $row['displayMetricStatus'] = [
                'adr' => $quantity > 0 ? 'ok' : 'missing_quantity',
                'ari' => $circleAdr > 0 && $adr > 0 ? 'ok' : ($circleAdr > 0 ? 'missing_adr' : 'missing_circle_adr'),
                'sci' => $sci > 0 ? 'ok' : 'missing_ari',
                'bookingRate' => $totalDetailNum > 0 ? 'ok' : 'missing_total_detail_num',
            ];
            $row['sourceLabel'] = '携程竞争圈返回';
            $row['sourceStatusText'] = '携程竞争圈返回';
            $row['metricSourceStatus'] = $this->buildCtripMetricSourceStatus($row);
        }
        unset($row);

        return $rows;
    }

    private function buildCtripMetricSourceStatus(array $row): array
    {
        $status = is_array($row['metricSourceStatus'] ?? null) ? $row['metricSourceStatus'] : [];
        foreach (array_keys($this->ctripBusinessMetricSourceKeyMap()) as $field) {
            if (!isset($status[$field])) {
                $status[$field] = (float)($row[$field] ?? 0) > 0 ? '携程竞争圈返回' : '系统未返回';
            }
        }
        $amountReturned = ($status['amount'] ?? '') === '携程竞争圈返回';
        $quantityReturned = ($status['quantity'] ?? '') === '携程竞争圈返回';
        $bookOrderReturned = ($status['bookOrderNum'] ?? '') === '携程竞争圈返回';
        $totalDetailReturned = ($status['totalDetailNum'] ?? '') === '携程竞争圈返回';
        $status['adr'] = $amountReturned && $quantityReturned ? '携程竞争圈返回' : '系统未返回';
        $status['ari'] = $status['adr'] === '携程竞争圈返回' ? '携程竞争圈返回' : '系统未返回';
        $status['sci'] = $status['ari'] === '携程竞争圈返回' ? '携程竞争圈返回' : '系统未返回';
        $status['bookingRate'] = $bookOrderReturned && $totalDetailReturned ? '携程竞争圈返回' : '系统未返回';
        return $status;
    }

    private function enrichMeituanBusinessDisplayMetrics(array $rows): array
    {
        foreach ($rows as &$row) {
            if (!$this->isMeituanBusinessDisplayRow($row)) {
                continue;
            }

            $roomNights = (float)($row['roomNights'] ?? 0);
            $roomRevenue = (float)($row['roomRevenue'] ?? 0);
            $salesRoomNights = (float)($row['salesRoomNights'] ?? 0);
            $sales = (float)($row['sales'] ?? 0);
            $exposure = (float)($row['exposure'] ?? 0);
            $views = (float)($row['views'] ?? 0);
            $viewConversion = (float)($row['viewConversion'] ?? 0);
            $payConversion = (float)($row['payConversion'] ?? 0);
            $metricSourceStatus = is_array($row['metricSourceStatus'] ?? null) ? $row['metricSourceStatus'] : [];
            $metricDerived = is_array($row['metricDerived'] ?? null) ? $row['metricDerived'] : [];

            $avgRoomPrice = $roomNights > 0 ? round($roomRevenue / $roomNights, 2) : 0.0;
            $avgSalesPrice = $salesRoomNights > 0 ? round($sales / $salesRoomNights, 2) : 0.0;
            $orderCount = (int)round((float)($row['orderCount'] ?? 0));
            if ($orderCount <= 0 && $views > 0 && $payConversion > 0) {
                $orderCount = (int)round($views * $payConversion);
            }
            if ($orderCount <= 0 && $salesRoomNights > 0 && $views > 0) {
                $orderCount = (int)round($salesRoomNights);
                $metricSourceStatus['orderCount'] = '按销售间夜代理估算';
                $metricDerived['orderCount'] = [
                    'method' => 'sales_room_nights_as_order_count_proxy',
                    'sales_room_nights' => $salesRoomNights,
                    'source_scope' => 'meituan_rank_percent_only',
                ];
            }
            if ($viewConversion <= 0 && $exposure > 0 && $views > 0) {
                $viewConversion = round($views / $exposure, 4);
                $metricSourceStatus['viewConversion'] = '按曝光和浏览估算';
                $metricDerived['viewConversion'] = [
                    'method' => 'views_div_exposure',
                    'views' => $views,
                    'exposure' => $exposure,
                    'source_scope' => 'meituan_rank_percent_only',
                ];
            }
            if ($payConversion <= 0 && $views > 0 && $orderCount > 0) {
                $payConversion = round($orderCount / $views, 4);
                $metricSourceStatus['payConversion'] = '按订单量和浏览估算';
                $metricDerived['payConversion'] = [
                    'method' => 'order_count_div_views',
                    'order_count' => $orderCount,
                    'views' => $views,
                    'order_count_source' => (string)($metricDerived['orderCount']['method'] ?? 'display_order_count'),
                    'source_scope' => 'meituan_rank_percent_only',
                ];
            }
            $absoluteConversion = (float)($row['absoluteConversion'] ?? 0);
            if ($absoluteConversion <= 0 && $viewConversion > 0 && $payConversion > 0) {
                $absoluteConversion = round($viewConversion * $payConversion, 4);
                if (isset($metricDerived['viewConversion']) || isset($metricDerived['payConversion'])) {
                    $metricSourceStatus['absoluteConversion'] = '按浏览转化和支付转化估算';
                    $metricDerived['absoluteConversion'] = [
                        'method' => 'view_conversion_times_pay_conversion',
                        'view_conversion' => $viewConversion,
                        'pay_conversion' => $payConversion,
                        'source_scope' => 'meituan_rank_percent_only',
                    ];
                }
            } elseif ($absoluteConversion <= 0 && $exposure > 0 && $orderCount > 0) {
                $absoluteConversion = round($orderCount / $exposure, 4);
                $metricSourceStatus['absoluteConversion'] = '按订单量和曝光估算';
                $metricDerived['absoluteConversion'] = [
                    'method' => 'order_count_div_exposure',
                    'order_count' => $orderCount,
                    'exposure' => $exposure,
                    'order_count_source' => (string)($metricDerived['orderCount']['method'] ?? 'display_order_count'),
                    'source_scope' => 'meituan_rank_percent_only',
                ];
            }
            $rankSummary = $this->summarizeMeituanRankHistory(is_array($row['rankHistory'] ?? null) ? $row['rankHistory'] : [], (int)($row['rank'] ?? 0));
            $platformTags = is_array($row['platformTags'] ?? null) ? $this->mergeStringList([], $row['platformTags']) : [];
            $hasVipTag = $this->hasMeituanVipPlatformTag($platformTags);

            $row['avgRoomPrice'] = $avgRoomPrice;
            $row['avgRoomPriceText'] = $avgRoomPrice > 0 ? number_format($avgRoomPrice, 0, '.', ',') : '-';
            $row['avgSalesPrice'] = $avgSalesPrice;
            $row['avgSalesPriceText'] = $avgSalesPrice > 0 ? number_format($avgSalesPrice, 0, '.', ',') : '-';
            $row['orderCount'] = $orderCount;
            $row['orderCountText'] = $orderCount > 0 ? number_format($orderCount) : '-';
            $row['viewConversion'] = $viewConversion;
            $row['payConversion'] = $payConversion;
            $row['absoluteConversion'] = $absoluteConversion;
            $row['absoluteConversionText'] = $absoluteConversion > 0 ? number_format($absoluteConversion * 100, 2, '.', '') . '%' : '-';
            $row['viewConversionText'] = $viewConversion > 0 ? number_format($viewConversion * 100, 2, '.', '') . '%' : '-';
            $row['payConversionText'] = $payConversion > 0 ? number_format($payConversion * 100, 2, '.', '') . '%' : '-';
            $row['metricSourceStatus'] = $metricSourceStatus;
            $row['metricDerived'] = $metricDerived;
            $row['platformTags'] = $platformTags;
            $row['platformTagText'] = !empty($platformTags) ? implode(' / ', $platformTags) : '未返回';
            $row['platformTagSourceText'] = !empty($platformTags)
                ? '美团榜单返回'
                : (($row['platformTagStatus'] ?? '') === 'returned_empty' ? '平台返回空标签' : '系统未返回');
            $row['hasVipTag'] = $hasVipTag;
            $row['rankByRange'] = $rankSummary['rankByRange'];
            $row['rankSummaryText'] = $rankSummary['rankSummaryText'];
            $row['rankTrendText'] = $rankSummary['rankTrendText'];
            $row['rankTrendClass'] = $rankSummary['rankTrendClass'];
            $row['currentPlatformRank'] = $rankSummary['currentRank'];
            $row['previousPlatformRank'] = $rankSummary['previousRank'];
            $row['rank30Best'] = $rankSummary['rank30Best'];
            $row['rank30Worst'] = $rankSummary['rank30Worst'];
            $row['rank30RangeText'] = $rankSummary['rank30RangeText'];
            $row['sourceStatusText'] = '美团榜单返回';
            $row['metricHealth'] = $this->buildMeituanMetricHealthRows($row, $metricSourceStatus);
            $row['displayMetricStatus'] = [
                'avgRoomPrice' => $roomNights > 0 ? 'ok' : 'missing_room_nights',
                'avgSalesPrice' => $salesRoomNights > 0 ? 'ok' : 'missing_sales_room_nights',
                'orderCount' => $orderCount > 0 ? 'ok' : 'missing_views_or_pay_conversion',
                'absoluteConversion' => $absoluteConversion > 0 ? 'ok' : 'missing_conversion',
            ];
        }
        unset($row);

        return $rows;
    }

    private function summarizeMeituanRankHistory(array $history, int $fallbackRank = 0): array
    {
        $rankByRange = [];
        $thirtyDayRanks = [];
        foreach ($history as $entry) {
            if (!is_array($entry)) {
                continue;
            }
            $rank = (int)($entry['rank'] ?? 0);
            if ($rank <= 0) {
                continue;
            }
            $range = (string)($entry['dateRange'] ?? '');
            if ($range === '') {
                $range = 'unknown';
            }
            $rangeLabel = (string)($entry['dateRangeLabel'] ?? '');
            if ($range === '30' || str_contains($range, '30') || str_contains($rangeLabel, '30')) {
                $thirtyDayRanks[] = $rank;
            }
            if (!isset($rankByRange[$range]) || $rank < (int)$rankByRange[$range]['rank']) {
                $rankByRange[$range] = [
                    'rank' => $rank,
                    'label' => $entry['dateRangeLabel'] ?? $this->meituanDateRangeLabel($range),
                    'rankType' => $entry['rankType'] ?? '',
                    'rankTypeLabel' => $entry['rankTypeLabel'] ?? '',
                    'metricLabel' => $entry['metricLabel'] ?? '',
                    'sourceLabel' => $entry['sourceLabel'] ?? '美团榜单返回',
                ];
            }
        }
        if (empty($rankByRange) && $fallbackRank > 0) {
            $rankByRange['unknown'] = [
                'rank' => $fallbackRank,
                'label' => '未标明时间',
                'rankType' => '',
                'rankTypeLabel' => '',
                'metricLabel' => '平台排名',
                'sourceLabel' => '美团榜单返回',
            ];
        }

        $currentRange = null;
        foreach (['0', '1', '7', '30', 'custom', 'unknown'] as $range) {
            if (isset($rankByRange[$range])) {
                $currentRange = $range;
                break;
            }
        }
        $previousRange = null;
        foreach ($currentRange === '0' ? ['1', '7', '30'] : ($currentRange === '1' ? ['7', '30'] : ['30', 'unknown']) as $range) {
            if (isset($rankByRange[$range])) {
                $previousRange = $range;
                break;
            }
        }

        $currentRank = $currentRange !== null ? (int)$rankByRange[$currentRange]['rank'] : 0;
        $previousRank = $previousRange !== null ? (int)$rankByRange[$previousRange]['rank'] : 0;
        $rankParts = [];
        foreach (['0', '1', '7', '30', 'custom', 'unknown'] as $range) {
            if (isset($rankByRange[$range])) {
                $rankParts[] = $rankByRange[$range]['label'] . '第' . $rankByRange[$range]['rank'];
            }
        }

        $trendText = '暂无变化';
        $trendClass = 'text-gray-500';
        if ($currentRank > 0 && $previousRank > 0) {
            if ($previousRank <= 10 && $currentRank > 10) {
                $trendText = '掉出前10';
                $trendClass = 'text-red-600';
            } elseif ($previousRank > 10 && $currentRank <= 10) {
                $trendText = '进入前10';
                $trendClass = 'text-emerald-600';
            } elseif ($currentRank < $previousRank) {
                $trendText = '上升' . ($previousRank - $currentRank) . '名';
                $trendClass = 'text-emerald-600';
            } elseif ($currentRank > $previousRank) {
                $trendText = '下降' . ($currentRank - $previousRank) . '名';
                $trendClass = 'text-red-600';
            } else {
                $trendText = '排名持平';
                $trendClass = 'text-gray-600';
            }
        }

        $rank30Best = count($thirtyDayRanks) > 0 ? min($thirtyDayRanks) : 0;
        $rank30Worst = count($thirtyDayRanks) > 0 ? max($thirtyDayRanks) : 0;
        $rank30RangeText = '近30天未返回';
        if ($rank30Best > 0 && $rank30Worst > 0) {
            $rank30RangeText = $rank30Best === $rank30Worst
                ? '近30天第 ' . $rank30Best
                : '近30天最好第 ' . $rank30Best . ' / 最差第 ' . $rank30Worst;
        }

        return [
            'rankByRange' => $rankByRange,
            'rankSummaryText' => !empty($rankParts) ? implode(' / ', $rankParts) : '平台未返回排名',
            'rankTrendText' => $trendText,
            'rankTrendClass' => $trendClass,
            'currentRank' => $currentRank,
            'previousRank' => $previousRank,
            'rank30Best' => $rank30Best,
            'rank30Worst' => $rank30Worst,
            'rank30RangeText' => $rank30RangeText,
        ];
    }

    private function buildMeituanMetricHealthRows(array $row, array $metricSourceStatus): array
    {
        $groups = [
            ['key' => 'stay', 'label' => '入住榜', 'fields' => ['roomNights', 'roomRevenue']],
            ['key' => 'sales', 'label' => '销售榜', 'fields' => ['salesRoomNights', 'sales']],
            ['key' => 'traffic', 'label' => '流量榜', 'fields' => ['exposure', 'views']],
            ['key' => 'conversion', 'label' => '转化榜', 'fields' => ['viewConversion', 'payConversion']],
        ];
        $rows = [];
        foreach ($groups as $group) {
            $returned = 0;
            foreach ($group['fields'] as $field) {
                $status = (string)($metricSourceStatus[$field] ?? '');
                if ((float)($row[$field] ?? 0) > 0 || $this->isMeituanMetricSourceUsable($status)) {
                    $returned++;
                }
            }
            $rows[] = [
                'key' => $group['key'],
                'label' => $group['label'],
                'status' => $returned === count($group['fields']) ? 'ok' : ($returned > 0 ? 'partial' : 'missing'),
                'statusText' => $returned === count($group['fields']) ? '已返回' : ($returned > 0 ? '部分返回' : '未返回'),
                'sourceLabel' => $returned > 0 ? '美团榜单返回' : '系统未返回',
            ];
        }
        return $rows;
    }

    private function finalizeMeituanBusinessDisplayRows(array $rows, string $sortField): array
    {
        $total = count($rows);
        foreach ($rows as $index => &$row) {
            if (!$this->isMeituanBusinessDisplayRow($row)) {
                continue;
            }
            $rank = (int)($row['currentPlatformRank'] ?? $row['rank'] ?? 0);
            $row['circlePositionText'] = $rank > 0
                ? ($rank <= $total ? '第 ' . $rank . ' / ' . $total . ' 名' : '第 ' . $rank . ' 名（本次返回' . $total . '家）')
                : '平台未返回';
            $prev = $rows[$index - 1] ?? null;
            $next = $rows[$index + 1] ?? null;
            $value = (float)($row[$sortField] ?? 0);
            $prevValue = is_array($prev) ? (float)($prev[$sortField] ?? 0) : 0.0;
            $nextValue = is_array($next) ? (float)($next[$sortField] ?? 0) : 0.0;
            $row['gapMetric'] = $sortField;
            $row['gapMetricLabel'] = $this->meituanDisplayMetricLabel($sortField);
            $row['gapToPrev'] = is_array($prev) ? round(max(0, $prevValue - $value), 2) : 0.0;
            $row['gapToNext'] = is_array($next) ? round(max(0, $value - $nextValue), 2) : 0.0;
            $row['gapToPrevText'] = is_array($prev)
                ? '距前一名 ' . $this->formatMeituanGapValue($row['gapToPrev'], $sortField)
                : '当前表内领先';
            $row['gapToNextText'] = is_array($next)
                ? '领先后一名 ' . $this->formatMeituanGapValue($row['gapToNext'], $sortField)
                : '尾部酒店';
            $leaderValue = isset($rows[0]) && is_array($rows[0]) ? (float)($rows[0][$sortField] ?? 0) : 0.0;
            $row['gapToLeader'] = round(max(0, $leaderValue - $value), 2);
            $row['gapToLeaderText'] = $index === 0 ? '当前TOP1' : '距TOP1 ' . $this->formatMeituanGapValue($row['gapToLeader'], $sortField);
            $row['rankGapSummaryText'] = implode(' / ', array_values(array_filter([
                (string)($row['gapToPrevText'] ?? ''),
                (string)($row['gapToLeaderText'] ?? ''),
                (string)($row['rank30RangeText'] ?? ''),
            ])));
        }
        unset($row);

        return $rows;
    }

    private function meituanDisplayMetricLabel(string $field): string
    {
        return [
            'roomNights' => '入住间夜',
            'roomRevenue' => '房费收入',
            'salesRoomNights' => '销售间夜',
            'sales' => '销售额',
            'exposure' => '曝光',
            'views' => '浏览',
        ][$field] ?? $field;
    }

    private function formatMeituanGapValue(float $value, string $field): string
    {
        if (in_array($field, ['roomRevenue', 'sales'], true)) {
            return '¥' . number_format((float)round($value));
        }
        return number_format((float)round($value));
    }

    private function findMeituanSelfDisplayRow(array $rows): ?array
    {
        foreach ($rows as $row) {
            if (is_array($row) && !empty($row['isSelf'])) {
                return $row;
            }
        }
        return null;
    }

    private function buildMeituanFunnelDiagnosisCard(array $rows, ?array $selfRow): array
    {
        if ($selfRow === null) {
            return [
                'key' => 'funnel-diagnosis',
                'label' => '四榜卡点',
                'value' => '本店未返回',
                'note' => '目标 POI 未出现在本次榜单，暂不生成卡点判断',
                'className' => 'bg-gray-50 text-gray-500 border-gray-200',
                'details' => [],
                'missing' => ['本店榜单行未返回'],
            ];
        }

        $checks = [
            ['key' => 'exposure', 'label' => '曝光', 'field' => 'exposure', 'threshold' => 0.85, 'action' => '补曝光'],
            ['key' => 'views', 'label' => '浏览', 'field' => 'views', 'threshold' => 0.85, 'action' => '提点击'],
            ['key' => 'conversion', 'label' => '转化', 'field' => 'payConversion', 'threshold' => 0.90, 'action' => '查转化'],
            ['key' => 'avgSalesPrice', 'label' => '客单', 'field' => 'avgSalesPrice', 'threshold' => 0.90, 'action' => '提客单'],
            ['key' => 'sales', 'label' => '收入', 'field' => 'sales', 'threshold' => 0.85, 'action' => '补收入'],
        ];

        $issues = [];
        $missing = [];
        foreach ($checks as $check) {
            $field = (string)$check['field'];
            $selfValue = (float)($selfRow[$field] ?? 0);
            $benchmark = $this->avgBusinessRows($rows, $field);
            if ($selfValue <= 0 || $benchmark <= 0) {
                $missing[] = $check['label'] . '未返回';
                continue;
            }
            if ($selfValue < $benchmark * (float)$check['threshold']) {
                $issues[] = [
                    'key' => (string)$check['key'],
                    'label' => $check['label'] . '低',
                    'action' => (string)$check['action'],
                    'value' => $this->formatMeituanDiagnosticValue($selfValue, $field),
                    'benchmark' => '圈内均值 ' . $this->formatMeituanDiagnosticValue($benchmark, $field),
                ];
            }
        }

        if (!empty($issues)) {
            $primary = $issues[0];
            $noteParts = array_map(
                static fn(array $issue): string => $issue['label'] . '：' . $issue['value'] . '，' . $issue['benchmark'],
                array_slice($issues, 0, 3)
            );
            return [
                'key' => 'funnel-diagnosis',
                'label' => '四榜卡点',
                'value' => (string)$primary['action'] . (count($issues) > 1 ? ' +' . (count($issues) - 1) : ''),
                'note' => implode('；', $noteParts),
                'className' => 'bg-rose-50 text-rose-700 border-rose-100',
                'details' => $issues,
                'missing' => $missing,
            ];
        }

        return [
            'key' => 'funnel-diagnosis',
            'label' => '四榜卡点',
            'value' => '暂无明显卡点',
            'note' => !empty($missing) ? ('部分字段未返回：' . implode('、', array_slice($missing, 0, 3))) : '曝光、浏览、转化、客单、收入未明显低于圈内均值',
            'className' => !empty($missing) ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-emerald-50 text-emerald-700 border-emerald-100',
            'details' => [],
            'missing' => $missing,
        ];
    }

    private function formatMeituanDiagnosticValue(float $value, string $field): string
    {
        if (in_array($field, ['payConversion', 'viewConversion', 'absoluteConversion'], true)) {
            return number_format($value * 100, 2, '.', '') . '%';
        }
        if (in_array($field, ['roomRevenue', 'sales', 'avgRoomPrice', 'avgSalesPrice'], true)) {
            return '¥' . number_format((float)round($value));
        }
        return number_format((float)round($value));
    }

    private function buildMeituanBusinessDisplaySummary(array $rows, array $context = []): array
    {
        $rows = array_values(array_filter($this->enrichMeituanBusinessDisplayMetrics($rows), fn($row): bool => is_array($row) && $this->isMeituanBusinessDisplayRow($row)));
        if (empty($rows)) {
            return $this->emptyMeituanBusinessDisplaySummary();
        }

        $hotelCount = count($rows);
        $totalRoomNights = $this->sumBusinessRows($rows, 'roomNights');
        $totalRoomRevenue = $this->sumBusinessRows($rows, 'roomRevenue');
        $totalSalesRoomNights = $this->sumBusinessRows($rows, 'salesRoomNights');
        $totalSales = $this->sumBusinessRows($rows, 'sales');
        $totalExposure = $this->sumBusinessRows($rows, 'exposure');
        $totalViews = $this->sumBusinessRows($rows, 'views');
        $totalOrderCount = (int)$this->sumBusinessRows($rows, 'orderCount');
        $avgRoomPrice = $totalRoomNights > 0 ? round($totalRoomRevenue / $totalRoomNights, 2) : 0.0;
        $avgSalesPrice = $totalSalesRoomNights > 0 ? round($totalSales / $totalSalesRoomNights, 2) : 0.0;
        $avgViewConversionRate = $this->avgBusinessRows($rows, 'viewConversion') * 100;
        $avgPayConversionRate = $this->avgBusinessRows($rows, 'payConversion') * 100;
        $avgAbsoluteConversionRate = $this->avgBusinessRows($rows, 'absoluteConversion') * 100;
        $hasViewConversionValue = $this->hasPositiveBusinessRows($rows, 'viewConversion');
        $hasPayConversionValue = $this->hasPositiveBusinessRows($rows, 'payConversion');
        $hasAbsoluteConversionValue = $this->hasPositiveBusinessRows($rows, 'absoluteConversion');
        $revenueHhi = $this->hhiBusinessRows($rows, 'sales');
        $visitHhi = $this->hhiBusinessRows($rows, 'views');
        $operationFocus = $revenueHhi > 0 && $visitHhi > 0 && $revenueHhi - $visitHhi > 0 ? '提高转化率' : ($revenueHhi > 0 && $visitHhi > 0 ? '抢夺流量' : '-');
        $marketInventory = $this->meituanBusinessMarketInventory($context);
        $marketVitalityRate = $marketInventory > 0 ? round($totalRoomNights / $marketInventory * 100, 2) : 0.0;
        $priceSigma = $this->meituanBusinessPriceSigma($rows);
        $marketPriceSignal = $this->meituanBusinessMarketPriceSignal($avgRoomPrice, $avgSalesPrice);
        $inventoryTurnoverRate = $totalRoomNights > 0 ? round($totalSalesRoomNights / $totalRoomNights * 100, 2) : 0.0;
        $rankHealthRows = $this->buildMeituanRankHealthRows($rows);
        $selfRow = $this->findMeituanSelfDisplayRow($rows);
        $funnelDiagnosis = $this->buildMeituanFunnelDiagnosisCard($rows, $selfRow);
        $rankInsights = $this->buildMeituanRankInsightCards($rows, $rankHealthRows, $funnelDiagnosis);
        $topSummaryRows = $this->buildMeituanTopSummaryRows($rows);
        $vipTaggedCount = count(array_filter($rows, static fn($row): bool => !empty($row['hasVipTag'])));
        $platformTagReturnedCount = count(array_filter($rows, static fn($row): bool => !empty($row['platformTags'])));
        $platformTagSummary = $this->buildMeituanPlatformTagSummary($rows);
        $derivedMetricCount = $this->countMeituanDerivedMetrics($rows);
        $sourceNotice = $derivedMetricCount > 0
            ? '美团榜单部分指标仅返回百分比；已优先按本店真实值 × 对方 percent ÷ 本店 percent 推导，缺少本店真实值时按百分比序列的最小一致整数比例尺估算，并在 metricDerived 中保留依据。未返回且不可推导字段继续保留缺失状态。'
            : '仅展示美团榜单已返回字段；不通过订单、客人、房态或房源映射推断。';
        $selfPositionText = $selfRow ? (string)($selfRow['circlePositionText'] ?? '已返回') : '本店未返回';

        return [
            'status' => 'success',
            'metrics' => [
                'hotelCount' => $hotelCount,
                'rankHealthReadyCount' => count(array_filter($rankHealthRows, static fn($row): bool => ($row['status'] ?? '') === 'ok')),
                'rankHealthTotalCount' => count($rankHealthRows),
                'vipTaggedCount' => $vipTaggedCount,
                'platformTagReturnedCount' => $platformTagReturnedCount,
                'selfPositionText' => $selfPositionText,
                'marketInventory' => $marketInventory,
                'marketVitalityRate' => $marketVitalityRate,
                'priceSigma' => $priceSigma,
                'marketPriceSignal' => $marketPriceSignal,
                'inventoryTurnoverRate' => $inventoryTurnoverRate,
                'revenueConcentration' => $revenueHhi,
                'visitConcentration' => $visitHhi,
                'operationFocus' => $operationFocus,
                'totalRoomNights' => round($totalRoomNights, 2),
                'totalRoomRevenue' => round($totalRoomRevenue, 2),
                'totalSalesRoomNights' => round($totalSalesRoomNights, 2),
                'totalSales' => round($totalSales, 2),
                'totalExposure' => round($totalExposure, 2),
                'totalViews' => round($totalViews, 2),
                'totalOrderCount' => $totalOrderCount,
                'avgRoomPrice' => $avgRoomPrice,
                'avgSalesPrice' => $avgSalesPrice,
                'avgViewConversionRate' => round($avgViewConversionRate, 2),
                'avgPayConversionRate' => round($avgPayConversionRate, 2),
                'avgAbsoluteConversionRate' => round($avgAbsoluteConversionRate, 2),
                'funnelDiagnosisValue' => (string)($funnelDiagnosis['value'] ?? '未生成'),
                'funnelDiagnosisIssueCount' => count($funnelDiagnosis['details'] ?? []),
                'derivedMetricCount' => $derivedMetricCount,
            ],
            'cards' => [
                $this->businessSummaryCard('hotelCount', '酒店总数', number_format($hotelCount), 'text-gray-700', 'bg-blue-50 border border-blue-200'),
                $this->businessSummaryCard('rankHealth', '榜单健康度', count(array_filter($rankHealthRows, static fn($row): bool => ($row['status'] ?? '') === 'ok')) . '/' . count($rankHealthRows), 'text-blue-600', 'bg-blue-50 border border-blue-200'),
                $this->businessSummaryCard('selfPosition', '本店圈内位置', $selfPositionText, $selfRow ? 'text-emerald-600' : 'text-gray-500', 'bg-emerald-50 border border-emerald-200'),
                $this->businessSummaryCard('platformVipTags', 'VIP竞对标签', $platformTagReturnedCount > 0 ? ('VIP ' . number_format($vipTaggedCount) . '家') : '未返回', $vipTaggedCount > 0 ? 'text-orange-600' : 'text-gray-500', 'bg-orange-50 border border-orange-200'),
                $this->businessSummaryCard('marketInventory', '市场总库存', $marketInventory > 0 ? number_format($marketInventory) : '-', 'text-indigo-600', 'bg-indigo-50 border border-indigo-200'),
                $this->businessSummaryCard('marketVitalityRate', '市场活力', $marketVitalityRate > 0 ? number_format($marketVitalityRate, 2, '.', '') . '%' : '-', 'text-blue-600', 'bg-blue-50 border border-blue-200', $this->meituanBusinessVitalityLevel($marketVitalityRate)),
                $this->businessSummaryCard('priceSigma', '竞争健康度', $priceSigma > 0 ? number_format($priceSigma, 2, '.', '') . '%' : '-', 'text-orange-600', 'bg-orange-50 border border-orange-200', $this->meituanBusinessPriceSigmaLevel($priceSigma)),
                $this->businessSummaryCard('marketPriceSignal', '市场价格预估', $marketPriceSignal, 'text-blue-600', 'bg-blue-50 border border-blue-200'),
                $this->businessSummaryCard('inventoryTurnoverRate', '库存周转率', $inventoryTurnoverRate > 0 ? number_format($inventoryTurnoverRate, 2, '.', '') . '%' : '-', 'text-cyan-600', 'bg-cyan-50 border border-cyan-200'),
                $this->businessSummaryCard('revenueConcentration', '收益集中度', $revenueHhi > 0 ? number_format($revenueHhi, 2, '.', '') : '-', 'text-orange-600', 'bg-orange-50 border border-orange-200'),
                $this->businessSummaryCard('visitConcentration', '浏览/访客集中度', $visitHhi > 0 ? number_format($visitHhi, 2, '.', '') : '-', 'text-orange-600', 'bg-orange-50 border border-orange-200'),
                $this->businessSummaryCard('operationFocus', '运营重心', $operationFocus, 'text-indigo-600', 'bg-indigo-50 border border-indigo-200'),
                $this->businessSummaryCard('totalRoomNights', '总入住间夜', number_format($totalRoomNights), 'text-red-600', 'bg-red-50 border border-red-200'),
                $this->businessSummaryCard('totalRoomRevenue', '总房费收入', '楼' . number_format((float)floor($totalRoomRevenue)), 'text-red-600', 'bg-red-50 border border-red-200'),
                $this->businessSummaryCard('totalSalesRoomNights', '总销售间夜', number_format($totalSalesRoomNights), 'text-green-600', 'bg-green-50 border border-green-200'),
                $this->businessSummaryCard('totalSales', '总销售额', '楼' . number_format((float)floor($totalSales)), 'text-green-600', 'bg-green-50 border border-green-200'),
                $this->businessSummaryCard('totalExposure', '总曝光量', number_format($totalExposure), 'text-blue-600', 'bg-blue-50 border border-blue-200'),
                $this->businessSummaryCard('totalViews', '总浏览量', number_format($totalViews), 'text-blue-600', 'bg-blue-50 border border-blue-200'),
                $this->businessSummaryCard('totalOrderCount', '总订单量', number_format($totalOrderCount), 'text-blue-600', 'bg-blue-50 border border-blue-200'),
                $this->businessSummaryCard('avgViewConversionRate', '平均浏览转化率', $hasViewConversionValue ? number_format($avgViewConversionRate, 2, '.', '') . '%' : '-', 'text-purple-600', 'bg-purple-50 border border-purple-200'),
                $this->businessSummaryCard('avgPayConversionRate', '平均支付转化率', $hasPayConversionValue ? number_format($avgPayConversionRate, 2, '.', '') . '%' : '-', 'text-purple-600', 'bg-purple-50 border border-purple-200'),
                $this->businessSummaryCard('avgAbsoluteConversionRate', '绝对转化率', $hasAbsoluteConversionValue ? number_format($avgAbsoluteConversionRate, 2, '.', '') . '%' : '-', 'text-purple-600', 'bg-purple-50 border border-purple-200'),
            ],
            'rank_insights' => $rankInsights,
            'rank_health_rows' => $rankHealthRows,
            'top_summary_rows' => $topSummaryRows,
            'funnel_diagnosis' => $funnelDiagnosis,
            'platform_tag_summary' => $platformTagSummary,
            'source_notice' => $sourceNotice,
        ];
    }

    private function countMeituanDerivedMetrics(array $rows): int
    {
        $count = 0;
        foreach ($rows as $row) {
            if (!is_array($row) || !is_array($row['metricDerived'] ?? null)) {
                continue;
            }
            $count += count($row['metricDerived']);
        }
        return $count;
    }

    private function buildMeituanPlatformTagSummary(array $rows): array
    {
        $tagCounts = [];
        $returnedCount = 0;
        $returnedEmptyCount = 0;
        $notReturnedCount = 0;
        $vipCount = 0;

        foreach ($rows as $row) {
            if (!is_array($row)) {
                continue;
            }
            $tags = is_array($row['platformTags'] ?? null) ? $this->mergeStringList([], $row['platformTags']) : [];
            if (!empty($tags)) {
                $returnedCount++;
                if ($this->hasMeituanVipPlatformTag($tags)) {
                    $vipCount++;
                }
                foreach ($tags as $tag) {
                    $tagCounts[$tag] = ($tagCounts[$tag] ?? 0) + 1;
                }
                continue;
            }

            if (($row['platformTagStatus'] ?? '') === 'returned_empty') {
                $returnedEmptyCount++;
            } else {
                $notReturnedCount++;
            }
        }

        arsort($tagCounts);
        $tags = [];
        foreach ($tagCounts as $tag => $count) {
            $tags[] = ['tag' => (string)$tag, 'count' => (int)$count];
        }

        return [
            'status' => $returnedCount > 0 ? 'returned' : ($returnedEmptyCount > 0 ? 'returned_empty' : 'not_returned'),
            'returned_count' => $returnedCount,
            'vip_count' => $vipCount,
            'returned_empty_count' => $returnedEmptyCount,
            'not_returned_count' => $notReturnedCount,
            'tag_count' => count($tagCounts),
            'tags' => array_slice($tags, 0, 20),
            'source_fields' => ['platformTags', 'platformTagStatus', 'isVip', 'vipFlag', 'memberFlag', 'crownTag'],
            'storage_fields' => [
                'online_daily_data.raw_data.platformTags',
                'online_daily_data.raw_data.platformTagStatus',
                'online_daily_data.raw_data.platformTagText',
                'online_daily_data.raw_data.hasVipTag',
            ],
            'privacy_scope' => '平台门店标签；不包含客人、订单手机号、房态或房源映射',
        ];
    }

    private function buildMeituanRankHealthRows(array $rows): array
    {
        $rankTypes = [
            'P_RZ' => '入住榜',
            'P_XS' => '销售榜',
            'P_LL' => '流量榜',
            'P_ZH' => '转化榜',
        ];
        $seen = [];
        foreach ($rows as $row) {
            foreach ((array)($row['rankHistory'] ?? []) as $entry) {
                if (!is_array($entry)) {
                    continue;
                }
                $rankType = (string)($entry['rankType'] ?? '');
                if ($rankType !== '') {
                    $seen[$rankType] = true;
                }
            }
        }
        $result = [];
        foreach ($rankTypes as $rankType => $label) {
            $ok = !empty($seen[$rankType]);
            $result[] = [
                'key' => $rankType,
                'label' => $label,
                'status' => $ok ? 'ok' : 'missing',
                'statusText' => $ok ? '已返回' : '未返回',
                'sourceLabel' => $ok ? '美团榜单返回' : '系统未返回',
                'className' => $ok ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-gray-50 text-gray-500 border-gray-200',
            ];
        }
        return $result;
    }

    private function buildMeituanRankInsightCards(array $rows, array $rankHealthRows, array $funnelDiagnosis = []): array
    {
        $hotelCount = count($rows);
        $healthReady = count(array_filter($rankHealthRows, static fn($row): bool => ($row['status'] ?? '') === 'ok'));
        $vipTaggedCount = count(array_filter($rows, static fn($row): bool => !empty($row['hasVipTag'])));
        $tagReturnedCount = count(array_filter($rows, static fn($row): bool => !empty($row['platformTags'])));
        $selfRow = $this->findMeituanSelfDisplayRow($rows);
        $top = $rows[0] ?? null;
        $conversionRiskRows = array_values(array_filter($rows, static function ($row): bool {
            $views = (float)($row['views'] ?? 0);
            $payConversion = (float)($row['payConversion'] ?? 0);
            return $views > 0 && $payConversion > 0 && $payConversion < 0.05;
        }));
        $positiveExposureRows = array_values(array_filter($rows, static fn($row): bool => (float)($row['exposure'] ?? 0) > 0));
        $positivePayConversionRows = array_values(array_filter($rows, static fn($row): bool => (float)($row['payConversion'] ?? 0) > 0));
        $avgExposure = count($positiveExposureRows) > 0 ? array_sum(array_map(static fn($row): float => (float)($row['exposure'] ?? 0), $positiveExposureRows)) / count($positiveExposureRows) : 0.0;
        $avgPayConversion = count($positivePayConversionRows) > 0 ? array_sum(array_map(static fn($row): float => (float)($row['payConversion'] ?? 0), $positivePayConversionRows)) / count($positivePayConversionRows) : 0.0;
        $vipExposureLowConversionRows = array_values(array_filter($rows, static function ($row) use ($avgExposure, $avgPayConversion): bool {
            return !empty($row['hasVipTag'])
                && $avgExposure > 0
                && $avgPayConversion > 0
                && (float)($row['exposure'] ?? 0) >= $avgExposure
                && (float)($row['payConversion'] ?? 0) < $avgPayConversion;
        }));
        $nonVipSalesOverSelfRows = [];
        if (is_array($selfRow)) {
            $selfSales = (float)($selfRow['sales'] ?? 0);
            if ($selfSales > 0) {
                $nonVipSalesOverSelfRows = array_values(array_filter($rows, static function ($row) use ($selfSales): bool {
                    return empty($row['hasVipTag']) && (float)($row['sales'] ?? 0) > $selfSales;
                }));
            }
        }
        if (count($vipExposureLowConversionRows) > 0) {
            $tagMetricValue = 'VIP转化低 ' . count($vipExposureLowConversionRows) . '家';
            $tagMetricNote = (string)($vipExposureLowConversionRows[0]['hotelName'] ?? 'VIP竞对') . '曝光高于圈内均值但支付转化低于均值';
            $tagMetricClass = 'bg-rose-50 text-rose-700 border-rose-100';
        } elseif (count($nonVipSalesOverSelfRows) > 0) {
            $tagMetricValue = '非VIP超过本店';
            $tagMetricNote = (string)($nonVipSalesOverSelfRows[0]['hotelName'] ?? '非VIP竞对') . '销售额超过本店，优先看价格与转化差距';
            $tagMetricClass = 'bg-amber-50 text-amber-700 border-amber-100';
        } elseif ($tagReturnedCount > 0) {
            $tagMetricValue = '可联动分析';
            $tagMetricNote = '平台标签已返回，可与曝光、销售额、支付转化一起判断权益影响';
            $tagMetricClass = 'bg-blue-50 text-blue-700 border-blue-100';
        } else {
            $tagMetricValue = '未返回';
            $tagMetricNote = '平台未返回标签，不判断 VIP、皇冠或权益造成的差距';
            $tagMetricClass = 'bg-gray-50 text-gray-500 border-gray-200';
        }

        return [
            [
                'key' => 'rank-health',
                'label' => '榜单健康度',
                'value' => $healthReady . '/' . count($rankHealthRows),
                'note' => $healthReady === count($rankHealthRows) ? '四类榜单均有返回' : '存在未返回榜单，保留缺失状态',
                'className' => $healthReady === count($rankHealthRows) ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-amber-50 text-amber-700 border-amber-100',
            ],
            [
                'key' => 'self-position',
                'label' => '本店位置',
                'value' => $selfRow ? (string)($selfRow['circlePositionText'] ?? '已返回') : '未返回',
                'note' => $selfRow ? (string)($selfRow['gapToLeaderText'] ?? '可对比TOP1') : '目标 POI 未出现在本次榜单',
                'className' => $selfRow ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-gray-50 text-gray-500 border-gray-200',
            ],
            [
                'key' => 'rank-gap',
                'label' => '排名差距',
                'value' => $selfRow ? (string)($selfRow['gapToPrevText'] ?? '已返回') : '未返回',
                'note' => $selfRow ? (string)($selfRow['rankGapSummaryText'] ?? $selfRow['rank30RangeText'] ?? '近30天未返回') : '目标 POI 未出现在本次榜单',
                'className' => $selfRow ? 'bg-cyan-50 text-cyan-700 border-cyan-100' : 'bg-gray-50 text-gray-500 border-gray-200',
            ],
            !empty($funnelDiagnosis) ? $funnelDiagnosis : [
                'key' => 'funnel-diagnosis',
                'label' => '四榜卡点',
                'value' => '未生成',
                'note' => '缺少本店或榜单字段，暂不生成卡点判断',
                'className' => 'bg-gray-50 text-gray-500 border-gray-200',
            ],
            [
                'key' => 'platform-tags',
                'label' => '平台标签',
                'value' => $tagReturnedCount > 0 ? ('VIP ' . $vipTaggedCount . '家') : '未返回',
                'note' => $tagReturnedCount > 0 ? "共{$tagReturnedCount}/{$hotelCount}家返回平台标签" : '不猜测 VIP、皇冠或权益标签',
                'className' => $tagReturnedCount > 0 ? 'bg-orange-50 text-orange-700 border-orange-100' : 'bg-gray-50 text-gray-500 border-gray-200',
            ],
            [
                'key' => 'tag-metric-link',
                'label' => '标签指标联动',
                'value' => $tagMetricValue,
                'note' => $tagMetricNote,
                'className' => $tagMetricClass,
            ],
            [
                'key' => 'top-summary',
                'label' => 'TOP1',
                'value' => is_array($top) ? (string)($top['hotelName'] ?? '-') : '-',
                'note' => is_array($top) ? ((string)($top['roomNights'] ?? 0) . ' 间夜 · ' . (string)($top['gapToNextText'] ?? '暂无后一名差距')) : '暂无可展示榜单',
                'className' => 'bg-indigo-50 text-indigo-700 border-indigo-100',
            ],
            [
                'key' => 'conversion-risk',
                'label' => '转化异常',
                'value' => count($conversionRiskRows) > 0 ? (count($conversionRiskRows) . '家') : '暂无',
                'note' => count($conversionRiskRows) > 0 ? '存在浏览高但支付转化偏低的聚合信号' : '当前未命中低支付转化聚合信号',
                'className' => count($conversionRiskRows) > 0 ? 'bg-rose-50 text-rose-700 border-rose-100' : 'bg-emerald-50 text-emerald-700 border-emerald-100',
            ],
        ];
    }

    private function buildMeituanTopSummaryRows(array $rows): array
    {
        return array_map(static fn(array $row): array => [
            'poiId' => (string)($row['poiId'] ?? ''),
            'hotelName' => (string)($row['hotelName'] ?? ''),
            'positionText' => (string)($row['circlePositionText'] ?? ''),
            'rankTrendText' => (string)($row['rankTrendText'] ?? ''),
            'platformTagText' => (string)($row['platformTagText'] ?? '未返回'),
            'roomNights' => (float)($row['roomNights'] ?? 0),
            'sales' => (float)($row['sales'] ?? 0),
            'gapToNextText' => (string)($row['gapToNextText'] ?? ''),
        ], array_slice($rows, 0, 3));
    }

    private function buildCtripBusinessDisplaySummary(array $rows): array
    {
        $rows = array_values(array_filter($rows, fn($row): bool => is_array($row) && $this->isCtripBusinessDisplayRow($row)));
        if (empty($rows)) {
            return $this->emptyCtripBusinessDisplaySummary();
        }

        $hotelCount = count($rows);
        $totalAmount = round($this->sumCtripBusinessRows($rows, 'amount'), 2);
        $totalQuantity = (int)$this->sumCtripBusinessRows($rows, 'quantity');
        $totalDetailNum = (int)$this->sumCtripBusinessRows($rows, 'totalDetailNum');
        $totalQunarDetailVisitors = (int)$this->sumCtripBusinessRows($rows, 'qunarDetailVisitors');
        $totalOrderNum = (int)$this->sumCtripBusinessRows($rows, 'totalOrderNum');
        $adr = $totalQuantity > 0 ? round($totalAmount / $totalQuantity, 2) : 0.0;
        $avgAri = $this->avgCtripBusinessRows($rows, 'ari');
        $avgSci = $this->avgCtripBusinessRows($rows, 'sci');
        $trafficValue = ($totalDetailNum + $totalQunarDetailVisitors) > 0 ? round($totalAmount / ($totalDetailNum + $totalQunarDetailVisitors), 2) : 0.0;
        $revenueHhi = $this->hhiCtripBusinessRows($rows, 'amount');
        $visitHhi = $this->hhiCtripBusinessRows($rows, 'totalDetailNum');
        $priceSigma = $this->priceSigmaCtripBusinessRows($rows);
        $ctripReviewImpact = $this->reviewImpactCtripBusinessRows($rows, 'commentScore', 'convertionRate');
        $qunarReviewImpact = $this->reviewImpactCtripBusinessRows($rows, 'qunarCommentScore', 'qunarDetailCR');

        $ariLevel = $this->levelForCtripBusinessMetric($avgAri, [
            [80, '价格偏低', 'text-red-600'],
            [95, '略低于均价', 'text-orange-600'],
            [110, '价格合理', 'text-green-600'],
            [130, '价格偏高', 'text-yellow-600'],
            [INF, '溢价优势', 'text-blue-600'],
        ]);
        $sciLevel = $this->levelForCtripBusinessMetric($avgSci, [
            [150, '极弱', 'text-red-600'],
            [260, '偏弱', 'text-orange-600'],
            [370, '中等', 'text-green-600'],
            [480, '较强', 'text-yellow-600'],
            [INF, '极强', 'text-blue-600'],
        ]);
        $revenueLevel = $this->levelForCtripBusinessMetric($revenueHhi, [
            [500, '低度内卷', 'text-yellow-600'],
            [800, '中度内卷', 'text-orange-600'],
            [INF, '寡头市场', 'text-red-600'],
        ]);
        $visitLevel = $this->levelForCtripBusinessMetric($visitHhi, [
            [400, '低度内卷', 'text-yellow-600'],
            [700, '中度内卷', 'text-orange-600'],
            [INF, '高度内卷', 'text-red-600'],
        ]);
        $priceLevel = $this->levelForCtripBusinessMetric($priceSigma, [
            [3, '健康', 'text-green-600'],
            [8, '良好', 'text-emerald-600'],
            [15, '激烈', 'text-orange-600'],
            [INF, '恶化', 'text-red-600'],
        ]);

        $metrics = [
            'hotelCount' => $hotelCount,
            'totalAmount' => $totalAmount,
            'totalQuantity' => $totalQuantity,
            'adr' => $adr,
            'avgAri' => $avgAri,
            'avgSci' => $avgSci,
            'totalDetailNum' => $totalDetailNum,
            'totalQunarDetailVisitors' => $totalQunarDetailVisitors,
            'totalOrderNum' => $totalOrderNum,
            'trafficValue' => $trafficValue,
            'revenueConcentration' => $revenueHhi,
            'visitConcentration' => $visitHhi,
            'priceSigma' => $priceSigma,
            'ctripReviewImpact' => $ctripReviewImpact,
