        $projectRoot = dirname(__DIR__, 2);
        $profileDir = $projectRoot . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'meituan_profile_' . $this->safeMeituanCaptureFilePart($storeId);
        return is_dir($profileDir);
    }

